UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('4-pattes-objet', 'Cet exercice apprend à votre chien à monter et à rester calmement les quatre pattes sur un objet stable quand vous le lui demandez. Il devient ainsi plus à l''aise avec de nouvelles surfaces, ce qui est excellent pour sa confiance en lui et pour faciliter des situations quotidiennes comme monter en voiture ou franchir de petits obstacles en promenade. C''est aussi une belle façon de renforcer votre lien et votre complicité.', 'Apprenez à votre chien à monter calmement et à rester sur un objet, renforçant sa confiance et votre lien.', 'Guidez votre chien pour qu''il monte ses quatre pattes sur un objet et récompensez-le quand il y reste.', '4 pattes sur un objet', 'L''objectif est que votre chien puisse, sur commande vocale, placer ses quatre pattes sur un objet désigné et y rester tranquillement pendant quelques secondes, même en présence de légères distractions. Cela développe sa confiance, son équilibre, et sa capacité à se concentrer sur vous et la tâche demandée.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien monte sur l''objet avec ses quatre pattes, y reste calmement pendant au moins 15 secondes sur une simple commande vocale (''Sur l''objet''), sans que vous n''ayez besoin de le guider avec la main ou une friandise.', 'Si votre chien halète excessivement (sauf après un jeu intense), bâille à répétition (signe de stress), se lèche les babines fréquemment, détourne le regard, tremble, a la queue basse ou sous le ventre, ou refuse manifestement de coopérer malgré des encouragements positifs. Ces signes indiquent qu''il est temps de faire une pause ou d''arrêter l''exercice pour aujourd''hui.', 'L''exercice est validé quand votre chien monte sur l''objet avec ses quatre pattes et y reste pendant au moins 15 secondes, sans aucune aide vocale ni gestuelle de votre part, pendant 3 tentatives consécutives, dans 3 environnements différents (maison, jardin calme, parc avec quelques distractions).', 'Vérifiez toujours la stabilité de l''objet avant chaque utilisation. Observez attentivement le langage corporel de votre chien pour déceler le moindre signe de stress ou d''inconfort. Ne laissez jamais votre chien sauter de l''objet sans votre permission, guidez la descente pour éviter les blessures articulaires. Soyez attentif à ne pas créer de la frustration ou de la peur, en allant toujours à son rythme.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/4-pattes-objet.png'),
('aboie-sur-commande', 'Cet exercice apprend à votre chien à aboyer quand vous le lui demandez, puis à se taire sur commande. C''est un trick amusant et utile pour canaliser les aboiements, par exemple pour alerter si besoin. Il permet de renforcer votre communication et le contrôle que vous avez sur un comportement naturel.', 'Apprenez à votre chien à aboyer quand vous le demandez et à se taire quand vous le voulez !', 'Provoquez un aboiement, marquez-le avec votre signal, récompensez, puis apprenez-lui le silence.', 'Aboie sur commande', 'L''objectif est que votre chien aboie sur votre signal verbal ''Aboie !'' et s''arrête sur ''Stop !'', de manière fiable, dans différents environnements et sans aide gestuelle de votre part.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien aboie clairement sur la commande ''Aboie !'' (sans provocation) et arrête d''aboyer dans les 3 secondes suivant la commande ''Stop !'', le tout sans hésitation.', 'Si le chien halète excessivement, bâille de manière répétée, tourne la tête ou évite votre regard, lèche ses babines fréquemment, a la queue basse ou entre les pattes, ou tremble légèrement. Ce sont des signes de stress ou de fatigue. Il faut alors arrêter immédiatement l''exercice et lui offrir un moment de calme.', 'L''exercice est validé quand le chien aboie sur la commande ''Aboie !'' (sans provocation) et se tait sur ''Stop !'' (sans aboiement supplémentaire), 5 fois sur 5 tentatives consécutives, dans 3 environnements différents (maison, jardin calme, parc avec quelques distractions). Le silence doit durer au moins 5 secondes avant la relance de la commande.', 'Surveillez attentivement les aboiements de réactivité : ne jamais récompenser un aboiement de peur ou d''agression. Assurez-vous que le chien s''amuse et ne ressent aucune pression. Il est facile de basculer d''un aboiement contrôlé à des aboiements intempestifs si l''exercice n''est pas bien géré. Ne pas entraîner l''exercice quand le chien est déjà excité ou sous le coup de l''émotion.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/aboie-sur-commande.png'),
('absence-couchee', 'Cet exercice apprend à votre chien à rester calmement en position couchée, même lorsque vous quittez la pièce. C''est très utile pour gérer les situations où vous devez vous absenter quelques instants, comme prendre une douche ou répondre à la porte, et éviter que votre chien ne vous suive partout ou fasse des bêtises. Il renforce l''autonomie et la confiance de votre chien.', 'Apprenez à votre chien à rester seul et calme en votre absence.', 'Demandez à votre chien de se coucher, puis quittez la pièce et revenez après un court instant, en augmentant progressivement la durée.', 'Absence couchée', 'Apprendre à votre chien à rester sagement en position couchée sans bouger, même quand vous n''êtes plus visible, et ce, pendant une longue période.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste en position couchée, calme et détendu, pendant au moins une minute sans que vous soyez visible. Il ne manifeste pas de signes d''anxiété ou d''agitation.', 'Arrêtez l''exercice si votre chien bâille, se lèche la truffe de manière répétée, halète excessivement, tremble ou tente de se lever de manière répétée. Ces signes indiquent qu''il est stressé ou fatigué.', 'L''exercice est validé quand le chien maintient la position couchée, sans bouger ni faire de bruit, pendant 1 minute, alors que le maître est hors de sa vue, et ce, 3 fois sur 5 tentatives consécutives.', 'Soyez très attentif aux signaux de stress de votre chien, car cet exercice demande une grande gestion de l''émotion liée à votre absence.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/absence-couchee.png'),
('agilite-maison', 'Transformez votre maison en un terrain d''aventure ! Cet exercice ludique utilise des objets de tous les jours pour créer un parcours d''obstacles simple. C''est une excellente façon de renforcer votre lien, de dépenser l''énergie de votre chien et de stimuler son intelligence, le tout sans équipement spécialisé.', 'Un parcours d''obstacles amusant et facile avec des objets du quotidien pour stimuler votre chien !', 'Créez un parcours simple avec des objets de la maison et guidez doucement votre chien pour qu''il franchisse chaque "obstacle".', 'Agility maison DIY', 'Apprendre à votre chien à suivre des indications simples (passer dessus, dessous, autour d''objets) et à explorer de nouvelles situations en toute confiance, tout en s''amusant à la maison.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien franchit plusieurs obstacles du parcours avec enthousiasme, en suivant vos indications vocales et gestuelles, sans être guidé par une friandise à chaque fois.', 'Arrêtez l''exercice si votre chien baille de manière répétée, se lèche les babines, détourne le regard, renifle le sol excessivement, ou semble fatigué ou désintéressé. C''est le signe qu''il a besoin d''une pause ou que l''exercice est trop long.', 'L''exercice est validé quand le chien complète un parcours de 3 obstacles différents (un ''dessus'', un ''dessous'', un ''tourne'') en suivant les indications du maître, 3 fois sur 5 tentatives consécutives, sans aide manuelle significative (seulement l''indication verbale et gestuelle à distance).', 'Surveillez toujours le langage corporel de votre chien pour vous assurer qu''il se sent bien et qu''il apprécie l''activité. Le plaisir doit être partagé !', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/agilite-maison.png'),
('animaux-divers', 'Cet exercice aide votre chien à se sentir plus à l''aise et calme en présence de différents animaux, comme les chats, les chevaux ou les poules. L''objectif est qu''il apprenne à les ignorer ou à avoir des réactions appropriées, sans stress ni excitation excessive. C''est utile pour des promenades sereines à la campagne ou des visites chez des amis qui ont d''autres animaux.', 'Apprenez à votre chien à rester zen face à différents animaux !', 'Exposez progressivement votre chien à d''autres animaux en respectant sa zone de confort et en le récompensant pour son calme.', 'Animaux divers', 'Apprendre à votre chien à rester calme et indifférent en présence d''animaux variés, réduisant ainsi son stress et son excitation.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien peut voir divers animaux sans aboyer, tirer sur la laisse, ou montrer des signes de stress. Il reste calme et peut même vous regarder ou continuer sa promenade indifféremment.', 'Arrêtez l''exercice si votre chien montre des signes de stress importants (bâillements répétés, léchage de babines, queue basse, tentative de fuite ou d''agression) ou de fatigue. Mieux vaut une séance courte et positive qu''une séance trop longue et stressante.', 'L''exercice est validé quand le chien peut passer à moins de 5 mètres d''un animal varié (chat, poule, cheval selon les conditions de l''exercice) en présence détendue (l''absence de tension sur la laisse, le chien ne fixe pas, accepte les friandises, sans jappement ni tentative de s''approcher) pendant au moins 10 secondes consécutives, sur 3 passages différents, 5 fois sur 5 tentatives consécutives.', 'Soyez attentif au langage corporel de votre chien pour anticiper ses réactions et ajuster la difficulté de l''exercice au fur et à mesure.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/animaux-divers.png'),
('calme-chiot', 'Cet exercice apprend à votre chiot à se calmer et à se reposer de lui-même. C''est utile pour qu''il devienne un chien équilibré, capable de se détendre à la maison, en voiture ou chez des amis. Vous allez l''aider à associer le calme à quelque chose de positif.', 'Apprenez à votre chiot à se calmer en récompensant ses moments de détente.', 'Récompensez votre chiot avec une friandise et une caresse discrète dès qu''il est calme et détendu.', 'Apprendre le calme (chiot)', 'Apprendre à votre chiot à se détendre seul dans divers environnements en récompensant ses moments de calme naturel.', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chiot est capable de se calmer seul et de se reposer dans différentes situations, sans que vous ayez besoin d''intervenir tout le temps. Vous le verrez choisir de s''allonger et de se détendre.', 'Arrêtez l''exercice si votre chiot montre des signes d''ennui, de frustration (il gémit, gratte) ou d''excitation (il ne tient plus en place). Ne le forcez jamais, l''objectif est qu''il aime se détendre.', 'L''exercice est validé quand le chiot reste calmement couché ou assis pendant au moins 30 secondes d''affilée sans solliciter le maître, et accepte 5 récompenses consécutives (données ou déposées) sans bouger de sa position de calme, sur au moins 3 sessions différentes dans la même journée.', 'Soyez attentif aux signaux de votre chiot et n''intervenez que s''il est réellement calme et détendu. La patience est la clé.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-chiot.png'),
('proprete', 'L''apprentissage de la propreté est essentiel pour une cohabitation harmonieuse. Cet exercice aide votre chien à comprendre qu''il doit faire ses besoins uniquement à l''extérieur. Cela demande de la patience et de la régularité, mais c''est une étape fondamentale pour son bien-être et le vôtre.', 'Apprenez à votre chien la propreté pour une vie sereine ensemble !', 'Emmenez régulièrement votre chien dehors, récompensez-le chaleureusement quand il fait ses besoins.', 'Apprentissage de la propreté', 'Apprendre à votre chien à faire ses besoins dehors de manière fiable et constante, en évitant les accidents à l''intérieur de la maison.', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Votre chien fait ses besoins systématiquement à l''extérieur, sans accident à l''intérieur de la maison. Il peut même vous prévenir quand il a besoin de sortir.', 'Arrêtez la séance si votre chien montre des signes de stress (halètement excessif, tremblements, queue basse), d''épuisement ou s''il n''est plus du tout intéressé par l''exercice.', 'L''exercice est validé quand le chien fait systématiquement ses besoins à l''extérieur (ou à l''endroit désigné, ex: tapis d''apprentissage) avec moins de 2 accidents par semaine pendant 4 semaines consécutives.', 'Soyez très attentif aux signaux de votre chien quand il cherche à faire ses besoins et sortez-le sans tarder.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/proprete.png'),
('arret-spontane', 'Cet exercice apprend à votre chien à s''arrêter tout seul dès qu''il sent une tension sur sa laisse. C''est très utile pour des promenades plus agréables, sans tirer, car le chien apprend à respecter la tension et ainsi à marcher en laisse plus calmement en ville ou en forêt.', 'Apprenez à votre chien à s''arrêter en douceur dès que la laisse se tend pour des promenades détendues.', 'Dès que la laisse se tend, arrêtez-vous comme un arbre et attendez que votre chien détende la laisse.', 'Arrêt spontané', 'Apprendre à votre chien à s''arrêter dès que la laisse se tend, pour des promenades sans tiraillement et plus sereines.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien s''arrête de lui-même dès qu''il sent une légère tension sur la laisse, se retourne vers vous ou la détend sans que vous ayez besoin de bouger ou de parler. La promenade devient fluide et agréable, avec une laisse constamment détendue.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement excessif, salivation, léchage de truffe, oreilles en arrière) ou de frustration importante (aboiements excessifs, mordillements de la laisse). Si votre chien semble indifférent ou refuse de bouger, c''est aussi un signe qu''il faut faire une pause.', 'L''exercice est validé quand le chien s''arrête spontanément et détend la laisse dans les 3 secondes suivant la tension, 8 fois sur 10 tentatives consécutives, sur différents parcours (rue, parc).', 'Soyez attentif à votre réaction au moment où la laisse se tend. C''est souvent une surprise, et votre réflexe peut être de tirer. Détendez-vous et anticipez l''arrêt pour être plus efficace.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/arret-spontane.png'),
('ascenseur', 'Cet exercice apprend à votre chien à se sentir bien dans un ascenseur. C''est important pour qu''il ne panique pas dans les petits espaces et qu''il puisse vous accompagner partout en ville, chez des amis ou chez le vétérinaire.', 'Rendez l''ascenseur agréable pour votre chien !', 'Récompensez votre chien pour chaque pas calme vers et dans l''ascenseur.', 'Ascenseur', 'Apprendre à votre chien à entrer calmement dans un ascenseur, à y rester sereinement pendant le trajet et à en sortir tranquillement, sans stress.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien entre et sort de l''ascenseur calmement, sans traîner ni tirer, et reste détendu pendant le trajet, même si d''autres personnes montent ou descendent.', 'Arrêtez l''exercice si votre chien montre des signes de stress comme des halètements excessifs, des tremblements, des oreilles basses, une queue entre les pattes, ou s''il tente de fuir. Arrêtez aussi s''il semble fatigué ou perd son intérêt.', 'L''exercice est validé quand le chien entre calmement dans l''ascenseur à 5 reprises consécutives, reste en position ''Assis'' ou ''Couché'' sans manifester de stress (pas de jappements, grattages, salivation excessive, halètement) pendant un trajet d''au moins 3 étages, et sort tranquillement de l''ascenseur sur demande, 3 fois sur 5 tentatives consécutives dans un environnement moyennement fréquenté.', 'Soyez attentif à tout signe de malaise ou de stress. Si votre chien ne réagit pas bien, n''insistez pas et demandez l''aide d''un professionnel.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/ascenseur.png'),
('assis-base', 'Apprenez à votre chien à s''asseoir de manière fiable et joyeuse, sur simple demande. Cet exercice est la base de nombreux autres apprentissages et vous sera utile dans une multitude de situations quotidiennes : pour saluer des invités calmement, attendre à la porte avant de sortir, ou simplement pour un moment de pause.', 'Apprenez l''assis, la base pour un chien calme et obéissant au quotidien !', 'Guidez votre chien en maintenant une friandise au-dessus de son museau jusqu''à ce qu''il pose ses fesses au sol.', 'Assis', 'Apprendre à votre chien à s''asseoir quand vous le lui demandez, même avec de légères distractions, afin de favoriser le calme et le contrôle.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien s''assoit facilement et rapidement au guidage de la friandise, et se montre enthousiaste à l''idée de répéter l''exercice. Il garde la position quelques secondes avant de se relever.', 'Arrêtez immédiatement si votre chien baille de façon répétée, se gratte souvent, détourne le regard, ou refuse la friandise. Ce sont des signes de stress ou de fatigue. Faites une pause et reprenez plus tard.', 'L''exercice est validé quand le chien s''assied sur commande vocale (''Assis'') sans l''aide d''une incitation manuelle (lure), en moins de 3 secondes, et maintient la position pendant au moins 5 secondes, 8 fois sur 10 tentatives consécutives dans un environnement sans distraction majeure.', 'Faites attention à ne pas utiliser votre corps ou vos mains pour pousser le chien ; l''objectif est qu''il s''assoie de lui-même en suivant la friandise.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-base.png'),
('assis-a-distance', 'Apprenez à votre chien à s''asseoir même quand vous êtes loin de lui. Cet exercice renforce le contrôle à distance, ce qui est très utile pour la sécurité de votre chien en promenade ou pour le gérer à la maison sans avoir à vous déplacer constamment.', 'Apprenez à votre chien à s''asseoir de loin, pour une meilleure sécurité et obéissance !', 'Demandez à votre chien de s''asseoir, puis reculez progressivement en le félicitant quand il réussit.', 'Assis à distance', 'Apprendre à votre chien à s''asseoir sur commande, même si vous êtes à plusieurs mètres de lui. Cela améliore son obéissance et votre communication à distance.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste assis sans bouger quand vous vous éloignez de plusieurs mètres. Il ne se lève que lorsque vous lui donnez l''ordre de bouger (rappel, libre, etc.).', 'Arrêtez l''exercice si votre chien est très distrait, refuse de s''asseoir plusieurs fois de suite, se gratte souvent, baille exagérément, ou cherche à fuir. Cela signifie qu''il est fatigué ou stressé.', 'L''exercice est validé quand le chien s''assoit sur commande vocale à une distance de 5 mètres et maintient la position pendant 10 secondes, 4 fois sur 5 tentatives consécutives, dans au moins deux environnements différents (ex: jardin et salon).', 'Soyez vigilant à la posture de votre chien : s''il est tendu ou raide, c''est un signe qu''il est mal à l''aise ou qu''il ne comprend pas.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-a-distance.png'),
('assis-automatique', 'Apprenez à votre chien à s''asseoir tout seul chaque fois que vous vous arrêtez. C''est très utile au quotidien pour la sécurité et le calme, par exemple avant de traverser la route ou quand vous discutez avec quelqu''un. Votre chien sera plus poli et attentif.', 'Votre chien s''assoit tout seul quand vous vous arrêtez. Pratique et plus sûr !', 'Marchez, arrêtez-vous, attendez que votre chien s''assoie, puis récompensez-le.', 'Assis automatique', 'Apprendre à votre chien à s''asseoir calmement et automatiquement dès que vous vous arrêtez de marcher, sans que vous ayez besoin de lui demander.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien s''assoit de lui-même, sans que vous ayez besoin de lui parler ou de le guider, dès que vous vous arrêtez, et ce, dans différents environnements et avec de légères distractions.', 'Arrêtez l''exercice si votre chien baille de façon répétée, se lèche la truffe, tourne la tête, gratte le sol ou refuse de s''asseoir. Ce sont des signes de stress ou de fatigue. Faites une pause ou arrêtez pour la séance.', 'L''exercice est validé quand le chien s''assied calmement et automatiquement dans les 2 secondes suivant votre arrêt, sans commande vocale additionnelle, et maintient la position pendant au moins 5 secondes, lors de 7 arrêts sur 10 tentatives consécutives, et ce sur 3 lieux différents (maison, jardin clôturé, rue calme).', 'Ne forcez jamais votre chien à s''asseoir. L''objectif est qu''il le fasse de lui-même. La patience est la clé de la réussite.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-automatique.png'),
('assis-en-marche', 'Votre chien s''assoit quand vous le lui demandez, même si vous continuez à marcher. C''est très utile en balade pour lui demander de patienter quelques secondes, par exemple si vous croisez quelqu''un ou si vous ramassez quelque chose sans qu''il ne vous suive.', 'Votre chien reste ', 'Dites ', 'Assis en marche', 'Apprendre à votre chien à s''asseoir et à rester en position d''arrêt pendant que vous faites quelques pas à côté de lui, sans qu''il ne bouge.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste assis sans bouger pendant que vous faites quelques pas, et vous pouvez revenir le récompenser sans qu''il n''ait bougé de sa place.', 'Arrêtez l''exercice si votre chien refuse de s''asseoir, s''il gémit, halète excessivement, baille de manière répétitive, se gratte souvent, ou s''il détourne le regard et ne participe plus. Il faut aussi arrêter si vous-même, vous sentez trop frustré.', 'L''exercice est validé quand le chien s''assied à la commande, maintient la position ''Assis-Reste'' pendant que le maître fait 5 pas en s''éloignant et en revenant vers lui, et ce, 4 fois sur 5 tentatives consécutives, avec la laisse détendue ou au sol.', 'Cet exercice est mentalement exigeant pour le chien. Soyez attentif aux signaux de fatigue.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-en-marche.png'),
('assis-longue-duree', 'Cet exercice apprend à votre chien à rester assis calmement pendant plus longtemps, même si vous vous éloignez un peu. C''est très utile pour des situations du quotidien comme quand vous discutez avec un voisin ou que vous attendez votre tour chez le vétérinaire. Votre chien apprendra à se contrôler et à vous faire confiance.', 'Apprenez à votre chien à rester assis longtemps, pour plus de calme au quotidien !', 'Demandez à votre chien de s''asseoir, récompensez-le pour être resté assis quelques secondes, puis augmentez progressivement la durée.', 'Assis longue durée', 'Apprendre à votre chien à rester assis sur commande pendant plusieurs minutes, avec vous près de lui, puis à distance, et même avec de petites distractions.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste assis pendant au moins 3 minutes quand vous lui demandez, même si vous vous éloignez de quelques mètres. Il ne bouge pas avant que vous ne lui donniez l''ordre de libération.', 'Arrêtez si votre chien bâille beaucoup, se lèche les babines, détourne le regard ou refuse de s''asseoir. S''il se montre agité ou frustré. Il est temps de faire une pause pour ne pas le dégoûter.', 'L''exercice est validé quand le chien maintient la position ''Assis'' pendant 3 minutes sans aide, à une distance de 5 mètres du maître, avec au moins une distraction sonore légère (ex: une personne marchant au loin) et sans se lever, 4 fois sur 5 tentatives consécutives.', 'Observez attentivement les signes de fatigue ou de confusion de votre chien pour ajuster la difficulté de l''exercice et garder son engagement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-longue-duree.png'),
('assis-lent', 'Cet exercice aide votre chien à renforcer les muscles de ses pattes et de son dos en douceur. Il apprend à passer calmement de la position assise à debout et inversement, ce qui améliore sa motricité et sa conscience corporelle. C''est utile pour la vie de tous les jours, par exemple pour monter en voiture ou se lever d''une position couchée sans effort.', 'Un exercice doux pour renforcer les muscles et améliorer la coordination de votre chien.', 'Demandez "Assis", puis guidez votre chien pour qu''il se lève doucement sans bouger les pattes arrière, et enchaînez à nouveau sur "Assis".', 'Assis-debout lent', 'Apprendre à votre chien à alterner calmement et doucement entre la position assise et debout, pour un renforcement musculaire doux et une meilleure proprioception.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien alterne calmement entre la position assise et debout, sans bouger ses pattes arrière, juste en suivant la friandise. Il semble concentré et détendu pendant l''exercice.', 'Arrêtez l''exercice si votre chien baille à répétition, se lèche les babines, détourne le regard, renifle le sol sans intérêt, ou tente de s''éloigner. Ce sont des signes de fatigue ou de stress.', 'L''exercice est validé quand le chien est capable d''effectuer 5 cycles ''assis-debout-assis'' consécutifs, en passant de chaque position à l''autre sans précipitation ni anticipation, en moins de 3 secondes par transition (assis -> debout lent, debout -> assis lent), avec un guidage minimal à l''aide de la friandise (lure) 8 fois sur 10 tentatives.', 'Soyez attentif à la posture de votre chien et à la fluidité de ses mouvements. Toute raideur ou hésitation inhabituelle doit vous alerter.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-lent.png'),
('assis-debout-rep', 'Cet exercice simple permet à votre chien de passer de la position assise à la position debout plusieurs fois de suite. C''est un excellent moyen de renforcer les muscles de ses pattes arrière en douceur. Votre chien sera plus fort et plus agile pour ses activités quotidiennes comme monter les escaliers ou sauter dans la voiture.', 'Un exercice simple pour des pattes arrière musclées et un chien plus agile !', 'Demandez à votre chien de s''asseoir, puis de se lever, en le guidant avec une friandise.', 'Assis-debout répétitions', 'Renforcer les muscles des pattes arrière de votre chien pour améliorer sa force et son agilité au quotidien.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien passe de la position assise à la position debout, et vice-versa, cinq fois de suite, sans hésitation et en suivant votre guidance gestuelle et verbale. Ses mouvements sont fluides et il semble à l''aise.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, se gratte souvent, renifle le sol, tourne la tête, ou s''il montre des signes de fatigue physique (mouvements plus lents, tremblements) ou de désintérêt. Mieux vaut une séance courte et positive qu''une séance trop longue et frustrante.', 'L''exercice est validé quand le chien effectue 5 cycles (assis-debout-assis) sans aide physique ni guidage excessif de la main, et ce, 3 fois sur 4 tentatives consécutives.', 'Soyez attentif à la posture de votre chien : il ne doit pas s''avachir ou se pencher excessivement lors des transitions, cela pourrait indiquer une douleur ou une faiblesse.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/assis-debout-rep.png'),
('attaque-arretee', 'Cet exercice apprend à votre chien à s''arrêter net lors d''un mouvement rapide et ciblé, comme s''il allait attraper quelque chose. C''est essentiel pour sa sécurité, par exemple s''il court vers un danger, et renforce votre contrôle en toutes situations.', 'Apprenez à votre chien à s''arrêter sur commande en pleine course !', 'Lancez votre chien vers une cible et dites "STOP" pour qu''il s''arrête net.', 'Attaque arrêtée', 'Apprendre à votre chien à s''interrompre et s''immobiliser sur commande, même en pleine action, pour sa sécurité et un meilleur contrôle.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien s''arrête net sur commande "STOP" à chaque fois, même en pleine course vers l''objet, et attend votre signal pour aller chercher la récompense.', 'Arrêtez l''exercice si votre chien bâille, se lèche les babines de manière excessive, détourne le regard, ou ne participe plus avec enthousiasme. Ce sont des signes de fatigue ou de stress.', 'L''exercice est validé quand le chien s''arrête complètement en moins de 2 foulées après la commande ''Stop!'', maintient la position au moins 5 secondes sans aide, sur 4 tentatives sur 5 consécutives, avec une distance de départ de 5 mètres.', 'Soyez vigilant à ne pas sur-solliciter votre chien. Cet exercice est intense et peut être fatiguant mentalement et physiquement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attaque-arretee.png'),
('attaque-lancee', 'L''attaque lancée est un exercice de haut niveau combinant puissance physique et contrôle émotionnel extrême. Sous la direction d''un professionnel, le chien apprend à neutraliser une menace distante sur ordre et à renoncer instantanément à l''agression sur commande du maître. Cet exercice forge un lien de confiance absolue et garantit que le chien reste gérable même dans un état d''excitation maximale.', 'Un exercice de protection stimulant pour développer le contrôle et l''obéissance de votre chien.', 'Sur votre commande, le chien poursuit et mord un figurant en fuite, puis lâche prise quand vous le lui demandez.', 'Attaque lancée', 'Apprendre à votre chien à attaquer un intrus désigné sur commande, puis à lâcher prise, dans un cadre contrôlé et sécurisé, pour développer ses compétences de protection.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien percute la cible avec détermination et cesse toute agression immédiatement au premier signal sonore du maître.', 'Arrêtez si le chien redirige son agressivité vers le maître, s''il montre des signes de confusion totale (tourne en rond), ou si l''essoufflement devient excessif (langue bleutée).', 'L''exercice est validé quand le chien effectue une course droite de 20m, mure la manchette avec fermeté, lâche sur un seul ordre verbal sans aide physique, et maintient une garde au ferme de 10 secondes sans contact avec l''HA, 4 fois sur 5.', 'Soyez constamment attentif aux signaux de votre chien et à la sécurité de l''environnement. Ne laissez jamais un chien fatigué ou stressé poursuivre cet exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attaque-lancee.png'),
('attend-gamelle', 'Cet exercice enseigne au chien à patienter calmement devant sa gamelle avant d''être autorisé à manger. Il favorise le contrôle de soi et prévient l''excitation excessive autour de la nourriture. C''est une étape fondamentale pour établir des routines saines et une relation de respect mutuel.', 'Apprenez à votre chien la patience avec sa gamelle !', 'Placez la gamelle et attendez que votre chien soit calme avant de donner le signal de manger.', 'Attendre devant la gamelle', 'Apprendre à votre chien à attendre un signal avant de se jeter sur sa gamelle, favorisant le calme et l''autocontrôle.', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien attend patiemment et calmement devant sa gamelle jusqu''à ce qu''il reçoive la permission verbale explicite pour manger, sans försöken d''y aller avant.', 'Le chien aboie de manière excessive, saute, tire agressivement sur la laisse, ou tente de prendre la gamelle avant l''autorisation. Dans ces cas, arrêtez immédiatement l''exercice pour cette session et reprenez plus tard avec une difficulté réduite.', 'Observer que le chien reste en position (assis ou sur son tapis) sans tentative d''approche, sans vocalise excessive, et sans tirer sur la laisse pendant au moins 5 secondes avant de donner le signal d''autorisation.', 'Surveillez attentivement les signes de stress ou de frustration chez votre chien pour adapter la difficulté.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attend-gamelle.png'),
('attendre-en-voiture', 'L''exercice ''attendre en voiture'' enseigne au chien à rester calme et patient dans le véhicule lorsqu''il est stationné. Cela est essentiel pour la sécurité et le confort du chien, ainsi que pour la tranquillité du propriétaire. Cet exercice prévient l''anxiété de séparation et développe l''autocontrôle du chien en votre absence.', 'Apprenez à votre chien à attendre patiemment en voiture pour des trajets plus sereins !', 'Ouvrez la porte de la voiture et récompensez votre chien quand il reste calme et immobile.', 'Attendre en voiture', 'Apprendre à votre chien à attendre tranquillement dans la voiture sans bouger, même quand la porte est ouverte, pour sa sécurité.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester seul dans la voiture pendant au moins 15 minutes sans manifester de signes de stress, d''anxiété ou de vocalises excessives, et il est détendu à votre retour.', 'Le chien montre des signes de détresse importants (halètement excessif, vomissements, destruction) malgré les tentatives de progression, indiquant un besoin de consultation professionnelle ou de réévaluation complète de l''approche.', 'Valider l''exercice en s''assurant que le chien reste constamment calme dans la voiture sans signes de détresse, même lors de courtes absences du propriétaire.', 'Soyez attentif à la température dans l\''habitacle et aux signes de stress ou de mal des transports de votre chien. La sécurité est primordiale.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attendre-en-voiture.png'),
('attente-au-pied', 'L''exercice ''Attente au pied'' enseigne au chien à rester immobile à vos côtés lorsqu''il est en laisse. C''est une compétence fondamentale pour le contrôle et la sécurité, assurant que votre chien reste calme et attentif dans diverses situations. Une bonne exécution démontre une relation de confiance et une compréhension mutuelle entre le propriétaire et le chien.', 'Votre chien apprend à attendre sagement à côté de vous.', 'Demandez "Au pied", marquez un très court arrêt, puis récompensez votre chien pour être resté à vos côtés.', 'Attente au pied', 'Apprendre à votre chien à rester à vos côtés en position "au pied" quand vous êtes immobile, et ce, même avec des distractions.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste immobile à la position ''Au pied'' pendant toute la durée demandée, avec la laisse détendue, malgré les petites distractions et déplacements de l''éducateur. Le chien ne cherche pas à avancer, reculer ou dépasser l''éducateur.', 'Le chien tente de bouger ou de suivre sans y être invité. La laisse devient tendue pendant l''attente. Le chien montre des signes de stress ou d'' frustratration (halètement excessif, bâillements, léchage des babines).', 'L''exercice est validé lorsque le chien peut maintenir la position ''Au pied'' pendant au moins 30 secondes avec une laisse détendue, sans bouger, lorsque l''éducateur est immobile. Les étapes intermédiaires de déplacement et de distraction doivent être maîtrisées avec un taux de réussite élevé avant de considérer l''exercice comme validé.', 'Surveillez toujours les signes de stress ou de fatigue chez votre chien. L''exercice doit rester un jeu agréable pour lui.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attente-au-pied.png'),
('attente-recompense', 'L''exercice ''Attente de récompense'' enseigne au chien à patienter calmement avant de recevoir une friandise. Cela développe l''autocontrôle et la patience, compétences essentielles pour une bonne communication entre le chien et son propriétaire. C''est un exercice fondamental pour prévenir l''excitation excessive et les comportements impulsifs lors des distributions de nourriture ou de jeux.', 'Apprenez à votre chien la patience et le contrôle pour qu''il attende sa récompense.', 'Tenez une friandise fermée dans votre main et donnez-la seulement quand votre chien est calme.', 'Attente de récompense', 'Apprendre à votre chien à attendre calmement une friandise, en renforçant son contrôle et sa patience.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien ne fait aucune tentative de prendre la friandise ni n''affiche de signe d''impatience (ex: sauts, fouillements, grognements) pendant le temps d''attente désigné, et il attend la commande ''C''est bon'' pour la prendre.', 'Le chien montre des signes évidents de stress, de peur ou de frustration (ex: halètement excessif, bâillements, léchage des babines répété, évitement du regard, tentatives de fuite, malpropreté), ou si le chien ne progresse pas du tout après plusieurs sessions.', 'Effectuer l''exercice 10 fois avec succès en une seule session, sans aucune tentative de vol de friandise.', 'Soyez très attentif aux réactions de votre chien. Le but est de créer une association positive avec l''attente, pas de le frustrer. Des sessions courtes et positives sont plus efficaces.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attente-recompense.png'),
('attente-passive', 'Cet exercice apprend à votre chien à rester calme et patient quand il doit attendre. C''est très utile dans la vie de tous les jours, par exemple quand vous buvez un café en terrasse ou discutez avec un ami. Votre chien apprend à se détendre sans toujours avoir besoin d''être au centre de l''attention.', 'Apprenez à votre chien la patience et le calme dans l''attente !', 'Asseyez-vous et ignorez votre chien jusqu''à ce qu''il se calme, puis récompensez son comportement passif.', 'Attente passive', 'Apprendre à votre chien à se calmer et à attendre patiemment dans différentes situations, même quand il n''y a pas d''action, pour qu''il soit plus autonome.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de s''asseoir ou de se coucher calmement à côté de vous pendant plusieurs minutes, sans vous solliciter, dans des environnements variés. Il semble détendu (respire calmement, peut s''endormir).', 'Arrêtez l''exercice si votre chien montre des signes de frustration intense, d''anxiété (halètement excessif, salivation, léchage compulsif), de fatigue ou de perte totale d''intérêt. Il faut terminer sur une note positive, si possible.', 'L''exercice est validé quand le chien maintient une position couchée ou assise détendue (sans japper ou gémir, sans tenter de se lever) pendant au moins 1 minute dans un environnement légèrement distrayant (ex: parc peu fréquenté, terrasse de café peu animée), 4 fois sur 5 tentatives consécutives, sans intervention physique ou verbale du maître mis à part le signal de départ et de fin.', 'Soyez attentif aux signaux d''apaisement de votre chien (bâillements, clignements des yeux, détournement du regard) et récompensez-les pour renforcer le calme.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/attente-passive.png'),
('away-to-me', 'Cette commande apprend à votre chien à se diriger vers votre droite sur une courte distance. C''est utile pour le guider quand vous marchez, par exemple pour éviter un obstacle ou pour lui demander de rester de ce côté de vous. Cela renforce votre communication et la confiance mutuelle.', 'Apprenez à votre chien à aller à droite de façon précise pour une meilleure communication.', 'Dites "Away to me" et guidez votre chien vers votre droite avec un geste large.', 'Away to me (droite)', 'Apprendre à votre chien à aller spécifiquement vers votre droite sur commande, renforçant ainsi la précision de vos instructions directionnelles.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien se dirige vers votre droite de manière fluide sur un ou deux pas, juste en entendant la commande et en voyant votre geste, sans que vous ayez besoin de le guider avec la friandise devant son nez.', 'Arrêtez l''exercice si votre chien bâille, se gratte souvent, renifle le sol sans raison, ou regarde ailleurs. Ce sont des signes qu''il est fatigué, stressé ou qu''il perd concentration. Reprenez plus tard quand il est frais et dispo.', 'L''exercice est validé quand le chien se déplace sciemment et calmement à votre droite sur une distance de 50 cm, suite à la commande verbale "Away Right", 4 fois sur 5 tentatives consécutives, sans aide physique de la laisse.', 'Soyez très attentif au timing de votre récompense et à la clarté de votre geste pour que votre chien comprenne bien ce que vous attendez de lui.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/away-to-me.png'),
('bain', 'Apprenez à votre chien à être plus à l''aise et même à aimer le moment du bain et du séchage. Cet exercice va transformer ce qui peut être une corvée en un moment de détente et de complicité avec votre compagnon, en réduisant son stress et vos difficultés.', 'Fini la corvée, faites du bain un moment de plaisir pour votre chien !', 'Proposez des friandises et des jeux pour associer le bain à des expériences positives, étape par étape.', 'Bain', 'Aider votre chien à être détendu et coopératif pendant le bain et le séchage, pour que ces moments soient plus faciles et agréables pour tout le monde.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien entre calmement dans la baignoire, accepte d''être mouillé et vous le lavez sans qu''il ne se débatte. Il accepte le séchage sans tension.', 'Si votre chien halète, se lèche excessivement les babines, se cache, vocalise (grogne/hurle) ou tente de s''échapper avec insistance, arrêtez immédiatement. Il est stressé et a besoin d''une pause. Reprenez plus tard, en revenant à une étape où il était à l''aise.', 'L''exercice est validé quand le chien entre volontairement dans le bain pour 3 séances consécutives, reste calme (sans tremblements excessifs, vocalises de stress ou tentatives d''évasion fortes) pendant au moins 5 minutes de lavage et 5 minutes de séchage (serviette ou séchoir à faible puissance) 4 fois sur 5 tentatives.', 'La patience est la clé. Chaque chien apprend à son rythme. Ne courez pas les étapes.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/bain.png'),
('balance-point', 'Le "Balance point" est un exercice d''équilibre amusant qui renforce la confiance de votre chien et améliore sa conscience corporelle. Il apprend à votre chien à trouver et maintenir son centre de gravité, ce qui est très utile pour prévenir les chutes et le rendre plus agile dans la vie de tous les jours, par exemple, pour monter et descendre des escaliers ou sauter dans la voiture.', 'Un challenge amusant pour un chien confiant et agile !', 'Demandez à votre chien de monter sur une surface et de maintenir son équilibre sur votre signal.', 'Balance point', 'Apprendre à votre chien à se tenir debout sur une surface instable ou étroite, en répartissant son poids pour garder l''équilibre, sur votre signal verbal.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien monte sur la surface désignée à votre demande et maintient son équilibre pendant plusieurs secondes, même avec de légères distractions. Il semble apprécier l''exercice et le fait volontairement.', 'Arrêtez l''exercice si votre chien montre des signes de stress (gueule fermée, léchage de truffe, évitement), s''il halète beaucoup ou s''il perd tout intérêt et préfère faire autre chose. Mieux vaut finir sur une note positive.', 'L''exercice est validé quand le chien monte sur l''objet cible (d''une hauteur de 15 cm et d''une largeur de 30 cm), y maintient une position stable (les 4 pattes sont sur l''objet) pendant 5 secondes consécutives sur le signal verbal ''Balance'', sans l''aide physique du maître (mains, laisse), 4 fois sur 5 tentatives consécutives.', 'Vérifiez toujours la stabilité et la non-glissance de la surface pour éviter une chute et une blessure.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/balance-point.png'),
('balancoire', 'La balançoire, aussi appelée teeter, est un super exercice pour booster la confiance de votre chien et renforcer votre lien. Il apprend à contrôler son corps en montant sur une planche qui bascule doucement. C''est un défi amusant qui demande de la concentration et de la coordination, parfait pour les chiens qui aiment apprendre de nouvelles choses.', 'Un super exercice d''équilibre et de confiance pour votre chien !', 'Guide ton chien sur la balançoire en le rassurant et en le récompensant à chaque étape.', 'Balançoire (teeter)', 'Apprendre à votre chien à monter sur une balançoire d''agility, à la faire basculer et à rester calme jusqu''au bout, renforçant ainsi sa confiance et son équilibre.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien monte calmement sur la balançoire, la fait basculer de manière contrôlée et en descend sans stress, y compris quand vous n''êtes plus en soutien physique.', 'Arrêtez si votre chien bâille beaucoup, se lèche les babines de manière répétée, détourne le regard, ou refuse de monter sur la balançoire. Ce sont des signes qu''il est stressé ou fatigué.', 'L''exercice est validé quand le chien monte sur la balançoire, la fait basculer entièrement, maintient sa position jusqu''à ce qu''elle touche le sol, attend 3 secondes en position stable et descend seulement sur ordre, 4 fois sur 5 tentatives consécutives.', 'Faites attention aux signaux de stress de votre chien. Cet exercice demande de la concentration et peut être intimidant au début.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/balancoire.png'),
('detection-banque-odeurs', 'La banque d''odeurs est un exercice stimulant où votre chien apprend à mémoriser puis à reconnaître plusieurs odeurs différentes. C''est un jeu qui développe son flair et sa concentration, parfait pour les jours de pluie ou pour simplement lui offrir une activité mentale enrichissante.', 'Un jeu stimulant pour le flair et la mémoire de votre chien !', 'Présentez une odeur à votre chien, cachez-la parmi d''autres, et encouragez-le à la retrouver.', 'Banque d''odeurs', 'Apprendre à votre chien à identifier et à retrouver des odeurs spécifiques parmi d''autres, renforçant ainsi ses capacités cognitives et olfactives.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien cherche activement les boîtes au signal, et signale clairement (en touchant avec le museau, en fixant) la boîte contenant l''odeur cible, même quand elle est cachée.', 'Arrêtez l''exercice si votre chien bâille de stress, se détourne des boîtes, renifle le sol sans chercher les objets, ou refuse de participer. C''est le signe qu''il est fatigué ou qu''il ne comprend plus.', 'L''exercice est validé quand le chien identifie et marque correctement l''odeur cible parmi 3 odeurs distractrices non nourries, 4 fois sur 5 tentatives consécutives, avec un temps de recherche ne dépassant pas 30 secondes par essai.', 'Surveillez toujours les signes de stress ou de frustration chez votre chien. Le jeu doit rester un plaisir pour lui !', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-banque-odeurs.png'),
('bat-training', 'Le BAT (Behavior Adjustment Training) est un exercice doux qui permet à votre chien d''apprendre à gérer ses émotions face à ce qui lui fait peur (autres chiens, personnes, vélos...). L''idée est de lui laisser suffisamment d''espace pour qu''il ne se sente pas menacé et qu''il puisse faire le choix de s''éloigner si besoin. Cela l''aide à être plus calme et confiant dans des situations délicates.', 'Aidez votre chien réactif à reprendre confiance en lui, en douceur.', 'Laissez votre chien décider de la distance face au déclencheur, récompensez son calme et son désengagement.', 'BAT (Behavior Adjustment)', 'Apprendre à votre chien à se sentir en sécurité et à réagir calmement face à des éléments qui le dérangent ou lui font peur, en lui donnant le contrôle de la distance.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de voir le déclencheur à une certaine distance, de le regarder puis de se détourner calmement sans montrer de signes de stress majeurs (pas de tirage de laisse, pas d''aboiements, pas de tremblements). Il est capable de faire ses propres choix de gestion de la distance.', 'Arrêtez la séance si votre chien montre des signes de stress importants (halètement excessif, tremblements, aboiements non stop, tentative de fuite), de fatigue, ou de désintérêt total. Il ne doit jamais être forcé au-delà de ses limites.', 'L''exercice est validé quand le chien peut rester calme (sans aboyer, tirer, grogner, se figer) pendant au moins 10 secondes en présence du déclencheur, à une distance où il l''a d''abord identifié puis s''en est délibérément éloigné de quelques pas (1-2 mètres) de lui-même, 3 fois sur 5 tentatives consécutives, sur 3 sessions différentes.', 'Soyez extrêmement attentif aux micro-signaux de stress de votre chien (léchage de babines, bâillements, détournement du regard, oreilles en arrière) pour réagir avant qu''il ne soit trop anxieux.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/bat-training.png'),
('blind-cross', 'Le "Blind Cross" est une technique de guidage avancée en agility. Elle vous permet de changer de côté de votre chien sans le freiner ni le perturber. C''est très utile pour aborder des obstacles où vous devez être rapidement de l''autre côté, comme après un saut ou avant un tunnel.', 'Guidez votre chien efficacement en changeant de côté sans interruption.', 'Faites un "Blind Cross" pour changer de côté de votre chien tout en le maintenant en mouvement avec fluidité.', 'Blind cross', 'Apprendre à votre chien à suivre votre changement de côté rapide et en douceur pour optimiser les trajectoires en agility.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien change de côté de manière fluide et sans hésitation, en continuant sa course vers l''obstacle suivant. Le mouvement est continu et énergique.', 'Arrêtez l''exercice si votre chien montre des signes de stress (bâillements répétés, léchage de babines, queue basse, refus de participer), de fatigue ou s''il perd tout intérêt pour l''exercice.', 'L''exercice est validé quand le chien exécute le blind cross avec un changement de côté fluide, sans ralentir ni couper le virage, 5 fois sur 7 tentatives consécutives, en maintenant une distance d''environ 1 mètre de vous, sur une surface plane sans obstacles.', 'Le ', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/blind-cross.png'),
('bouteille-friandises', 'La bouteille à friandises est un jeu simple et amusant qui stimule l''esprit de votre chien. Il doit trouver comment faire sortir les croquettes de la bouteille. C''est une excellente activité pour l''occuper et le fatiguer mentalement, ce qui est tout aussi important que l''exercice physique.', 'Un jeu malin pour stimuler l''esprit de votre chien et l''occuper joyeusement.', 'Montrez à votre chien comment les friandises peuvent tomber de la bouteille en la manipulant.', 'Bouteille à friandises', 'Apprendre à votre chien à résoudre un casse-tête simple pour obtenir ses friandises, favorisant ainsi sa concentration et son autonomie.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien est capable de faire tomber les friandises de la bouteille de manière autonome, en manipulant la bouteille avec son nez ou ses pattes, et qu''il semble prendre du plaisir à le faire.', 'Arrêtez l''exercice si votre chien montre des signes de frustration (grognements, pattes sur la bouteille sans succès, s''éloigne) ou de fatigue. Il est important que l''activité reste un jeu positif.', 'L''exercice est validé quand le chien est capable de faire sortir au moins 5 friandises de la bouteille en moins de 2 minutes, 3 fois sur 5 tentatives consécutives, sans aide humaine ni signe de frustration excessive.', 'Faites attention à ce que votre chien ne mordille pas et n''ingère pas de morceaux de plastique.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/bouteille-friandises.png'),
('brossage', 'Le brossage régulier est essentiel pour la bonne santé de la peau et du pelage de votre chien. Cet exercice va lui apprendre à accepter d''être manipulé gentiment, sans peur, pour que ce moment devienne un plaisir partagé. C''est important pour détecter d''éventuels problèmes cutanés ou parasites.', 'Faites du brossage un moment agréable pour votre chien.', 'Commencez par des caresses, introduisez la brosse très brièvement et récompensez généreusement le calme.', 'Brossage', 'Apprendre à votre chien à apprécier ou du moins tolérer calmement le brossage de tout son corps, rendant les séances futures plus faciles et moins stressantes pour vous deux.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme pendant que vous le brossez sur différentes parties de son corps pendant plusieurs minutes. Il ne cherche pas à s''échapper et accepte les friandises pendant la manipulation.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement, bâillements répétitifs, léchage de truffe, oreilles en arrière, queue basse), s''il grogne, ou s''il essaie de mordre. Arrêtez aussi s''il n''est plus intéressé par les friandises ou semble fatigué.', 'L''exercice est validé quand le chien accepte un brossage doux de 5 zones différentes (épaule, dos, flanc droit/gauche, queue) pendant au moins 10 secondes par zone, sans signe de stress ou de fuite, 3 fois sur 5 tentatives consécutives, et accepte une récompense après chaque zone brossée.', 'Soyez attentif à tout signe d''inconfort ou de douleur, et ne forcez jamais votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/brossage.png'),
('bruits-chantier', 'Cet exercice aide votre chien à s''habituer aux bruits forts et imprévisibles comme ceux qu''on entend sur un chantier. L''objectif est qu''il reste calme et serein, même quand des sons surprenants se produisent. C''est important pour sa sécurité et votre tranquillité en ville.', 'Rendez les bruits de chantier normaux pour votre chien grâce à cet exercice !', 'Diffusez des bruits de chantier à faible volume et récompensez le calme de votre chien.', 'Bruits de chantier', 'Apprendre à votre chien à ne pas paniquer face aux bruits forts et soudains d''un chantier. Il apprendra à les ignorer ou à les tolérer calmement.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme, détendu et peut même s''endormir ou jouer pendant que les bruits de chantier sont diffusés à un volume modéré, sans montrer de signes de stress. Il peut même prendre des friandises que vous lui offrez.', 'Arrêtez l''exercice si votre chien présente des signes de stress (halètement, bâillements excessifs, oreilles plaquées, queue entre les pattes, tentative de fuite), de fatigue ou s''il perd tout intérêt pour les friandises. Il est crucial d''arrêter avant que le chien soit trop anxieux.', 'L''exercice est validé quand le chien ignore au moins 3 bruits de forte intensité (niveau sonore équivalent à celui d''un marteau-piqueur à 20 mètres) sur 5 tentatives consécutives, ou qu''il revient spontanément vers le manieur au lieu de réagir aux bruits, sans présenter de signes de stress (halètement, tremblements, tentatives de fuite, aboiements) et maintient une allure normale pendant 10 secondes après le bruit, lors de 3 sessions distinctes sur une semaine.', 'Soyez vigilant face aux signaux de stress subtils de votre chien. Chaque chien réagit différemment. Ne forcez jamais s''il est mal à l''aise.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/bruits-chantier.png'),
('bruits-menagers', 'Cet exercice aide votre chien à se sentir plus à l''aise avec les bruits de la maison. En l''habituant progressivement, vous éviterez qu''il panique ou stresse quand vous utilisez l''aspirateur, le mixeur ou le sèche-cheveux. Un chien serein face aux bruits est un chien plus heureux au quotidien.', 'Transformez les bruits quotidiens en moments agréables pour votre chien !', 'Associez les bruits faibles à des friandises et augmentez le volume très progressivement.', 'Bruits ménagers', 'Faire en sorte que votre chien associe les bruits de la maison à quelque chose de positif, comme des friandises et des caresses, plutôt qu''à la peur.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme, curieux, ou même indifférent en présence de bruits domestiques faibles et modérés, et il accepte des friandises pendant que le bruit est là.', 'Arrêtez immédiatement si votre chien refuse les friandises, tente de fuir, se cache, tremble, ou présente d''autres signes de peur ou de stress. Il est important de ne pas dépasser ses limites.', 'L''exercice est validé quand le chien reste calme (pas de tremblements, pas de tentatives de fuite, respiration normale) à une distance de moins de 1 mètre de l''appareil en fonctionnement (à puissance normale) pendant 30 secondes consécutives, et ce, pour 3 bruits différents (ex: aspirateur, sèche-cheveux, mixeur) sur 5 tentatives.', 'Surveillez toujours les signes de stress ou de malaise pour ne pas traumatiser votre chien. L''exercice doit rester un jeu agréable.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/bruits-menagers.png'),
('honte', 'Apprenez à votre chien un tour amusant : "Cache ta honte" ! Il mettra sa patte sur son museau comme s''il était gêné. C''est un excellent moyen de renforcer votre complicité et d''impressionner vos amis. Cet exercice stimule aussi son esprit et sa coordination.', 'Un tour amusant pour renforcer votre lien et stimuler votre chien !', 'Frottez une friandise sur sa patte, puis guidez-la vers son museau en disant "Honte !".', 'Cache ta honte', 'Apprendre à votre chien à couvrir son museau avec sa patte sur commande, pour le plaisir et la stimulation mentale.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien pose sa patte sur son museau de manière volontaire et rapide dès que vous dites "Honte !", sans que vous ayez besoin de le guider avec une friandise.', 'Arrêtez l''exercice si votre chien se désintéresse, se couche, bâille beaucoup, se gratte souvent, ou tourne la tête. Ce sont des signes qu''il est fatigué ou stressé. Une séance doit toujours se terminer sur une note positive.', 'L''exercice est validé quand le chien met sa patte sur son museau et la maintient pendant 2 secondes, 4 fois sur 5 tentatives consécutives, sur la seule commande vocale ''Cache !'' sans aide manuelle ni guidage par friandise.', 'Soyez attentif aux signaux de communication de votre chien : s''il semble confus ou mal à l''aise, simplifiez l''étape ou faites une pause.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/honte.png'),
('cache-friandises', 'Cet exercice stimule le flair de votre chien et l''aide à se concentrer. Il consiste à cacher des friandises et à l''encourager à les trouver. C''est une activité simple à mettre en place qui le dépense mentalement et renforce votre lien.', 'Un jeu de recherche simple et amusant pour dépenser mentalement votre chien.', 'Cachez des friandises dans des endroits faciles à trouver au début, et encouragez votre chien à les chercher avec son flair.', 'Cache-friandises maison', 'Apprendre à votre chien à utiliser son flair pour chercher des friandises cachées, ce qui le stimule mentalement et le rend plus calme à la maison.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien trouve systématiquement les friandises cachées en utilisant son flair, sans que vous ayez besoin de trop le guider, et qu''il semble prendre plaisir au jeu.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (bâillements répétés, se gratte), de frustration (gratte le sol avec insistance sans trouver) ou de désintérêt (s''éloigne et fait autre chose).', 'L''exercice est validé quand le chien trouve la friandise cachée de manière invisible (sans l''avoir vu cacher) dans 3 endroits différents, 4 fois sur 5 tentatives consécutives, en moins de 30 secondes par cachette.', 'Ne laissez jamais votre chien manger une friandise cachée qu''il n''aurait pas trouvée, même par accident, pour ne pas le démotiver pour les prochaines recherches.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cache-friandises.png'),
('calm-apres-jeu', 'Cet exercice apprend à votre chien à se calmer rapidement après une période de jeu ou d''excitation. C''est très utile pour gérer des situations comme l''arrivée d''invités ou la fin d''une promenade agitée. Votre chien apprendra à se détendre sur commande, ce qui apporte plus de sérénité à la maison.', 'Aidez votre chien à retrouver son calme après l''excitation.', 'Après un moment d''excitation, demandez calmement à votre chien de s''allonger et récompensez son calme.', 'Calme après le jeu', 'Apprendre à votre chien à retrouver le calme après un moment d''excitation, comme un jeu intense ou une rencontre avec d''autres chiens.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de se calmer plus rapidement après un jeu ou une activité excitante, et reste couché ou assis calmement pendant quelques minutes quand vous le lui demandez.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement excessif, bâillements répétés, évitement du regard) ou de fatigue, ou s''il perd tout intérêt pour l''exercice.', 'L''exercice est validé quand le chien maintient une position de calme (assis ou couché) avec des signes de détente (aucun halètement excessif, regard lointain, absence de léchage de babines ou de grattage compulsif) pendant au moins 30 secondes, 4 fois sur 5 tentatives consécutives, suite à 2 minutes de jeu intense. La libération doit être donnée calmement par le maître.', 'Soyez attentif à votre propre état de calme. Votre chien est une éponge à émotions ; si vous êtes stressé ou agité, il le sera aussi.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calm-apres-jeu.png'),
('calme-restaurant', 'Cet exercice vise à apprendre au chien à rester calme et détendu dans un environnement stimulant comme un restaurant. Le but est qu''il comprenne qu''il doit se coucher et rester tranquille, même en présence d''odeurs alléchantes, de bruits et de mouvements. Il s''agit d''une étape cruciale pour une cohabitation harmonieuse en public.', 'Apprenez à votre chien à se poser calmement sous une table, pour des sorties sereines.', 'Récompensez chaque moment de calme de votre chien sous la table dans des environnements de plus en plus stimulants.', 'Calme au restaurant', 'Apprendre à votre chien à se détendre et à rester calme sous une table dans des lieux animés comme un restaurant, afin qu''il puisse vous accompagner partout en toute sérénité.', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien reste couché et détendu sur sa couverture, ignorant les distractions du restaurant. Il se lève uniquement sur commande ou lorsque vous vous apprêtez à partir. Il peut bailler ou fermer les yeux, signe de détente.', 'Le chien montre des signes de stress excessif (halètement excessif, tremblements, salivation abondante), une agressivité ou une excitation incontrôlable. Si le chien ne parvient pas à se calmer malgré les efforts, il est préférable de mettre fin à la séance et de réessayer dans des conditions plus favorables.', 'Observer la capacité du chien à rester couché et calme pendant au moins 15 minutes dans l''environnement du restaurant, malgré les distractions (clients, bruits, odeurs de nourriture). Le chien ne doit pas aboyer, pleurnicher, tenter de se lever ou de mendier. La laisse doit rester détendue.', 'Ce n''est pas anormal si votre chien dort pendant l''exercice : c''est le signe qu''il est détendu et en confiance. Ne le réveillez pas si ce n''est pas nécessaire.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-restaurant.png'),
('calme-exterieur', 'Cet exercice vise à apprendre à votre chien à rester calme et à ignorer les distractions extérieures, telles que les passants, les autres chiens ou les bruits. L''objectif est de développer sa concentration sur vous et de renforcer le lien de confiance. Une approche progressive et positive est essentielle pour réussir.', 'Apprenez à votre chien à se détendre partout, même en extérieur !', 'Trouvez un endroit calme dehors, asseyez-vous et ignorez votre chien jusqu''à ce qu''il se pose de lui-même.', 'Calme en extérieur', 'Apprendre à votre chien à se calmer et à se détendre dans des environnements extérieurs variés, malgré les stimulations autour de lui.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien ignore la plupart des distractions standards (passants, autres chiens calmes, bruits de circulation) pour se concentrer sur son propriétaire. Il reste en position demandée (assis/couché) sans réagir ou en réagissant très peu et de manière contrôlée.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, baîllements répétitifs, tentative de fuite). Il aboie, grogne, saute ou tire de manière incontrôlable sur la laisse. La relation de confiance est compromise ou le chien refuse catégoriquement de participer.', 'Observer le comportement du chien dans différentes situations extérieures avec divers niveaux de distraction et évaluer sa capacité à rester calme et attentif au propriétaire. Examiner également la rapidité de son retour au calme après une distraction.', 'Soyez attentif au langage corporel de votre chien pour repérer les premiers signes d’inconfort ou de stress et ajustez l''environnement en conséquence.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-exterieur.png'),
('calme-cabinet-vet', 'Cet exercice vise à apprendre à votre chien à rester calme et détendu dans un environnement potentiellement stressant, comme une salle d''attente vétérinaire ou chez le toiletteur. L''objectif est de prévenir les aboiements, les sauts et l''agitation, en favorisant une attitude de repos. Une bonne gestion de l''environnement et des récompenses appropriées sont essentielles pour la réussite.', 'Apprenez à votre chien la zen attitude en salle d''attente !', 'Récompensez votre chien pour chaque instant de calme dans un environnement stimulant.', 'Calme en salle d''attente', 'Apprendre à votre chien à rester calme et serein dans des environnements potentiellement stressants, en attendant, par exemple, chez le vétérinaire ou dans un lieu public.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste assis ou couché calmement, sans aboyer ni manifester d''autres signes de stress, pendant au moins 10 minutes dans une salle d''attente typique, même en présence d''une distraction modérée (ex: une personne qui passe ou un autre chien au loin).', 'Le chien manifeste des signes de stress excessif et incontrôlable malgré vos efforts (halètement intense, tremblements, tentatives désespérées de fuite). Vous ne parvenez pas à détourner son attention des stimuli stressants.', 'Entraînez-vous dans plusieurs salles d''attente différentes (vétérinaire, toiletteur, amis propriétaires de chiens). Variez les jours et les heures. L''objectif est que le chien applique le comportement appris dans divers contextes.', 'Soyez attentif à l''environnement : assurez-vous qu''aucun autre animal ou personne ne puisse perturber brutalement votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-cabinet-vet.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('calme-en-voiture', 'Apprenez à votre chien à rester calme et détendu pendant les trajets en voiture. Cet exercice est essentiel pour rendre les déplacements plus agréables pour vous et votre compagnon. Un chien calme en voiture réduit le stress et l''anxiété pour tout le monde.', 'Apprenez à votre chien à aimer la voiture pour des trajets sans stress!', 'Commencez par des sessions courtes et positives dans la voiture à l''arrêt, puis augmentez progressivement la durée et la distance.', 'Calme en voiture', 'Votre chien apprend à rester calme et en sécurité dans le véhicule, même quand il est en mouvement, pour des trajets sereins.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien monte volontairement dans la voiture, y reste calme et détendu pendant toute la durée du trajet, sans vocaliser, haleter excessivement, ou montrer des signes d''anxiété ou de mal des transports.', 'Le chien manifeste une peur ou une anxiété intense, des vomissements, ou un comportement incontrôlable malgré les efforts et les mesures de soutien. Reprenez l''exercice à un stade antérieur ou consultez un professionnel comportementaliste canin.', 'Observer le chien pour des signes de relaxation (respiration calme, corps détendu, absence de bâillements excessifs ou de léchages de babines). Récompenser la quiétude. Augmenter progressivement la durée et la distance des trajets uniquement lorsque le chien est confortablement installé et calme.', 'Observez attentivement les signes de stress ou de mal des transports pour adapter l''exercice au rythme de votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-en-voiture.png'),
('calme-pendant-activites', 'Cet exercice vise à apprendre à votre chien à rester calme et détendu lorsque vous êtes occupé à d''autres activités. L''objectif est qu''il comprenne qu''il n''a pas besoin d''attirer votre attention constamment et qu''il peut trouver son propre confort. Cela renforce votre lien et améliore la gestion des comportements indésirables tels que les sauts ou les aboiements.', 'Apprenez à votre chien à être calme et indépendant pendant vos activités.', 'Demandez à votre chien de s''installer à sa place, puis commencez une activité calme à côté de lui en le récompensant s''il reste tranquille.', 'Calme pendant vos activités', 'Apprendre à votre chien à rester tranquillement à sa place pendant que vous faites une activité calme à proximité. L''objectif est de construire son autonomie et de réduire le besoin d''attention constante.', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester allongé ou assis calmement dans son espace pendant que vous réalisez diverses activités inactives ou peu engageantes, cherchant de manière autonome le repos sans réclamer constamment votre attention, même en présence de légères distractions.', 'Le chien montre des signes de stress, d''anxiété, de frustration excessive, ou s''il devient complètement apathique et éteint. Si le chien réagit de manière agressive ou si l''exercice devient une source de conflit répétée.', 'Observer le chien réagir calmement à votre immobilité et à de légères distractions pendant au moins 5 minutes consécutives, sans mendicité active ou agitation anxieuse.', 'Surveillez attentivement les signes de stress ou d''anxiété chez votre chien et arrêtez l''exercice si nécessaire pour ne pas le mettre en difficulté.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-pendant-activites.png'),
('calme-sur-couverture', 'Apprenez à votre chien à se calmer et à se détendre sur sa couverture. Cet exercice crée un lieu de sécurité et de repos pour lui, utile à la maison, chez des amis ou en voyage. Il associe la couverture à un état de calme, ce qui aide à gérer l''excitation et le stress au quotidien.', 'La couverture devient un havre de paix pour votre chien.', 'Invitez votre chien à aller sur sa couverture et récompensez son calme.', 'Calme sur couverture', 'Apprendre à votre chien à se calmer et à se détendre sur sa couverture, créant ainsi un lieu de sécurité et de repos.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien se dirige vers sa couverture sur votre signal et s''y installe calmement (assis ou couché) pendant plusieurs minutes, même en votre absence à côté de lui. Il attend votre signal pour en descendre.', 'Arrêtez l''exercice si votre chien baille de façon répétée, se lèche les babines, regarde ailleurs, gratte la couverture ou essaie de partir. Ce sont des signes de stress ou de fatigue. Il faut terminer la séance sur une note positive, quitte à revenir à une étape plus facile.', 'L''exercice est validé quand le chien s''allonge de lui-même sur la couverture et y reste calme pendant au moins 5 minutes, sans aide ni incitation, 3 fois sur 5 tentatives consécutives, même lorsque le maître se trouve à 3 mètres de distance.', 'Soyez attentif au langage corporel de votre chien : tout signe d''inconfort ou de stress doit vous alerter et vous faire arrêter la séance.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/calme-sur-couverture.png'),
('canalisation-drive', 'Cet exercice apprend à votre chien à contrôler son énergie et sa force quand il attrape quelque chose, comme un jouet ou une friandise. C''est important pour la sécurité et pour éviter les morsures accidentelles, surtout dans le jeu. Votre chien apprendra à être plus doux et à mieux se maîtriser.', 'Apprenez à votre chien à attraper avec douceur et contrôle !', 'Présentez un objet ou une friandise, et demandez à votre chien de le prendre délicatement.', 'Canalisation du drive', 'Apprendre à votre chien à attraper et tenir un objet en douceur, sans utiliser trop de force, même quand il est excité. Cela permet un meilleur contrôle de soi dans le jeu ou lors des interactions.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien prend la friandise ou l''objet avec une gueule douce et sans tension, dès que vous prononcez le signal, sans arracher ou mordre fort. Il est calme et contrôlé pendant l''interaction.', 'Arrêtez l''exercice si votre chien ne parvient plus à prendre la friandise en douceur après plusieurs tentatives, s''il montre des signes de frustration (grognements, tentatives brutales), ou s''il est fatigué et perd l''attention. Mieux vaut des séances courtes et positives !', 'L''exercice est validé quand le chien prend l''objet délicatement sans contact avec la main du maître, 8 fois sur 10 tentatives consécutives, sans bondir, et que s''il est invité à lâcher l''objet après l''avoir pris, il le fait en moins de 3 secondes.', 'Soyez très attentif aux signaux de communication de votre chien : s''il serre la mâchoire ou montre les dents, il faut arrêter et revoir les étapes.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/canalisation-drive.png'),
('cani-marche', 'La cani-marche est une marche dynamique où votre chien vous aide en tirant. C''est un excellent moyen de dépenser son énergie et de renforcer votre complicité. Cela lui permet d''explorer son environnement de manière active et de développer sa force musculaire en toute sécurité.', 'Une marche sportive où votre chien vous tracte doucement grâce à son harnais.', 'Laissez votre chien tirer naturellement en le motivant sans cesse pour maintenir une traction constante.', 'Cani-marche', 'Apprendre à votre chien à marcher en traction constante et contrôlée, ce qui est très utile pour son exercice physique.', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien maintient une tension constante sur la ligne et tire de manière fluide pendant toute la durée de la marche, sans que vous ayez à le solliciter constamment.', 'Arrêtez l''exercice si votre chien présente des signes de fatigue (halètement excessif, traîne la patte), de stress (bâillements répétés, léchage de truffe) ou s''il perd tout intérêt à tirer. La séance doit rester un plaisir pour lui.', 'L''exercice est validé quand le chien maintient une tension constante sur la laisse pendant au moins 3 minutes sur terrain varié, sans à-coups excessifs, sur 3 tentatives consécutives.', 'Soyez attentif à la température et à l''état du sol (éviter le bitume chaud ou les surfaces glissantes) pour protéger les pattes de votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cani-marche.png'),
('cani-rando', 'La cani-randonnée, c''est partir en longue promenade avec votre chien qui porte son propre équipement dans un sac à dos spécial. C''est une super activité pour dépenser son énergie et partager un moment privilégié en pleine nature. Cela renforce votre lien et développe son endurance.', 'Partez à l''aventure avec votre chien porteur de son propre matériel !', 'Proposez d''abord le sac vide, puis ajoutez du poids progressivement sur des balades courtes.', 'Cani-randonnée', 'Apprendre à votre chien à porter un sac de bât léger et confortable lors de vos randonnées en pleine nature, en toute sécurité et avec plaisir.', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Votre chien porte son sac à dos avec un poids adapté sur une longue période (plus d''une heure) sans montrer de signes d''inconfort ni de fatigue excessive. Il semble heureux et énergique pendant et après la randonnée.', 'Arrêtez immédiatement si votre chien boite, halète excessivement, traîne la patte, refuse d''avancer, se lèche les pattes de manière compulsive ou montre des signes de douleur ou de stress (queue basse, oreilles en arrière).', 'L''exercice est validé quand le chien porte un sac de bât lesté à 5% de son poids corporel pendant 30 minutes de marche continue sur un terrain varié (chemin de terre, herbe, légère pente), sans tenter de l''enlever ou de le mordre, et sans montrer de signes d''inconfort ou de stress, et ce, lors de 3 tentatives consécutives.', 'Surveillez attentivement les signes de fatigue ou de douleur, surtout au niveau des coussinets et des articulations, tout au long de la randonnée.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cani-rando.png'),
('cani-trottinette', 'Apprenez à votre chien à tirer une trottinette en toute sécurité. C''est une activité amusante qui permet à votre chien de se dépenser physiquement et mentalement, tout en renforçant votre complicité. Idéal pour les chiens énergiques qui ont besoin de se défouler.', 'La cani-trottinette : défoulement et complicité garantis !', 'Apprenez d''abord à votre chien à marcher à côté de la trottinette, puis à tracter sur commande.', 'Cani-trottinette', 'Apprendre à votre chien à tracter une trottinette de manière contrôlée et en rythme, en suivant des indications simples.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien tire la trottinette en rythme, en suivant vos commandes de direction et d''arrêt, avec une attitude joyeuse et motivée.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (halètement excessif, traînement des pattes), de stress (tentatives de fuite, queue entre les pattes, oreilles en arrière) ou de perte d''intérêt (il refuse d''avancer, est distrait en permanence).', 'L''exercice est validé quand le chien tracte la trottinette de manière constante pendant 5 minutes sur un parcours varié (lignes droites et 2-3 virages simples) en exécutant au moins 90% des commandes de direction et d''arrêt de manière autonome, pendant 3 séances consécutives.', 'Surveillez toujours le rythme de votre chien et son confort respiratoire, surtout en montée ou par temps chaud.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cani-trottinette.png'),
('cani-vtt', 'Le Cani-VTT est une activité sportive où vous faites du VTT avec votre chien attaché à votre vélo. Votre chien court devant vous, tirant légèrement, tandis que vous pédalez. C''est un excellent moyen de partager une activité intense en plein air et de renforcer votre complicité, tout en permettant à votre chien de dépenser son énergie de manière constructive.', 'Faites du VTT avec votre chien attelé pour une dépense physique et mentale intense !', 'Apprenez à votre chien à tirer votre VTT en toute sécurité, en le guidant et en communiquant.', 'Cani-VTT', 'Apprendre à votre chien à courir en ligne droite devant votre VTT, à maintenir une vitesse constante et à répondre à vos indications de direction et d''arrêt en toute sécurité.', 'La constance est la clé du succès', '20 min', '5 fois', '1x/jour', 'tous', 'Votre chien trotte ou galope en ligne droite devant vous, maintient l''allure sans que vous ayez à le pousser, et répond de manière fiable à vos commandes de direction et d''arrêt.', 'Arrêtez immédiatement l''exercice si votre chien boite, halète excessivement, traîne la patte, refuse d''avancer ou montre des signes de douleur ou de fatigue extrême.', 'L''exercice est validé lorsque le chien court en ligne droite devant le VTT sur une distance de 2 kilomètres, maintient une vitesse constante sans sollicitation excessive, répond correctement à au moins 3 commandes de direction (droite/gauche) et 2 commandes d''arrêt sur 3 tentatives consécutives, sans tirer de manière désordonnée ou se déporter, et ce, sur des parcours variés (chemins de terre, légères montées/descentes).', 'Soyez constamment attentif aux signaux de votre chien (langue sortie, halètements, position des oreilles et de la queue) pour prévenir la fatigue ou la déshydratation.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cani-vtt.png'),
('canicross-initiation', 'Le Canicross est un sport où vous courez attaché à votre chien par un harnais spécial. Ce premier exercice vous apprendra, à vous et votre chien, à courir en douceur ensemble, sans tirer excessivement ni vous freiner. C''est un excellent moyen de renforcer votre complicité tout en faisant une activité physique dynamique.', 'Courez ensemble, en harmonie, avec votre chien en Canicross !', 'Attachez votre chien et commencez à marcher, puis trotter pour qu''il comprenne le mouvement vers l''avant.', 'Canicross initiation', 'Apprendre à votre chien à courir en avant de vous avec la ligne tendue, sans à-coups, et à rester concentré sur le chemin.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien trotte en avant, la ligne de trait tendue de manière constante, sans tirer excessivement ou vous freiner, et en restant concentré sur le chemin pendant plusieurs minutes.', 'Arrêtez immédiatement l''exercice si votre chien montre des signes de fatigue (halètement excessif, traîne la patte), de stress (queue basse, oreilles en arrière, bâillements répétitifs, léchage de truffe) ou de perte d''intérêt totale. Le plaisir doit rester la priorité.', 'L''exercice est validé quand le chien court en avant du maître avec la ligne de trait tendue (sans à-coups ni détentes prolongées) sur une distance de 500 mètres, sans s''arrêter de lui-même plus d''une fois et sans se déporter plus de 3 fois du chenille (1 mètre de large) défini, 3 fois sur 5 tentatives consécutives.', 'Soyez attentif à toute boiterie ou signe d''inconfort de votre chien pendant et après l''effort. N''hésitez pas à écourter la séance au moindre doute et à consulter un vétérinaire si besoin.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/canicross-initiation.png'),
('capturing-calme', 'Le "capturing du calme" est une technique toute simple pour apprendre à votre chien à être calme et détendu par lui-même. Plutôt que de lui demander de se calmer, vous allez récompenser les moments où il est spontanément tranquille. Cela l''aide à comprendre que le calme est payant et désirable, même sans intervention de votre part.', 'Récompensez les moments de calme de votre chien pour qu''il devienne un pro de la relaxation !', 'Dès que votre chien est calme, jetez une friandise près de lui sans parler ni le regarder directement.', 'Capturing du calme', 'Apprendre à votre chien à se calmer seul en le récompensant lorsqu''il est naturellement détendu, sans que vous ayez besoin de lui demander.', 'La constance est la clé du succès', 'toute la journée', '5 fois', '1x/jour', 'tous', 'Votre chien commence à chercher son panier ou son tapis de lui-même pour se calmer, ou se détend simplement plus souvent quand il n''y a pas d''activité. Il reste calme même après avoir mangé sa friandise.', 'Arrêtez si votre chien s''énerve, vous suit partout après chaque friandise, ou si vous observez des signes de stress comme des bâillements excessifs, des léchages de babines ou des détournements du regard.', 'L''exercice est validé quand le chien montre spontanément au moins 3 signes de calme (soupir, bâillement, pose de la tête, regard détendu, immobilité) sur une période de 5 minutes, sans votre intervention, et qu''il accepte la récompense sans se lever, 5 fois consécutives.', 'Restez attentif aux moindres signes de calme pour ne pas rater une occasion de récompenser ce comportement précieux.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/capturing-calme.png'),
('cavaletti', 'L''exercice des Cavaletti consiste à faire marcher votre chien calmement au-dessus de petites barres posées au sol. Cela améliore sa coordination, son équilibre et renforce ses muscles en douceur. C''est comme une petite séance de sport qui aide votre chien à mieux contrôler son corps !', 'Améliorez l''équilibre et la coordination de votre chien avec les Cavaletti !', 'Guide votre chien pour qu''il marche calmement au-dessus des barres posées au sol, une patte après l''autre.', 'Cavaletti', 'Apprendre à votre chien à enjamber calmement des obstacles bas, ce qui améliore sa conscience de son corps et sa confiance en lui.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien marche calmement au-dessus des barres, une patte après l''autre, sans les toucher et sans tirer sur la laisse. Il semble détendu et concentré.', 'Arrêtez l''exercice si votre chien baille, se lèche les babines, tourne la tête, ralentit, gratte la terre ou refuse d''avancer. Ce sont des signes qu''il en a assez.', 'L''exercice est validé quand le chien enjambe 5 cavaletti consécutifs, espacés d''une longueur de corps, à une hauteur de 10 cm, sans toucher les barres, et en marchant à un rythme calme et régulier, sur 3 essais consécutifs.', 'Vérifiez que votre chien ne saute pas par-dessus les barres, mais enjambe bien toutes les barres, une après l''autre. Il doit rester calme.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cavaletti.png'),
('certification-unite-cynophile', 'Cet exercice est une simulation d''examen pour vérifier les acquis de votre chien dans divers environnements. Il permet de s''assurer que votre chien peut réagir correctement et en toute sécurité dans des situations variées du quotidien, comme lors de rencontres avec d''autres chiens ou personnes.', 'Préparez-vous à l''examen de certification avec cet exercice complet de mise en situation !', 'Passez en revue une série d''épreuves simulant des situations réelles pour évaluer l''obéissance et le comportement de votre chien.', 'Certification unité cynophile', 'Évaluer la capacité de votre chien à obéir et à se comporter de manière appropriée lors de diverses simulations du quotidien pour une certification.', 'La constance est la clé du succès', '60 min', '5 fois', '1x/jour', 'tous', 'Votre chien obéit calmement et avec plaisir à vos demandes dans la majorité des situations proposées, sans montrer de signes de stress ni de réactivité excessive.', 'Si votre chien montre des signes de stress importants (halètement excessif, tremblements, queue basse, refus de coopérer) ou de fatigue, arrêtez immédiatement l''exercice pour son bien-être.', 'L''exercice est validé si le chien réussit 70% des épreuves proposées (minimum 7 sur 10 simulations différentes), en exécutant les commandes avec un taux de réussite de 80% (absence d''aboiement, tenue au pied maîtrisée, non consommation d''appâts) et en restant calme et sous contrôle pendant la totalité de l''examen (10 minutes) sans tension constante ni réaction indésirable majeure.', 'Veillez à la sécurité de l''environnement, notamment vis-à-vis des autres chiens et personnes, et anticipez les réactions de votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/certification-unite-cynophile.png'),
('changement-position-distance', 'Le changement de position à distance est un exercice avancé qui permet à votre chien de passer de la position "assis" à "couché" (et vice-versa) même lorsque vous êtes loin de lui. C''est très utile pour la gestion quotidienne, par exemple pour lui demander de rester calme au restaurant ou à la maison quand des invités arrivent, sans avoir à vous déplacer.', 'Votre chien change de position sur une simple demande, même quand vous êtes loin !', 'Demandez à votre chien de s''asseoir, puis de se coucher, puis de se rasseoir, tout en augmentant la distance.', 'Changement de position à dista', 'Apprendre à votre chien à alterner les positions "assis" et "couché" à distance, avec fluidité et fiabilité, même avec des distractions légères.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien alterne facilement et rapidement les positions "assis" et "couché" sur votre demande, même lorsque vous êtes à plusieurs mètres de lui, sans se lever ni bouger de son emplacement initial.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, se lèche la truffe, détourne le regard, se gratte, cherche à s''échapper ou ne répond plus aux commandes. Ce sont des signes de stress ou de fatigue.', 'L''exercice est validé quand le chien exécute 5 changements de position (assis-couché ou couché-assis) consécutifs et corrects, à une distance de 5 mètres, 3 fois sur 4 tentatives successives, en moins de 3 secondes par changement.', 'Faites attention à ce que votre chien ne prenne pas l''habitude de se lever pour venir chercher sa récompense. C''est l''inverse de l''objectif !', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/changement-position-distance.png'),
('changement-rythme', 'Cet exercice apprend à votre chien à adapter sa vitesse de marche en fonction de la vôtre. C''est utile pour avoir des promenades plus agréables et sécurisées, où votre chien reste attentif à vous, que vous marchiez vite ou lentement. Il apprend ainsi à mieux suivre votre rythme au quotidien.', 'Marchez ensemble, au même rythme !', 'Accélérez ou ralentissez votre marche, et récompensez votre chien quand il s''adapte à vous.', 'Changement de rythme', 'Apprendre à votre chien à changer de rythme de marche avec vous, pour une promenade harmonieuse et attentive.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien adapte sa vitesse de marche naturellement à la vôtre, qu''il s''agisse d''accélérer ou de ralentir, et reste attentif à vos changements de rythme pendant une promenade de 5 minutes. Il ne tire plus sur la laisse et vous suit sans effort.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement excessif, salivation, bâillements répétés, queue basse), de fatigue, ou s''il perd complètement son intérêt pour l''exercice et refuse de suivre. Il est important de ne jamais le forcer.', 'L''exercice est validé quand le chien ajuste son rythme de marche (accélérer, ralentir) en réponse à vos commandes vocales et mouvements du corps, en restant à votre gauche avec une laisse détendue dans 80% des tentatives sur une promenade de 10 minutes, sans tirer plus de 2 fois par minute.', 'Soyez attentif à votre chien mais aussi aux environs : regardez où vous mettez les pieds et ne vous laissez pas surprendre par un obstacle ou un autre chien trop proche.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/changement-rythme.png'),
('chapeaux-uniformes', 'Cet exercice aide votre chien à se sentir à l''aise quand il rencontre des personnes portant des uniformes (postier, policier, livreur) ou des chapeaux, des casques. Souvent, les chiens réagissent par peur ou excitation à ces apparences inhabituelles. En l''habituant, vous rendez les rencontres plus sereines et sécurisantes pour tous.', 'Apprenez à votre chien à accepter calmement les personnes aux apparences inhabituelles.', 'Présentez progressivement à votre chien des objets ou vêtements inhabituels, en le récompensant pour son calme.', 'Chapeaux et uniformes', 'L’objectif est que votre chien reste calme et confiant face à des personnes portant des chapeaux, des casques ou des uniformes, sans aboyer, grogner ou chercher à fuir.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien reste calme et indifférent en présence de personnes portant des chapeaux, des casques ou des uniformes, quelle que soit la personne. Il doit pouvoir ignorer ou observer ces personnes sans stress.', 'Arrêtez immédiatement si votre chien montre des signes de stress intenses (gueule fermée, corps raide, halètements rapides, tentatives de fuite, grognements) ou de fatigue. Mieux vaut faire des séances courtes et positives.', 'L''exercice est validé quand le chien peut rester calme (sans aboyer, grogner, tirer excessivement ou chercher à fuir) pendant 15 secondes consécutives à une distance de 3 mètres d''une personne portant un chapeau, un casque ou un uniforme, le tout sur 3 essais consécutifs avec 3 personnes/tenues différentes.', 'Soyez attentif à toute réaction négative de votre chien, même minime, pour ajuster la difficulté de l''exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chapeaux-uniformes.png'),
('chin-rest', 'Le "Chin Rest" est un exercice simple qui apprend à votre chien à poser son menton sur votre main ou un objet sur commande. C''est super utile pour faciliter les soins quotidiens comme nettoyer les yeux, appliquer un traitement, ou vérifier les dents, car votre chien restera calme et immobile de son plein gré.', 'Apprenez à votre chien à poser son menton pour des soins plus sereins et coopératifs !', 'Présentez votre main à plat et invitez votre chien à poser son menton dessus.', 'Chin rest (menton posé)', 'Apprendre à votre chien à poser et maintenir son menton sur une cible désignée pour des périodes courtes, rendant les manipulations plus faciles et moins stressantes pour lui.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien pose son menton sur votre main ou une cible donnée dès que vous donnez le signal verbal et maintient la position pendant quelques secondes (3-5 secondes) avant que vous ne le libériez.', 'Arrêtez l''exercice si votre chien bâille, se gratte souvent, tourne la tête, ne répond plus à l''invitation, ou tente de s''éloigner. Ces signes montrent qu''il est fatigué ou stressé.', 'L''exercice est validé quand le chien pose volontairement son menton sur la main cible et maintient la position pendant au moins 5 secondes, 4 fois sur 5 tentatives consécutives, sans aucune aide physique ou guidage avec la friandise, en réponse à la seule commande vocale ''Menton''.', 'Faites attention aux micro-signes de gêne ou de stress de votre chien. Il doit toujours apprendre avec plaisir.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chin-rest.png'),
('chuchoter', 'Le "chuchoter" est un exercice amusant qui apprend à votre chien à aboyer très doucement, presque sans bruit, sur commande. C''est un trick sympa pour impressionner vos amis et aussi utile pour mieux contrôler les aboiements de votre chien à la maison.', 'Apprenez à votre chien à "chuchoter" sur commande : un trick amusant et utile pour gérer les aboiements !', 'Demandez à votre chien de "parler" puis incitez-le à baisser le volume en le récompensant dès le moindre aboiement silencieux.', 'Chuchoter', 'Apprendre à votre chien à aboyer doucement et sur commande, en imitant un chuchotement, pour un meilleur contrôle vocal.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien est capable de produire un aboiement très doux, presque un murmure, uniquement sur votre commande spécifique de chuchotement, sans aboyer fort au préalable.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (bâillements répétés, inattention), de frustration ou de confusion. Mieux vaut faire des séances courtes et positives.', 'L''exercice est validé quand le chien produit un aboiement chuchoté (son à peine audible, sans résonance complète d''un aboiement normal) sur la commande ''Chuchote !'', 4 fois sur 5 tentatives consécutives, dans un environnement calme, sans l''aide d''un déclencheur externe, et ce, sur deux séances d''entraînement différentes.', 'Soyez vigilant à ne pas créer de confusion avec l''ordre "parle" si vous l''utilisez déjà. Le "chuchoter" doit être un ordre distinct avec un signal différent.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chuchoter.png'),
('come-bye', 'Le ''Come Bye'' est une commande directionnelle utilisée en agility et en pistage pour demander au chien de tourner vers la gauche et de faire un tour sur lui-même dans le sens inverse des aiguilles d''une montre. Cet exercice est essentiel pour améliorer la connexion et la communication entre le maître et le chien, permettant des changements de direction rapides et précis.', 'Apprenez à votre chien à tourner à gauche sur commande !', 'Placez-vous face à votre chien, guidez-le avec votre main gauche et dites "Come Bye".', 'Come bye (gauche)', 'Apprendre à votre chien à se diriger et à tourner vers la gauche sur un signal verbal et gestuel, tout en restant attentif à vos indications. Cela améliore son contrôle directionnel à distance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien complète un tour à 360 degrés sur la gauche en moins de 3 secondes après la commande vocale, avec une attitude joyeuse et engagée.', 'Le chien montre des signes de stress, de fatigue, ou d''incompréhension répétée malgré les ajustements, ou le chien effectue l''action sans la commande vocale.', 'Observer si le chien tourne complètement sur lui-même dans le sens inverse des aiguilles d''une montre à partir de son point de départ, en suivant le leurre ou le geste du maître, suite à la commande vocale ''Come Bye''.', 'Soyez attentif à la patte de votre chien : certains chiens ont une préférence naturelle pour tourner d''un côté. L''objectif est d''équilibrer les deux directions.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/come-bye.png'),
('compter', 'Le jeu ''Compter les aboiements'' est un excellent exercice pour stimuler mentalement votre chien et renforcer son contrôle de soi. Il apprendra à différencier un comportement attendu (aboyer une fois) d''un comportement non désiré (aboyer plusieurs fois). Cet exercice convient à la plupart des chiens capables d''aboyer sur commande et nécessite peu de matériel.', 'Apprenez à votre chien à aboyer à la demande et à contrôler ses aboiements.', 'Demandez à votre chien d''aboyer, comptez ses aboiements, puis demandez le silence.', 'Compter les aboiements', 'Apprendre à votre chien à aboyer un nombre de fois précis sur demande, puis à se taire.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable d''aboyer le nombre exact de fois demandé par le handler, sur commande, dans au moins 80% des essais, et s''arrête après le dernier aboiement sans indication supplémentaire.', 'L''exercice doit s''arrêter si le chien montre des signes de stress, de frustration excessive, d''épuisement, ou s''il ne fait aucun progrès après plusieurs sessions malgré des ajustements.', 'Observez la régularité avec laquelle le chien aboie le nombre de fois demandé avant de le récompenser. La récompense est donnée uniquement après le bon nombre d''aboiements.', 'Écoutez attentivement le langage corporel de votre chien pour ne jamais le mettre mal à l''aise ou le forcer. Chaque chien a son rythme d''apprentissage.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/compter.png'),
('compteur-comportemental', 'Le Compteur Comportemental est une méthode d''éducation canine positive qui vise à enseigner au chien à associer un son (ou un mot) à une récompense. Il permet de renforcer des comportements souhaités en les marquant précisément au moment où ils se produisent. Cet exercice est excellent pour développer la connexion entre le propriétaire et le chien ainsi que pour enseigner de nouveaux apprentissages de manière ludique et efficace.', 'Transformez le déclencheur de votre chien en une source de joie et de calme !', 'Dès que votre chien voit son déclencheur, donnez-lui immédiatement une friandise.', 'Compteur comportemental', 'Apprendre à votre chien à associer la vue d''un élément stressant ou excitant (le "déclencheur") à l''arrivée d''une récompense, pour modifier ses émotions et son comportement.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien propose le comportement ciblé de manière plus fréquente et autonome. Il démontre une vigilance accrue et une réponse rapide au click/mot marqueur, indiquant qu''il anticipe la récompense. Le chien semble engagé et motivé durant les séances.', 'Le chien montre des signes de stress, de frustration excessive ou d''épuisement. Le chien devient désintéressé, ignore les commandes ou la friandise. Des erreurs de timing répétées de la part du handler (ne pas cliquer/parler au bon moment) empêchent la compréhension du chien.', 'Commencez dans un environnement familier et calme. Le click/mot marqueur doit être immédiatement suivi d''une friandise. Observez les comportements spontanés du chien, marquez ceux que vous souhaitez encourager et récompensez. Augmentez progressivement la durée de tenue du comportement ou la complexité de la demande. Puis, introduisez des distractions et d''autres environnements.', 'Le Compteur Comportemental prend du temps. Soyez patient et constant. Chaque petite amélioration est une victoire !', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/compteur-comportemental.png'),
('conduite-figurant', 'La conduite du figurant est un exercice essentiel pour un chien de protection, testant sa capacité à suivre une personne désignée dans diverses situations. Il évalue le contrôle du chien lorsqu''il est tenu en laisse à côté de son maître, tout en devant ignorer les distractions potentielles. Cet exercice est crucial pour développer la concentration et la discipline du chien dans un environnement potentiellement stressant.', 'Apprenez à votre chien à protéger son espace personnel avec confiance.', 'Votre chien se positionne entre vous et le figurant, et le guide calmement loin de vous.', 'Conduite du figurant', 'Apprendre à votre chien à escorter calmement une personne inconnue loin de vous, sans agressivité ni peur, en renforçant votre lien de confiance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien marche de manière constante à gauche du handler, avec une laisse détendue, en restant attentif au handler et en suivant ses mouvements sans hésitation ni tiraillement.', 'Le chien montre des signes de stress excessif, d''agressivité, de peur, ou refuse catégoriquement de coopérer. Le handler doit arrêter l''exercice pour éviter de dégrader la relation ou de blesser le chien.', 'L''exercice est validé lorsque le chien peut être conduit sur une distance de 100 mètres avec 3 changements de direction, 2 arrêts, et en ignorant 2 distractions modérées, sans que le chien ne tire sur la laisse ou ne perde sa position.', 'Soyez attentif aux signaux d''apaisement ou de stress de votre chien et agissez en conséquence pour éviter un débordement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/conduite-figurant.png'),
('contournement-obstacles', 'Cet exercice enseigne au chien à naviguer habilement autour d''objets de différentes tailles et formes. Il améliore la concentration, la confiance et la coordination du chien, tout en renforçant le lien entre le chien et son maître. C''est une excellente activité pour stimuler mentalement et physiquement votre compagnon.', 'Apprenez à votre chien à naviguer en ville avec aisance et en toute confiance !', 'Placez-vous entre l''obstacle et votre chien et guidez-le calmement autour.', 'Contournement d''obstacles', 'Apprendre à votre chien à contourner les obstacles urbains de manière détendue et sans tirer sur la laisse, en gardant votre attention.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien contourne 80% des obstacles présentés (de difficulté croissante) de manière fluide et autonome, avec une réaction positive. Il ne cherche pas à contourner l''obstacle si la commande n''est pas donnée.', 'Le chien montre des signes de stress, de fatigue excessive, de peur ou d''agressivité. Si le chien refuse catégoriquement de coopérer malgré plusieurs tentatives de simplification.', 'Observer si le chien contourne l''obstacle volontairement, sans hésitation excessive, en réponse à la commande verbale et/ou au geste, en suivant le chemin désiré.', 'Surveillez toujours l''environnement pour la sécurité de votre chien et des autres. Soyez attentif aux voitures, vélos ou autres chiens qui pourraient surprendre votre compagnon.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/contournement-obstacles.png'),
('counter-conditioning', 'Le contre-conditionnement est un exercice qui vise à transformer une émotion négative en une émotion positive chez votre chien. Si votre chien a peur des orages, par exemple, nous allons lui apprendre à associer l''orage à quelque chose de super agréable, comme des friandises. Cela va l''aider à se sentir mieux face à ce qui lui fait peur.', 'Transformez la peur en plaisir avec des associations positives !', 'Dès que le déclencheur apparaît, donnez immédiatement une friandise très appétissante à votre chien.', 'Contre-conditionnement classiq', 'Apprendre à votre chien à associer une situation ou un objet qui lui fait peur ou le stresse à une émotion positive, pour qu''il se sente plus détendu.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien observe le déclencheur sans montrer de signes de stress, ses oreilles sont détendues, sa queue bat doucement et il anticipe la friandise avec plaisir. À terme, il cherchera spontanément votre regard à l''apparition du déclencheur.', 'Arrêtez immédiatement si votre chien refuse les friandises, s''il halète, bâille énormément, tourne la tête, se gratte, se lèche les babines de manière répétée, ou s''il commence à aboyer ou grogner. Cela signifie qu''il est dépassé.', 'L''exercice est validé quand le chien montre des signes d''anticipation positive (ex: se tourne vers le maître, agite la queue, regarde son maître pour la friandise) face au stimulus craint, dans 3 situations différentes, à une intensité moyenne du stimulus, et ce, sans montrer de signes de stress significatifs (halètements, léchages de babines excessifs, oreilles en arrière) pendant au moins 5 minutes.', 'Soyez attentif aux moindres signes de stress de votre chien. Le but est de créer des émotions positives, pas d''augmenter sa peur.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/counter-conditioning.png'),
('controle-apres-prise', 'Cet exercice apprend à votre chien à ne pas sauter sur les objets qu''on lui lance, et à attendre votre signal pour les prendre. C''est très utile pour qu''il reste calme quand vous jouez ou pour éviter qu''il ne s''empare de choses dangereuses.', 'Apprenez à votre chien à attendre avant de prendre un objet que vous lancez.', 'Lancez une friandise ou un jouet, et demandez à votre chien d''attendre avant de le prendre.', 'Contrôle après la prise', 'Apprendre à votre chien à contrôler son envie de prendre un objet lancé, et à attendre patiemment votre autorisation.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien attend sagement que vous lui donniez le signal "Prends !" avant de se jeter sur l''objet lancé, montrant son contrôle et son calme.', 'Arrêtez l''exercice si votre chien est frustré, aboie de façon excessive, ignore systématiquement vos demandes, ou montre des signes de fatigue. Une séance réussie est courte et positive.', 'L''exercice est validé quand le chien maintient sa position d''attente (assis ou debout) pendant au moins 5 secondes après le lancer de l''objet, et prend l''objet uniquement et systématiquement sur le signal vocal ''Prends'', 8 fois sur 10 tentatives consécutives, avec un objet de valeur moyenne et à une distance de lancer de 3 mètres.', 'Soyez attentif à toute frustration chez le chien. Si l''exercice est trop difficile, il peut devenir contre-productif.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/controle-apres-prise.png'),
('controle-foule', 'Cet exercice apprend à votre chien à rester calme et à ne pas s''approcher des gens lorsqu''il y a une foule ou beaucoup de monde. C''est utile pour les promenades en ville ou les lieux animés, afin que votre chien ne bouscule personne et reste à vos côtés en toute sécurité. Vous lui apprenez à ignorer les distractions autour de lui.', 'Apprenez à votre chien à rester calme au milieu de la foule.', 'Marchez en gardant votre chien près de vous et récompensez son calme face à la foule.', 'Contrôle de foule', 'Apprendre à votre chien à rester serein et à maintenir une distance respectueuse avec les personnes autour de lui, même dans des environnements très fréquentés. Il apprendra à ne pas solliciter l''attention des passants.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien peut marcher calmement à vos côtés dans une foule modérée, sans tirer sur la laisse, sans chercher à interagir avec les passants de manière excessive, et qu''il reste attentif à vous.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, se lèche les babines, tourne la tête ou essaie de fuir (signes de stress). Si il tire de façon excessive ou refuse d''avancer.', 'L''exercice est validé quand le chien marche au pied sans tirer sur la laisse pendant 5 minutes consécutives, sans tenter d''approcher de personnes à moins de 2 mètres, et en ignorant au moins 3 sollicitations passives de passants (regards, paroles) dans une zone de foule modérée, lors de 3 tentatives successives.', 'Soyez attentif aux signaux d''apaisement de votre chien. Il communique son inconfort avant que la situation ne dégénère.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/controle-foule.png'),
('pace-control', 'Apprenez à votre chien à marcher à vos côtés en ajustant sa vitesse, que vous ralentissiez ou accélériez. Cela améliore votre coordination et sa capacité à se concentrer sur vous lors des promenades, rendant les sorties plus agréables et sécurisées pour vous deux.', 'Harmonisez vos pas avec votre chien pour des promenades fluides et attentionnées.', 'Marchez avec votre chien à vos côtés, en variant votre vitesse et en le récompensant lorsqu''il s''adapte.', 'Contrôle du rythme', 'Apprendre à votre chien à maintenir sa position à vos côtés quelle que soit votre vitesse de marche, en restant attentif à vos changements de rythme.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien marche à vos côtés avec une laisse détendue, s''arrêtant et repartant, ou changeant de vitesse en même temps que vous, de manière fluide et sans tirer. Il reste attentif à vos mouvements.', 'Arrêtez si votre chien montre des signes de stress, de fatigue (halètement excessif, traîne les pattes, bâillements répétés) ou s''il perd complètement l''attention et refuse de coopérer. Des séances courtes et positives sont plus efficaces que des séances trop longues et frustrantes.', 'L''exercice est validé quand le chien maintient sa position à votre côté (épaule alignée avec votre jambe) pendant 4 minutes consécutives, en ajustant sa vitesse lors de 5 changements de rythme (2 accélérations, 2 ralentissements, 1 arrêt) avec une laisse détendue, et ce, 3 fois sur 5 tentatives.', 'Faites attention à vos propres signaux corporels. Votre langage corporel détendu et votre voix encourageante sont essentiels pour rassurer votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/pace-control.png'),
('couche-base', 'Le « couché » est un ordre très utile. Il permet à votre chien de se détendre et de rester calme dans de nombreuses situations, comme lorsque vous êtes au restaurant ou que vous avez des invités à la maison. C''est aussi un excellent moyen de renforcer votre lien en travaillant ensemble.', 'Apprenez à votre chien à se coucher sur commande !', 'Guidez votre chien avec une friandise pour le faire se coucher doucement.', 'Couché', 'Apprendre à votre chien à se coucher quand vous le lui demandez, même quand il est un peu distrait. Cela l''aide à se calmer et à se reposer n''importe où.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien se couche de lui-même en suivant le mouvement de votre main avec la friandise. Plus tard, il se couchera dès que vous direz ''Couché''.', 'Arrêtez l''exercice si votre chien bâille beaucoup, se lèche les babines, regarde ailleurs, gratte le sol ou refuse de suivre la friandise. Ce sont des signes qu''il est fatigué ou stressé.', 'L''exercice est validé quand le chien se couche spontanément et maintient la position au moins 10 secondes, sur commande ''Couché'', à une distance de 2 mètres du maître, lors de 8 tentatives sur 10 consécutives.', 'Faites attention à vos mouvements de main. Ils doivent être lents et clairs pour que votre chien comprenne bien ce que vous attendez de lui.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/couche-base.png'),
('couche-a-distance', 'Le "Couché à distance" est un exercice super utile pour demander à votre chien de se coucher même quand il est loin de vous. Imaginez : il s''apprête à courir vers une route, ou vous voulez qu''il reste tranquille pendant que vous discutez. Cet exercice renforce son obéissance et votre contrôle, même à distance.', 'Apprenez à votre chien à se coucher même à distance pour plus de sécurité et de contrôle.', 'Dites "couché" et faites le geste, puis guidez mentalement votre chien pour qu''il se couche à distance.', 'Couché à distance', 'Apprendre à votre chien à se coucher rapidement, sur votre commande, même si vous êtes à plusieurs mètres de lui. Cela renforce son écoute et votre capacité à le gérer dans diverses situations.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien se couche de manière fiable sur l''ordre "couché" et sur votre signal gestuel, même lorsque vous êtes à plusieurs mètres de lui. Il maintient la position jusqu''à ce que vous veniez le récompenser.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, se lèche la truffe excessivement, détourne le regard, renifle le sol sans raison, ou refuse de participer. Ces signes indiquent du stress ou de la fatigue.', 'L''exercice est validé quand le chien s''assied, maintient la position ''Reste'' à 5 mètres de distance, et se couche sur la commande vocale ''Couché'' et le signal gestuel (si utilisé), puis maintient la position couchée pendant au moins 10 secondes, 4 fois sur 5 tentatives consécutives, dans 3 environnements différents.', 'Soyez attentif à la réaction de votre chien. Le but est qu''il apprenne dans la joie, pas dans la contrainte. Une séance courte et réussie est toujours préférable.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/couche-a-distance.png'),
('couche-en-marche', 'Apprenez à votre chien à se coucher et à rester en position pendant que vous marchez, puis à vous rejoindre à la demande. C''est très utile au quotidien pour la sécurité ou lors de situations spécifiques comme attendre à la terrasse d''un café, ou pendant une conversation.', 'Un exercice pratique pour un chien obéissant et serein en toutes circonstances.', 'Alors que votre chien est en mouvement, demandez-lui de se coucher, éloignez-vous et rappelez-le.', 'Couché en marche', 'Votre chien doit se coucher et rester calme quand vous vous éloignez, puis revenir vers vous joyeusement quand vous l''appelez.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien se couche et reste en place pendant que vous marchez, même sur plusieurs mètres, et revient vers vous avec joie quand vous l''appelez.', 'Si votre chien halète excessivement, détourne le regard, bâille ou se gratte souvent, c''est qu''il est stressé ou fatigué. Arrêtez l''exercice et reprenez plus tard, dans un environnement plus calme.', 'L''exercice est validé quand le chien se couche sur commande, maintient la position ''Reste'' pendant que le maître s''éloigne de 5 mètres pendant 10 secondes, et revient au rappel joyeusement, sur 4 tentatives réussies sur 5 consécutives, dans un environnement modérément distrayant.', 'Attention à ne pas rallonger trop vite la distance d''éloignement. Allez-y très progressivement, pas à pas, pour ne pas décourager votre chien. Chaque petite réussite doit être une joie partagée.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/couche-en-marche.png'),
('couche-longue-duree', 'Le "couché longue durée" apprend à votre chien à rester calmement dans la position couchée pendant une période prolongée, même si vous vous éloignez ou qu''il y a des petites distractions. C''est très utile à la maison, quand vous recevez des invités, au restaurant ou dans les transports en commun. Cela renforce son calme et sa confiance.', 'Apprenez à votre chien à rester couché sereinement sur la durée !', 'Demandez à votre chien de se coucher, récompensez, puis augmentez progressivement la durée et la distance.', 'Couché longue durée', 'Apprendre à votre chien à rester couché et calme de plus en plus longtemps, même quand vous bougez.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste couché calmement pendant plusieurs minutes, même si vous vous éloignez de quelques mètres ou qu''il y a de légers bruits.', 'Arrêtez immédiatement si votre chien baille de manière répétée, se lèche les babines, détourne le regard, gémit, ou essaie de se cacher. Ce sont des signes de stress ou de fatigue. Il est temps de faire une pause ou d''arrêter l''exercice pour aujourd''hui. Il faut que l''exercice reste amusant.', 'L''exercice est validé quand le chien maintient la position couchée pendant 2 minutes, avec le maître se déplaçant à une distance de 3 mètres, 4 fois sur 5 tentatives consécutives, dans un environnement avec des distractions légères (ex: bruits doux, passage d''une personne à distance).', 'Soyez attentif à la communication de votre chien : un regard fuyant ou des bâillements peuvent indiquer qu''il commence à être mal à l''aise. Ne le forcez jamais.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/couche-longue-duree.png'),
('couper-griffes', 'Couper les griffes de votre chien est une partie essentielle de ses soins, essentielle pour prévenir les douleurs, les problèmes de posture et les blessures. Une coupe régulière rendra votre compagnon plus à l''aise et favorisera une bonne locomotricité. Il est important d''associer cette tâche à une expérience positive pour éviter toute anxiété future.', 'Des griffes bien entretenues pour un chien heureux et en bonne santé !', 'Habituez votre chien au toucher des pattes et au coupe-griffes progressivement et positivement.', 'Couper les griffes', 'Apprendre à votre chien à se laisser manipuler les pattes et à accepter le coupe-griffes, pour des séances de soin sereines et régulières.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Toutes les griffes accessibles ont été coupées proprement sans blesser le chien, et ce, dans un laps de temps raisonnable et sans stress excessif pour l''animal.', 'Le chien montre des signes de stress intense (halètement excessif, tremblements, tentatives répétées de fuite, grognements ou morsures) ou si le propriétaire est trop anxieux et risque de blesser le chien.', 'Observer la réaction du chien : s''il est calme, détendu et accepte la manipulation avec une légère anticipation de la récompense. Vérifier la régularité des griffes après la coupe.', 'Surveillez attentivement les signes de stress ou de douleur de votre chien et arrêtez l''exercice au moindre signal négatif. La patience est la clé.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/couper-griffes.png'),
('endurance-longue', 'La course d''endurance est un excellent exercice pour améliorer la condition physique de votre chien et renforcer votre lien. Elle permet de dépenser son énergie de manière constructive, tout en travaillant son souffle et ses muscles. Une pratique régulière peut aussi contribuer à prévenir l''obésité et certains problèmes de santé chez le chien.', 'Courez ensemble pour une meilleure endurance !', 'Courez à un rythme modéré sur une durée prolongée en gardant une allure constante avec votre chien.', 'Course d''endurance', 'Développer l''endurance de votre chien pour qu''il puisse courir plus longtemps à vos côtés, en toute sécurité.', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien maintient une allure de course stable pendant la durée prévue, sans signe de détresse physique ou mentale, et montre une attitude positive et récupérée après l''exercice. Il semble plus endurant lors des séances suivantes.', 'Le chien montre des signes de fatigue extrême (halètement excessif, affaissement, refus d''avancer), des boiteries, des blessures apparentes, ou une détresse visible. Le handler doit également arrêter si les conditions météorologiques deviennent dangereuses (chaleur ou froid extrêmes).', 'Observer la réactivité et l''enthousiasme du chien au début de la séance, sa capacité à maintenir un effort régulier sur la durée, et son comportement calme et récupéré à la fin. Surveiller les signes de fatigue ou d''inconfort pendant l''exercice.', 'Surveillez toujours l''état physique de votre chien et les conditions météorologiques. Ne le forcez jamais.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/endurance-longue.png'),
('course-cote', 'La course en côte est un excellent exercice cardiovasculaire pour renforcer les muscles des pattes arrière et améliorer l''endurance de votre chien. Elle est particulièrement utile pour les chiens sportifs ou ceux qui ont besoin de perdre du poids. Assurez-vous que votre chien est apte à ce type d''effort et augmentez l''intensité progressivement.', 'Faites de votre chien un athlète avec la Course en Côte !', 'Courez ou marchez rapidement en côte avec votre chien sur de courtes distances.', 'Course en côte', 'Améliorer la force musculaire, l''endurance et la condition physique de votre chien grâce à des sprints courts et intenses en montée.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et descend la pente avec assurance et sans crainte, récupère rapidement et montre de l''enthousiasme pour l''exercice lors des séances suivantes.', 'Signes évidents de fatigue (halètement excessif, refus de bouger), boiterie, douleur, blessure ou refus catégorique de continuer l''exercice.', 'Observer le chien pendant et après l''exercice. Évaluer sa capacité à monter la pente sans hésitation excessive, sa récupération après l''effort et l''absence de boiterie ou de douleur.', 'Faites très attention aux signes de surchauffe chez votre chien (halètement excessif, langue bleuâtre, démarche instable) et arrêtez tout effort immédiatement si vous les observez. Mettez le à l''ombre et donnez-lui de l''eau fraîche.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/course-cote.png'),
('crawl', 'Le ''Crawl'' est un exercice excellent pour renforcer le lien avec votre chien tout en améliorant sa confiance et son contrôle corporel. Il s''agit d''apprendre au chien à ramper vers vous sur commande, simulant un mouvement de reptation. Cet exercice nécessite patience et récompenses fréquentes pour encourager le chien à se baisser et à avancer.', 'Faites ramper votre chien pour le plaisir et la souplesse !', 'Guide votre chien au sol avec une friandise pour le faire ramper.', 'Crawl', 'Apprendre à votre chien à ramper sur commande, en se déplaçant au sol allongé sur le ventre, en suivant une friandise ou votre main.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien rampe sur une distance d''au moins 1 mètre en réponse à la commande ''Crawl'', avec le corps près du sol et en utilisant ses pattes avant, puis revient à une position neutre (assis ou couché) sans que le handler n''ait à tirer sur la laisse.', 'Arrêter l''exercice immédiatement si le chien montre des signes de stress, de peur, d''agression, de fatigue excessive, ou s''il se blesse. De plus, cesser si l''exercice devient une source de frustration pour vous ou le chien.', 'Observer si le chien exécute le mouvement de rampement de manière fluide et contrôlée sur commande verbale dans divers environnements. La durée et la distance parcourues doivent augmenter progressivement.', 'Soyez attentif à tout signe de douleur ou de boiterie pendant ou après l''exercice. Si cela se produit, consultez un vétérinaire.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/crawl.png'),
('zone-tampon', 'La création de zone tampon est une technique essentielle pour aider votre chien à mieux gérer son espace personnel et à éviter les réactions excessives face à d''autres chiens ou personnes. Cet exercice apprend au chien à se sentir à l''aise en présence d''une distraction sans avoir besoin de réagir. Il permet de renforcer le lien de confiance et de développer l''autocontrôle du chien.', 'Apprenez à votre chien à respecter votre bulle avec votre corps !', 'Interposez-vous calmement entre votre chien et ce qui le stimule en vous déplaçant latéralement.', 'Création de zone tampon', 'Apprendre à votre chien à maintenir une distance respectueuse lorsque vous vous interposez entre lui et ce qui le dérange, en utilisant votre corps comme un signal clair.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de maintenir une attitude calme et détendue, avec une respiration normale et un corps relâché, lorsque la distraction est présente à une distance de 5 à 10 mètres. Il peut détourner le regard et se tourner vers le propriétaire pour recevoir une récompense.', 'Arrêtez l''exercice si le chien montre des signes de stress excessif (halètement prononcé, tremblements, évitement marqué) ou s''il réagit de manière incontrôlable malgré vos interventions. Reprenez plus tard à une distance plus sécuritaire.', 'L''exercice est validé lorsque le chien peut tolérer la présence d''une distraction à une distance réduite sans montrer de signes de stress ou de réactivité, et qu''il est capable de se rediriger vers le propriétaire pour obtenir une récompense.', 'Soyez attentif à votre propre langage corporel : votre calme et votre confiance sont essentiels pour rassurer votre chien. Une tension de votre part sera ressentie par votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/zone-tampon.png'),
('croisement-chien', 'Cet exercice aide votre chien à rester calme et attentif à vous lorsque vous croisez d''autres chiens en promenade. Il apprendra à ignorer les autres chiens et à se concentrer sur vous, ce qui rendra vos sorties plus agréables et moins stressantes pour tout le monde.', 'Apprenez à votre chien à croiser d''autres chiens en toute sérénité !', 'Dès que vous voyez un autre chien, attirez l''attention du vôtre sur vous avec une friandise.', 'Croisement de chiens', 'Apprendre à votre chien à croiser d''autres chiens sans réagir, en restant détendu et concentré sur vous, même en présence de distractions.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de passer devant un autre chien en vous regardant ou en restant indifférent, sans tirer sur la laisse, aboyer ou montrer des signes de stress, sur au moins 5 croisements consécutifs.', 'Arrêtez l''exercice si votre chien montre des signes de stress importants (halètement excessif, salivation, tentatives d''évitement, aboiements répétés sans pouvoir capter son attention), s''il se désintéresse complètement des friandises, ou si l''intensité du passage des autres chiens est trop élevée (trop près, trop rapide, trop nombreux).', 'L''exercice est validé quand le chien croise 5 chiens différents de suite (à une distance de 3-5 mètres minimum), en gardant une laisse détendue, sans aboiement ni tirage, et en regardant le maître au moins 3 fois sur ces 5 croisements, à l''incitation du maître, ou volontairement. Ce comportement doit être observé sur 3 sorties consécutives.', 'Soyez vigilant à la distance de tolérance de votre chien. Commencez toujours l''exercice à une distance où il est capable de rester calme, même si c''est très loin de l''autre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/croisement-chien.png'),
('croisement-pieton', 'Cet exercice apprend à votre chien à marcher calmement à vos côtés quand vous croisez des personnes, sans tirer sur la laisse, aboyer ou leur sauter dessus. C''est essentiel pour des promenades sereines en ville ou dans des lieux fréquentés, pour la sécurité de tous et le bien-être de votre chien.', 'Apprenez à votre chien à croiser des piétons calmement et sans réagir.', 'Dès que vous voyez un piéton, attirez l''attention de votre chien, donnez-lui une friandise et continuez votre chemin.', 'Croisement de piétons', 'Apprendre à votre chien à ignorer les piétons et à rester concentré sur vous quand il croise des gens.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien peut croiser plusieurs piétons en marchant calmement à vos côtés, en vous regardant occasionnellement ou en acceptant une friandise sans manifester de stress ou de réactivité (aboiements, tiraillements).', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement excessif, salivation, léchage de babines, queue basse et agitée, tentatives de fuite) ou s''il perd complètement son attention et refuse les friandises. Il faut que l''exercice reste positif.', 'L''exercice est validé quand le chien croise 3 piétons sur 5 tentatives consécutives en restant à vos côtés sans tirer sur la laisse, aboyer, sauter, et en effectuant un contact visuel d''au moins 2 secondes avec le maître à la demande, le tout à une distance moyenne de 2 mètres des piétons.', 'Soyez toujours attentif aux signaux de votre chien. Chaque chien a son propre rythme d''apprentissage.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/croisement-pieton.png'),
('croiser-pattes', 'Apprenez à votre chien à croiser élégamment ses pattes avant lorsqu''il est couché. Ce tour amusant impressionnera vos amis et renforcera votre complicité. Cela demande de la patience et de la précision, mais le résultat est très gratifiant !', 'Un tour élégant qui renforce la complicité avec votre chien !', 'Placez une friandise de l''autre côté de la patte de votre chien pour l''encourager à la croiser.', 'Croiser les pattes', 'Apprendre à votre chien à croiser ses pattes avant sur commande, pour un tour mignon et amusant.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien croise ses pattes avant sur commande, sans aide de la friandise, en au moins 3 endroits différents. Il a l''air détendu et content de le faire.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, détourne le regard, se lèche les babines excessivement, ou semble agité. Ces signes indiquent qu''il est stressé ou fatigué.', 'L''exercice est validé quand le chien, positionné ''Couché'', croise ses deux pattes avant sur la commande ''Croise'' et maintient cette position pendant au moins 3 secondes, 4 fois sur 5 tentatives consécutives, sans aucune aide manuelle ou leurre visible.', 'Soyez attentif à tout signe d''inconfort ou de douleur, en particulier chez les chiens âgés ou ayant des problèmes articulaires.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/croiser-pattes.png'),
('cross-drive', 'Le "Cross Drive" est un exercice de conduite qui demande au chien de se déplacer perpendiculairement par rapport à vous, en suivant une trajectoire droite. Cela permet de renforcer votre communication et le contrôle directionnel de votre chien à distance, essentiel pour des balades sereines ou des sports canins.', 'Apprenez à votre chien à se déplacer avec précision à vos côtés, même à distance.', 'Demandez à votre chien de marcher droit devant lui, tout en restant parallèle à votre déplacement.', 'Cross drive', 'Votre chien apprend à se déplacer en ligne droite à côté d''un obstacle imaginaire ou réel, en maintenant une distance constante avec vous, un peu comme s''il poussait un troupeau sur le côté.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien avance droit devant lui, parallèle à votre marche, sur environ 3-5 mètres, et s''arrête de manière autonome à votre signal. Il doit sembler confiant et motivé.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (bâillements répétés, se gratte, détourne le regard) ou de frustration. C''est le signe qu''il a besoin d''une pause.', 'L''exercice est validé quand le chien effectue un Cross Drive sur une distance de 3 mètres, en maintenant une distance de moins de 1,5 mètre par rapport au maître, 4 fois sur 5 tentatives consécutives sans aide visuelle ou manuelle.', 'Soyez attentif à la posture de votre chien. Il doit être détendu et sûr de lui, pas raide ou hésitant. Sa queue doit être à une hauteur normale et se mouvoir naturellement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cross-drive.png'),
('quel-main', 'Le jeu du "Dans quelle main ?" est enrichissant et amusant pour votre chien. Il permet de stimuler son flair et sa réflexion en douceur. C''est un excellent moyen de renforcer votre lien et de lui offrir une activité mentale simple, mais efficace.', 'Un jeu simple pour stimuler le flair et la réflexion de votre chien.', 'Cachez une friandise et laissez votre chien deviner dans quelle main elle se trouve.', 'Dans quelle main ?', 'Apprendre à votre chien à utiliser son flair pour trouver une friandise cachée dans l''une de vos mains.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi si votre chien arrive à trouver la friandise dans la bonne main au moins 4 fois sur 5, en utilisant son flair.', 'Arrêtez l''exercice si votre chien bâille de façon répétée (signe de stress), se détourne, refuse de chercher, ou s''il semble frustré ou énervé.', 'L''exercice est validé quand le chien touche la bonne main avec son museau ou sa patte au moins 8 fois sur 10 tentatives consécutives, sans aide verbale ou gestuelle supplémentaire après ''Cherche !''.', 'Soyez attentif aux signaux d''apaisement de votre chien. Il doit rester calme et concentré pour profiter du jeu.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/quel-main.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('debout-base', 'L''exercice ''Debout'' enseigne au chien à se tenir debout sur commande, ce qui est un prérequis pour de nombreux autres exercices et un excellent moyen de renforcer le contrôle et la concentration. Cet exercice est utile pour habituer le chien à rester immobile dans différentes situations, que ce soit à la maison ou à l''extérieur. Il faut de la patience et de la répétition pour que le chien comprenne et exécute le ''Debout'' avec fiabilité.', 'Apprenez la position debout à votre chien facilement !', 'Avec une friandise, guidez votre chien pour qu''il se lève sans avancer.', 'Debout', 'Apprendre à votre chien à se lever sur commande, qu''il soit assis ou couché.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien se met debout sur commande verbale et/ou visuelle dans 80% des essais, maintient la position pendant 10 secondes sans bouger, et répond quelle que soit la distraction légère.', 'Le chien montre des signes de stress, d''ennui profond, de douleur, ou si les séances durent plus de 5 minutes sans succès notable. Reprendre plus tard avec une approche plus simple ou plus motivante.', 'Demander au chien de se mettre ''Debout'' et vérifier qu''il adopte la position correcte (sur ses quatre pattes) et la maintient pendant au moins 5 secondes sans aide. Répéter plusieurs fois.', 'Surveillez toujours les signes de fatigue ou de frustration chez votre chien. L''apprentissage doit être un moment agréable pour lui.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/debout-base.png'),
('debout-en-marche', 'Le ''Debout en marche'' est un exercice d''obéissance avancée destiné à apprendre au chien à rester immobile dans une position définie (assis, couché, ou debout) pendant que le maître s''éloigne sur une courte distance, puis à le rejoindre. Cet exercice développe la concentration, le contrôle de soi et la confiance entre le chien et son propriétaire. Il est progressif et nécessite une base solide en obéissance.', 'Faites rester votre chien debout pendant que vous marchez, pour plus de contrôle.', 'Demandez à votre chien de "Debout" et marchez quelques pas avant de revenir le récompenser.', 'Debout en marche', 'Apprendre à votre chien à rester debout et immobile, même lorsque vous vous déplacez, afin d''améliorer son obéissance et sa gestion en toutes circonstances.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste inflexiblement debout, sans aucune tentative de déplacement ou de mouvement de tête / corps, pendant toute la durée de l''absence du propriétaire et jusqu''au signal de rappel. La réaction au rappel est rapide et enthousiaste.', 'Le chien montre des signes de stress, de fatigue, d''agitation ou d''incompréhension. Si le chien ne parvient pas à maintenir la position pendant plus de quelques secondes malgré des aides ou des retours rapides, il faut arrêter l''exercice et revenir à une étape plus simple ou à un entraînement de base.', 'Pour valider l''exercice, le chien doit rester immobile dans la position demandée (''Debout'') pendant que le propriétaire s''éloigne sur au moins 5 mètres, tourne le dos, et revienne à sa position initiale sans que le chien ne bouge. Le rappel à la fin doit être exécuté sans hésitation.', 'Vérifiez toujours l''environnement avant de commencer : pas de dangers, sol non glissant. Ne mettez jamais votre chien en situation d''échec.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/debout-en-marche.png'),
('cardboard-destroy', 'Le déchiquetage de carton est un excellent exercice pour stimuler mentalement votre chien et lui permettre de dépenser de l''énergie de manière constructive. Cela détourne le besoin naturel de mastication et de destruction vers un objet approuvé. Assurez-vous d''utiliser du carton propre et sans ruban adhésif ni agrafes pour la sécurité de votre animal.', 'Un jeu destructeur et malin pour un chien joyeux !', 'Proposez un carton rempli de friandises à détruire, encouragez votre chien à chercher et à déchirer.', 'Déchiquetage de carton', 'Apprendre à votre chien à déchiqueter un carton en toute sécurité pour trouver des friandises, développant ainsi sa confiance et sa résolution de problèmes.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien déchiquette et/ou mâche le carton de manière active et enjoyée, sans essayer d''ingérer de grosses portions ni montrer de signes d''anxiété ou de frustration persistante.', 'Le chien ingère de gros morceaux de carton, devient excessivement anxieux ou frustré, perd tout intérêt, ou si l''exercice dépasse le temps recommandé ou la capacité de supervision du propriétaire.', 'Le chien doit montrer un intérêt actif pour le carton et s''engager dans l''activité de déchiquetage ou de mastication pendant la durée prévue de l''exercice, sous supervision.', 'Surveillez toujours l''ingestion de carton : de petits morceaux ne sont généralement pas problématiques, mais de gros morceaux peuvent causer des occlusions.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/cardboard-destroy.png'),
('surfaces-chiot', 'Cet exercice vise à familiariser votre chien avec une variété de surfaces inhabituelles ou potentiellement intimidantes. En l''exposant progressivement à différentes textures et sensations sous ses pattes, vous renforcerez sa confiance dans des environnements variés. C''est une excellente activité pour prévenir les peurs futures et encourager une attitude positive face à la nouveauté.', 'Aidez votre chien à explorer de nouvelles surfaces en toute confiance et à devenir un toutou bien dans ses pattes !', 'Faites découvrir de nouvelles surfaces à votre chien en le guidant doucement avec une friandise.', 'Découverte de surfaces', 'Apprendre à votre chien à marcher avec assurance sur diverses surfaces pour renforcer sa confiance en lui dans des environnements variés.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien traverse calmement et avec confiance la majorité des surfaces proposées sans signe de stress. Il est curieux et montre une ouverture à explorer de nouvelles textures. Il est capable de se concentrer sur vous malgré la nouveauté sensorielle.', 'Le chien montre des signes clairs de détresse (peur intense, tentative de fuite, agressivité défensive). L''exercice génère plus de stress que de confiance. La situation devient dangereuse pour le chien ou pour l''environnement.', 'Évaluer la réactivité du chien face à différentes textures (métal, bois, tissu épais, caoutchouc, gravier lisse, herbe artificielle, etc.) dans divers environnements (calme, légèrement animé). Observer sa posture, ses mouvements, et son niveau d''excitation ou de stress.', 'Observez toujours les réactions de votre chien. Le but est de construire la confiance, pas de créer du stress.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/surfaces-chiot.png'),
('chiot-jardin', 'Cet exercice vise à familiariser votre chien avec l''environnement extérieur sécurisé de votre jardin. Il permet au chien d''explorer, de sentir et de découvrir les nouvelles odeurs, textures et recoins du jardin en toute confiance. L''objectif est de créer une association positive avec cet espace et de le rendre confortable pour votre compagnon.', 'Explorez le jardin avec votre chien pour qu''il s''y sente bien et en sécurité !', 'Accompagnez votre chien dans son jardin en le laissant explorer à son rythme, en le guidant doucement si besoin.', 'Découverte du jardin', 'Apprendre à votre chien à explorer son jardin tranquillement et en sécurité, pour qu''il se sente confiant et à l''aise dans cet espace vert.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien entre volontairement dans le jardin, explore activement et montre des signes de détente et d''intérêt pour son environnement. Il termine la séance sur une note positive.', 'Le chien montre des signes de stress intense (halètements excessifs, tremblements, tentatives de fuite répétées) ou est complètement désintéressé et refuse d''interagir.', 'Observer la réaction du chien à l''entrée du jardin, sa curiosité et son intérêt pour l''exploration. Noter s''il présente des signes de peur ou d''anxiété.', 'Soyez attentif à tout élément nouveau ou dangereux qui pourrait apparaître dans le jardin (fruits tombés, objets curieux).', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/chiot-jardin.png'),
('defense-maitre', 'La "défense du maître" n''est PAS un exercice de protection agressive. Il s''agit d''apprendre à votre chien à rester calme et confiant face à des situations potentiellement stressantes en votre présence. L''objectif est de renforcer votre lien et la confiance que votre chien a en vous pour gérer diverses situations.', 'Un exercice pour une confiance mutuelle renforcée !', 'Apprenez à votre chien à rester calme et attentif à vous face à des stimuli variés.', 'Défense du maître', 'Apprendre à votre chien à rester serein et confiant en votre présence, même face à des inconnus ou des bruits soudains, en augmentant la confiance mutuelle.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de rester calme et attentif à vous en présence de stimuli variés (personnes, bruits légers) sans grogner, aboyer ou tenter de fuir. Il vous regarde et attend vos instructions, même face à l''inconnu.', 'Arrêtez immédiatement si votre chien montre des signes de stress importants (tremblements, halètements excessifs, se fige, tente de fuir), de fatigue ou s''il perd tout intérêt pour l''exercice (ne prend plus les friandises, vous ignore complètement).', 'L''exercice est validé quand le chien reste calme (pas d''aboiements, pas de tirage excessif sur la laisse) pendant au moins 30 secondes en présence d''un ''intrus'' à une distance de 3 mètres, et ce, lors de 4 tentatives sur 5 occasions consécutives, sans intervention physique du maître (hormis la tenue de laisse) et en répondant à 2 commandes vocales sur 3 (ex: ''Calme'', ''Regarde-moi'').', 'Ce n''est pas un exercice de garde. Soyez vigilant à ne pas inconsciemment encourager des comportements agressifs. L''objectif est la sérénité et la confiance.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/defense-maitre.png'),
('demi-tour', 'Le demi-tour est une technique simple mais très pratique pour vous aider à mieux gérer les promenades avec votre chien. Il apprend à votre chien à changer de direction avec vous, en restant concentré. Cela rend les sorties plus agréables, plus calmes et plus sûres pour vous deux.', 'Apprenez à votre chien à vous suivre dans chaque tournant, pour des promenades complices !', 'Faites un demi-cercle et incitez votre chien à vous suivre, puis récompensez-le chaleureusement.', 'Demi-tour', 'Apprendre à votre chien à faire demi-tour naturellement quand vous changez de direction, pour une meilleure connexion en promenade.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien fait le demi-tour avec vous de manière fluide et naturelle, en restant attentif à votre mouvement, sans que vous ayez besoin de tirer sur la laisse ou de le guider avec une friandise.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (traîne des pattes, ignore la friandise), de stress (se gratte, se lèche les babines de manière excessive) ou s''il perd tout intérêt (renifle par terre en continu, ne vous regarde plus). La session doit rester un moment positif.', 'L''exercice est validé quand le chien exécute le demi-tour en tournant dans la même direction que le maître, la laisse restant détendue (sans aucune traction du maître), sur 7 de 10 tentatives consécutives, et dans un environnement avec des distractions légères.', 'Soyez vigilant à la fluidité de votre mouvement et à ne pas brusquer votre chien. Le demi-tour doit être un geste naturel et non une contrainte.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/demi-tour.png'),
('demi-tour-suite', 'Le demi-tour en suite est un exercice de précision qui renforce la connexion entre vous et votre chien pendant la promenade. Il apprend à votre chien à changer de direction avec vous, de manière fluide et attentive, comme un danseur. C''est très utile pour éviter les situations délicates en ville ou pour une marche au pied impeccable.', 'Un demi-tour fluide et en synchronisation parfaite avec votre chien !', 'Inversez le pas en guidant votre chien avec fluidité pour qu''il reste à votre hauteur.', 'Demi-tour en suite', 'Apprendre à votre chien à faire un demi-tour parfait et attentif à vos côtés, en gardant une position précise.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien fait un demi-tour fluide et rapide, se repositionnant parfaitement à vos côtés sans que la laisse ne se tende. Il reste attentif à votre présence.', 'Arrêtez l''exercice si votre chien tire sur la laisse, tente de vous ignorer, renifle le sol sans interruption ou montre des signes de stress (halètement excessif, bâillements répétés, léchage de babines).', 'L''exercice est validé lorsque le chien effectue un demi-tour précis, en restant à votre gauche et en reprenant une position ''au pied'' correcte, dans 4 cas sur 5 tentatives consécutives, sans tension sur la laisse, dans un environnement peu distrayant. La transition entre l''ancien et le nouvel axe de marche doit être fluide.', 'Vérifiez l''équilibre et la souplesse de votre chien quand vous l''exécutez. Choisissez toujours un endroit sécurisé et calme pour ne pas le perturber.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/demi-tour-suite.png'),
('desescalade-surface', 'Cet exercice consiste à descendre une pente raide ou un escalier difficile aux côtés de votre chien, en le guidant et en le sécurisant. Cela renforce votre lien et la confiance de votre chien dans des situations délicates. C''est utile pour les randonnées ou les accès compliqués.', 'Descendez ensemble les pentes difficiles en toute sécurité !', 'Marchez à côté de votre chien, main sur son collier, pour l''aider à descendre une pente raide ou des escaliers.', 'Descente en rappel assistée', 'Apprendre à votre chien à descendre en toute sécurité une pente ou des escaliers difficiles à vos côtés, en confiance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien descend la pente ou l''escalier à votre rythme, calmement, sans tirer ni tenter de fuir. Il accepte votre main sur son collier comme un soutien.', 'Si votre chien montre des signes de stress (halètement excessif, oreilles en arrière, queue basse, refus d''avancer, gémissements) ou s''il semble fatigué, arrêtez immédiatement. Ne le forcez jamais.', 'L''exercice est validé quand le chien descend une pente modérément raide (environ 30°) ou un escalier de 10 marches aux côtés du maître sans aucune tension sur la laisse et sans aide physique, 3 fois sur 5 tentatives consécutives, en affichant des signes de confiance (queue neutre ou légèrement haute, pas fluides).', 'Soyez toujours vigilant à l''environnement : pas d''obstacles, pas de personnes imprévues qui pourraient vous bousculer.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desescalade-surface.png'),
('desens-eau', 'Cet exercice aide votre chien à se sentir à l''aise et calme au contact de l''eau, que ce soit pour un bain, la pluie, ou des jeux aquatiques. L''objectif est de transformer une expérience potentiellement stressante en un moment agréable et sans peur pour lui.', 'Faites de l''eau une amie pour votre chien avec des jeux et de la patience !', 'Présentez l''eau doucement, sans forcer, en associant chaque contact à une récompense positive.', 'Désensibilisation à l''eau', 'Rendre l''eau amusante et non effrayante pour votre chien, afin qu''il accepte les bains et ne craigne plus les flaques ou les jeux aquatiques.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien s''approche volontiers de l''eau, accepte d''y tremper les pattes et ne montre aucun signe de stress lors d''un contact doux. Il peut même chercher à jouer avec l''eau.', 'Arrêtez immédiatement l''exercice si votre chien gémit, tremble, essaie de fuir, se lèche les babines de manière excessive, bâille beaucoup ou a le poil hérissé. Ce sont des signes de stress.', 'L''exercice est validé quand le chien s''approche volontairement de la source d''eau (bassine, flaque) et interagit positivement (patte dans l''eau, museau à la surface, jeu avec un jouet aquatique) pendant au moins 30 secondes, sur 3 tentatives consécutives sans signe de stress et ce, avec une intensité d''eau augmentant progressivement (ex: plus d''eau dans la bassine, jet d''eau doux de l''arrosoir).', 'Soyez attentif à tout signe d''inconfort ou de stress chez votre chien. Chaque étape doit être validée par son enthousiasme et sa décontraction.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-eau.png'),
('desens-aspirateur', 'Cet exercice vise à habituer votre chien à l''aspirateur, une source de bruit et de mouvement souvent stressante. L''objectif est de transformer cette perception négative en une expérience neutre, voire positive. Il est crucial de procéder par étapes progressives pour ne pas brusquer le chien et construire sa confiance.', 'Faites de l''aspirateur un ami, pas un monstre !', 'Proposez une friandise à votre chien à chaque fois que l''aspirateur apparaît ou fait du bruit.', 'Désensibilisation aspirateur', 'Apprendre à votre chien à être détendu en présence de l''aspirateur, qu''il soit éteint ou en marche.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien peut rester dans la même pièce que l''aspirateur allumé, bouger et aspirer sans montrer de signes de peur ou d''agressivité. Le chien accepte les friandises et recherche le contact visuel avec le propriétaire pendant l''exercice.', 'Le chien montre des signes clairs de détresse : halètement excessif, tremblements, salivation importante, tentatives de fuite désespérées, agressivité (grognements, morsures).', 'Observer attentivement toutes les réactions du chien : oreilles, queue, posture, vocalises, tentatives de fuite. Relever le niveau de stress ou d''inconfort. Valider le passage à l''étape suivante uniquement si le chien est dans un état de calme et de curiosité.', 'Soyez attentif à tout signe de peur ou d''inconfort chez votre chien et ajustez l''exercice en conséquence.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-aspirateur.png'),
('desens-dents', 'Cet exercice vise à habituer progressivement votre chien au brossage de ses dents, une étape cruciale pour son hygiène bucco-dentaire. L''objectif est de rendre cette expérience positive et sans stress pour lui, en utilisant des renforcements positifs. Une bonne hygiène dentaire prévient de nombreux problèmes de santé chez le chien.', 'Rendez le brossage de dents un moment de plaisir pour votre chien !', 'Proposez le matériel de brossage petit à petit, en associant chaque étape à une récompense.', 'Désensibilisation brossage den', 'Apprendre à votre chien à tolérer de plus en plus le contact et le mouvement de la brosse à dents dans sa gueule, sans stress ni peur.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte que vous manipuliez ses babines et que vous brossiez doucement plusieurs de ses dents avec une brosse (même brièvement) sans montrer de signes de peur ou d''agression, et associe cette action à des récompenses positives.', 'Le chien montre des signes clairs de stress, de peur, d''agression (mordillement, grognement), ou une aversion marquée pour l''outil ou la manipulation. Si le chien est vraiment stressé, il faut s''arrêter et reprendre l''exercice plus tard ou avec une approche différente.', 'Observer la réaction du chien lors de chaque étape. Le chien doit rester calme, curieux et accepter le contact de la pâte ou de la brosse sans signes de stress (halètement excessif, bâillements de stress, tremblements, tentative de fuite, grognements).', 'La constance est la clé : des sessions courtes mais régulières sont plus efficaces qu''une longue session occasionnelle.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-dents.png'),
('desens-sac-poubelle', 'Cet exercice vise à habituer progressivement votre chien à la présence et au bruit de sacs en plastique, souvent source d''anxiété ou de peur chez certains individus. L''objectif est de créer une association positive avec ce son, le rendant ainsi plus supportable dans la vie quotidienne. Une approche douce et progressive est essentielle pour que le chien apprenne en toute confiance.', 'Transformez la peur des sacs en plastique en indifférence joyeuse !', 'Froissez doucement un sac en plastique loin de votre chien et récompensez son calme.', 'Désensibilisation bruits sacs ', 'Apprendre à votre chien à rester calme et détendu en présence du bruit de sacs en plastique, même quand il est inattendu.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien tolère le bruit du sac en plastique lorsqu''il est froissé modérément, même à proximité, sans montrer de signes de peur intense (fuite, tremblements, aboiements excessifs). Il peut même réagir avec une légère curiosité ou indifférence.', 'Si le chien montre des signes de peur ou de stress graves et persistants malgré les ajustements, il est préférable d''arrêter la séance pour ne pas aggraver la situation. Le renforcement positif doit toujours être le maître mot.', 'Observer la réaction du chien à différentes intensités et distances de bruit de sac en plastique. L''objectif est que le chien reste calme, curieux ou indifférent plutôt que peureux ou anxieux.', 'Observez attentivement les réactions de votre chien. Chaque chien a son propre rythme d''apprentissage. Ne le forcez jamais et adaptez-vous à ses signaux.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-sac-poubelle.png'),
('desens-cage-transport', 'La désensibilisation à la cage de transport est un processus graduel pour aider votre chien à associer la caisse à des expériences positives et à se sentir en sécurité à l''intérieur. L''objectif est de surmonter toute peur ou anxiété liée à la cage, permettant ainsi des déplacements plus sereins pour vous deux. Une approche patiente et positive est essentielle pour le succès de cet exercice. Cela peut être utile pour les voyages, les visites chez le vétérinaire ou simplement pour offrir un espace de repos sécurisé à votre animal.', 'Faites de la cage de votre chien un endroit qu''il adore !', 'Placez la cage dans un endroit calme et attirez votre chien à l''intérieur avec des friandises, sans le forcer.', 'Désensibilisation cage de tran', 'Aider votre chien à se sentir bien et en sécurité dans sa cage de transport, pour qu''il y entre et y reste calmement quand on lui demande.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien entre dans la cage de transport sans hésitation lorsqu''elle est ouverte, y reste calme et détendu (même avec la porte fermée pendant plusieurs minutes), et accepte d''y être transporté pour de courtes durées sans panique.', 'Le chien montre des signes de peur, de panique, de détresse (aboiements excessifs, gémissements, tentatives désespérées de sortie, halètement très fort) ou de refus catégorique de coopérer. L''exercice doit être stoppé immédiatement pour ne pas renforcer l''anxiété.', 'Observer que le chien entre volontairement dans la cage ouverte, y reste calme pendant de courtes périodes avec la porte fermée, et tolère des déplacements légers de la cage, le tout sans signes de détresse.', 'Observez attentivement les expressions corporelles de votre chien. Le moindre signe de malaise doit vous alerter et vous faire ralentir.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-cage-transport.png'),
('desens-chapeau', 'Cet exercice a pour but d''aider votre chien à ne plus avoir peur des casquettes et des chapeaux. Il est essentiel d''aborder cela en douceur, en associant l''objet à des expériences positives. Progressivement, le chien apprendra que ces accessoires ne représentent aucune menace.', 'Apprenez à votre chien à aimer les chapeaux !', 'Présentez une casquette de manière positive et récompensez votre chien dès qu''il reste calme.', 'Désensibilisation casquettes/c', 'Apprendre à votre chien à ne pas être effrayé ou surpris par le port de casquettes ou de chapeaux, en associant ces objets à des expériences positives et agréables.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien peut voir un chapeau porté par son propriétaire sans manifester de signes de peur, de stress ou d''agressivité, et peut même interagir positivement avec (ex: curiosité, indifférence).', 'Le chien montre des signes clairs de peur (tremblements, tentatives de fuite, halètement excessif, s''accroupit, grogne, aboie). Le propriétaire ne parvient pas à maintenir une dynamique positive avec le chien.', 'Observer le chien lors de chaque étape : est-il détendu, curieux, ou anxieux ? Réagir en fonction de ses réactions : avancer si calme, reculer si stressé. Utiliser des friandises et des félicitations vocales uniquement quand le chien montre un comportement calme ou neutre face au chapeau.', 'Certains chiens peuvent avoir une mauvaise expérience passée avec les chapeaux. Soyez particulièrement attentif à leurs réactions et n''hésitez pas à demander l''aide d''un professionnel.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-chapeau.png'),
('desens-collier-elisabethain', 'Cet exercice aide votre chien à mieux supporter le port de la collerette, souvent nécessaire après une opération ou une blessure. L''objectif est de rendre cette expérience moins stressante pour lui, afin qu''il puisse récupérer sereinement sans contrainte. Nous allons y aller pas à pas pour qu''il s''habitue en douceur.', 'Rendez la collerette amie de votre chien en douceur !', 'Présentez la collerette, récompensez, puis augmentez progressivement la durée du contact.', 'Désensibilisation collerette', 'Aider votre chien à accepter calmement le port de la collerette pour les soins vétérinaires ou la convalescence, en réduisant son stress.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme quand vous lui mettez la collerette, ne se débat pas et tolère de la garder quelques minutes sans signe de stress. Il peut vaquer à ses occupations habituelles (manger, boire, se reposer) avec la collerette.', 'Si votre chien se fige, tremble, bâille à répétition, détourne la tête, essaie de fuir ou se gratte frénétiquement la collerette, arrêtez l''exercice immédiatement. Ce sont des signes de stress ou d''inconfort. Reprenez plus tard à une étape plus facile.', 'L''exercice est validé quand le chien accepte que la collerette soit posée sur sa tête pendant 30 secondes, 5 fois sur 5 tentatives consécutives, sans signe de stress (halètement, tentative de l''enlever, fuite) et qu''il accepte de la porter attachée pendant 1 minute, 3 fois sur 3 tentatives consécutives, en restant calme.', 'Soyez attentif à tout signe d''irritation ou de frottement excessif de la collerette sur sa peau. Vérifiez régulièrement son cou.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-collier-elisabethain.png'),
('desens-feux-artifice', 'Cet exercice aide votre chien à mieux supporter les bruits forts et soudains comme les feux d''artifice ou les orages. L''idée est de l''habituer doucement pour qu''il n''ait plus peur. On va commencer avec des sons très faibles et augmenter le volume petit à petit, toujours en douceur.', 'Habituez votre chien aux bruits forts pour qu''il n''ait plus peur.', 'Diffusez des bruits de feux d''artifice très faibles pendant que votre chien fait une activité agréable.', 'Désensibilisation feux d''artif', 'Aider votre chien à tolérer les bruits intenses et imprévus pour qu''il reste calme et serein face aux feux d''artifice ou aux orages.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien peut écouter l''enregistrement des feux d''artifice à un volume réaliste sans montrer de signes de stress, tout en continuant une activité normale et détendue.', 'Dès que votre chien montre le moindre signe d''inconfort, de stress (queue entre les pattes, oreilles en arrière, halètement, tremblements) ou s''il perd tout intérêt pour l''activité proposée, arrêtez la séance. Il est crucial de ne pas dépasser son seuil de tolérance.', 'L''exercice est validé quand le chien reste calme (pas de tremblements, halètements excessifs, tentatives de fuite) et prend systématiquement une friandise très appétissante dans les 3 secondes suivant l''émission du son, à un volume sonore de 80% maximum du volume maximal de l''appareil de diffusion, et ce, lors de 5 tentatives consécutives réparties sur 2 jours différents, avec au moins 3 types de sons différents.', 'La désensibilisation est un processus long et progressif. Chaque petite avancée est une victoire. Ne brûlez pas les étapes.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-feux-artifice.png'),
('desens-sol-grille', 'Cet exercice aide votre chien à se sentir à l''aise et sûr de lui lorsqu''il marche sur des surfaces nouvelles ou inhabituelles, comme les grilles métalliques des bouches d''égout ou des passages qui font du bruit sous les pattes. C''est important pour les promenades en ville ou dans des lieux publics. Votre chien apprendra à gérer son appréhension et à vous faire confiance dans ces situations.', 'Aidez votre chien à surmonter sa peur des grilles et des surfaces inconnues.', 'Approchez calmement la grille, récompensez la moindre interaction positive et guidez votre chien pour qu''il la traverse pas à pas.', 'Désensibilisation grilles au s', 'Apprendre à votre chien à marcher sereinement sur différentes grilles au sol sans montrer de peur ou d''hésitation.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien s''approche volontairement des grilles, les traverse sans hésitation et montre un langage corporel détendu (queue haute, oreilles relaxes, pas souples). Il peut même vous regarder pour demander sa friandise après avoir traversé.', 'Arrêtez immédiatement si votre chien montre des signes de stress importants : queue sous le ventre, oreilles en arrière, halètement excessif, tremblements, tentatives de fuite, refus net d''avancer. Faites une pause et reprenez plus tard ou à un niveau plus simple.', 'L''exercice est validé quand le chien traverse une grille de plus de 1,5 mètre de long, 5 fois consécutives, sans aucune hésitation, sans s''arrêter et sans que le maître n''ait besoin d''utiliser de leurre (friandise), mais uniquement des encouragements verbaux, et ce sur 3 types de grilles différentes (métal, bois, plastique).', 'Soyez très attentif au langage corporel de votre chien. Le moindre signe d''inconfort doit être pris au sérieux. Avancez à son rythme et non au vôtre.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-sol-grille.png'),
('desens-manipulations-pattes', 'Apprenez à votre chien à aimer qu''on lui touche les pattes. C''est très utile pour le couper les griffes, le sécher après une balade ou enlever une épine. Nous allons y aller doucement pour qu''il se sente en confiance.', 'Rendez la manipulation des pattes agréable pour votre chien !', 'Touchez doucement la patte de votre chien et donnez-lui une friandise aussitôt.', 'Désensibilisation manipulation', 'Apprendre à votre chien à accepter calmement le toucher et la manipulation de ses pattes, sans stress ni peur.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme, ne retire pas sa patte et accepte que vous touchiez ses doigts. Il peut même anticiper la friandise quand vous vous penchez vers sa patte.', 'Si votre chien retire sa patte de manière répétée, tourne la tête, lèche sa babine, bâille ou tente de s''éloigner, arrêtez l''exercice. Il est stressé ou fatigué.', 'L''exercice est validé quand le chien accepte un toucher léger sur chaque patte (chaque doigt) pendant 5 secondes consécutives, sans signe de stress (tremblement, retrait, léchage excessif) et sans tentative de retrait, 4 fois sur 5 tentatives consécutives.', 'Ne faites jamais cet exercice si votre chien est blessé ou a mal aux pattes, vous risqueriez d''aggraver la douleur et de créer une association négative.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-manipulations-pattes.png'),
('desens-museliere', 'Cet exercice vise à rendre la muselière moins effrayante pour votre chien, en l''associant à des expériences positives. L''objectif est qu''il accepte de la porter sans stress, pour sa sécurité et celle des autres lors de situations spécifiques comme les visites chez le vétérinaire ou les transports.', 'Transformez la muselière en un accessoire positif pour votre chien !', 'Présentez la muselière comme une source de récompenses délicieuses.', 'Désensibilisation muselière', 'Apprendre à votre chien à aimer sa muselière et la porter calmement, sans contrainte, grâce à des associations positives.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien met sa muselière calmement et de lui-même quand vous la lui présentez. Il la porte tranquillement pendant plusieurs minutes en étant détendu.', 'Arrêtez l''exercice si votre chien tourne la tête, recule, se lèche les babines de manière excessive, bâille, détourne le regard ou montre des signes de stress. Il est important de finir la séance sur une note positive.', 'L''exercice est validé quand le chien accepte de mettre sa muselière par lui-même (en allant mettre son museau dedans ou en coopérant à sa mise en place) et la porte pendant 5 minutes consécutives sans tenter de la retirer, et ce, 3 fois sur 5 tentatives consécutives dans un environnement calme.', 'Vérifiez toujours que votre chien peut bien respirer et que la muselière ne lui blesse pas le museau. Une muselière bien ajustée est essentielle.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-museliere.png'),
('desens-oreilles', 'La désensibilisation au nettoyage des oreilles est cruciale pour la santé de votre chien. Cet exercice vise à habituer progressivement votre compagnon à la manipulation de ses oreilles et à l''utilisation d''un produit de nettoyage. Une approche douce et positive permet de prévenir la peur ou l''anxiété lors des soins, rendant cette routine plus agréable pour vous deux.', 'Rendez le soin des oreilles facile et agréable pour votre chien dès maintenant !', 'Associez délicatement le toucher des oreilles de votre chien à des friandises et des caresses.', 'Désensibilisation nettoyage or', 'Apprendre à votre chien à accepter le toucher et l''inspection de ses oreilles calmement et sans stress.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte passivement et sans crainte la manipulation de ses oreilles et l''application du produit nettoyant, voire recherche l''interaction. Il reste calme pendant toute la durée de la séance.', 'Le chien montre des signes clairs de peur, d''anxiété, de stress ou d''agressivité (grognement, tentative de morsure, fuite intense). L''exercice devient une source de conflit.', 'Observer la réaction du chien : recherche-t-il activement la manipulation, la queue remue-t-elle, son corps est-il détendu ? Y a-t-il des signes de peur (lèvres pincées, bâillements excessifs, détournement du regard) ?', 'Le nettoyage des oreilles doit toujours être un moment de calme et de collaboration, jamais une lutte.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-oreilles.png'),
('desens-orage', 'La désensibilisation aux orages est un processus graduel visant à aider un chien à mieux tolérer les bruits forts et soudains associés aux orages. L''objectif est de changer l''association négative du chien avec ces sons en une association neutre, voire positive. Cela demande patience, cohérence et une approche positive de la part du propriétaire.', 'Dédramatiser les orages pour un chien plus serein.', 'Diffusez des bruits d''orage et associez-les à des moments positifs pour votre chien.', 'Désensibilisation orages', 'Aider votre chien à tolérer et à rester calme face aux bruits et aux éclairs d''orage, pour diminuer son stress et ses réactions de panique.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et détendu, voire continue à jouer ou manger, lorsque les sons d''orage sont reproduits à un volume raisonnablement élevé (simulant une intensité d''orage modérée), et montre peu ou pas de réaction de peur.', 'Le chien montre des signes évidents et persistants de panique, de stress intense, ou il tente activement de fuir la source sonore malgré les efforts du maître pour le rassurer. Dans ce cas, il faut arrêter l''exercice et consulter un professionnel.', 'Observer la réaction du chien à différents volumes sonores. Le chien doit rester détendu, sans signes de stress (halètement excessif, tremblements, tentatives de fuite, vocalises). Le chien doit pouvoir manger des friandises et interagir positivement avec le maître au volume testé.', 'Soyez très attentif aux signaux d''apaisement de votre chien pour ne pas le brusquer et renforcer sa peur.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-orage.png'),
('desens-parapluie', 'La désensibilisation au parapluie est une technique d''éducation canine essentielle pour aider votre chien à ne plus avoir peur des objets qui s''ouvrent soudainement ou qui sont inhabituels. Cet exercice permet de créer une association positive avec le parapluie, transformant la peur en curiosité ou indifférence. Il est crucial de procéder par étapes progressives pour ne pas submerger le chien et construire sa confiance.', 'Apprenez à votre chien à aimer les parapluies !', 'Ouvrez et fermez doucement un parapluie en récompensant votre chien pour son calme.', 'Désensibilisation parapluie', 'Votre chien apprend à rester calme et détendu face à un parapluie qui s''ouvre, pour qu''il ne panique plus en promenade.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme, voire curieux, lorsque le parapluie est ouvert, fermé, et même légèrement manipulé à proximité. Il ne montre plus de signes de panique ou de fuite face à cet objet.', 'Arrêtez la séance si le chien montre des signes de stress intenses ou de fatigue. Terminez toujours sur une note positive, même si cela signifie revenir à une étape très simple où le chien réussit.', 'Observez le comportement du chien à chaque étape. Le chien doit montrer des signes de calme, de curiosité ou d''indifférence. S''il y a des signes de stress, retournez à l''étape précédente ou reculez.', 'Soyez très attentif aux réactions de votre chien. Le but est de créer une association positive, pas de le traumatiser.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-parapluie.png'),
('desens-piqure', 'La désensibilisation aux piqûres vise à habituer votre chien à des stimuli inhabituels et potentiellement stressants. Cet exercice est crucial pour les chiens anxieux ou ceux qui doivent subir des soins vétérinaires fréquents. L''objectif est de créer une association positive avec les manipulations, réduisant ainsi l''anxiété lors des visites chez le vétérinaire ou les toilettages.', 'Préparez votre chien aux piqûres pour des visites vétérinaires sereines !', 'Touchez doucement le cou ou la cuisse de votre chien avec votre doigt ou un capuchon de stylo, puis donnez une friandise.', 'Désensibilisation piqûres', 'Habituer votre chien à être touché comme pour une piqûre, afin qu''il reste calme lors des visites chez le vétérinaire ou en cas de besoin de soins.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien accepte passivement et sans signe d''anxiété des touchers légers et des simulations de piqûres sur différentes parties du corps, associant ces manipulations à des récompenses positives.', 'Le chien montre des signes évidents de peur, d''agressivité, ou une détresse généralisée. L''exercice doit être arrêté immédiatement si le chien ne peut pas être calmé ou s''il est manifestement mal à l''aise.', 'Observer la réaction du chien à chaque étape. La validation se fait lorsque le chien reste détendu et accepte le contact ou la manipulation sans signe de stress.', 'Surveillez toujours le langage corporel de votre chien. Le moindre signe d''inconfort doit vous faire ralentir ou arrêter.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-piqure.png'),
('desens-seche-cheveux', 'La désensibilisation au sèche-cheveux est essentielle pour aider un chien à ne pas craindre cet appareil bruyant. L''objectif est d''associer le son du sèche-cheveux à des expériences positives, en commençant à distance et en augmentant progressivement l''exposition. Cet exercice requiert patience et constance pour garantir le bien-être de votre animal.', 'Transformez la peur du sèche-cheveux en moment de calme avec votre chien !', 'Proposez une friandise à votre chien pendant qu''une autre personne allume puis éteint le sèche-cheveux loin de lui.', 'Désensibilisation sèche-cheveu', 'Apprendre à votre chien à rester calme et détendu face au bruit et au souffle du sèche-cheveux, pour faciliter les séances de séchage.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable de rester calme (pas de signes de peur ou d''anxiété extrême) pendant que le sèche-cheveux est allumé et à proximité raisonnable, même s''il est utilisé doucement dans sa direction. Il accepte des friandises et ne cherche pas à fuir.', 'Le chien montre des signes de stress importants (halètement excessif, tremblements, tentatives répétées de fuite, grognements, refus catégorique de nourriture). Toute réaction de peur extrême ou tout signe de panique.', 'Observer la réaction du chien face au son et au mouvement du sèche-cheveux à différentes distances et intensités. S''assurer qu''il reste calme, curieux, ou ignore l''appareil, et qu''il accepte les récompenses.', 'Il est crucial d''avancer très, très lentement et de toujours respecter le rythme de votre chien pour ne pas aggraver sa peur. La patience est la clé.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-seche-cheveux.png'),
('desens-sons-enregistres', 'Cet exercice aide votre chien à mieux supporter les bruits forts ou inattendus qui peuvent le stresser, comme les orages ou les feux d''artifice. En écoutant des sons enregistrés à faible volume, votre chien va s''habituer progressivement et apprendre à rester calme face à ces bruits.', 'Aidez votre chien à surmonter sa peur des bruits forts pas à pas.', 'Diffusez un son effrayant à très faible volume et récompensez le calme de votre chien.', 'Désensibilisation sons enregis', 'Apprendre à votre chien à rester calme et détendu en présence de bruits forts ou inhabituels grâce à des sons enregistrés.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien peut écouter des sons enregistrés (type orage, feux d''artifice) à un volume modéré sans montrer de signes de stress, restant détendu et capable de se concentrer sur d''autres choses.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement, tremblements, queue basse, tentative de fuite) ou s''il est clairement désintéressé et fatigué. La séance doit toujours se terminer sur une note positive.', 'L''exercice est validé quand le chien écoute un son enregistré (ex: orage fort ou feux d''artifice) à un volume équivalent à une conversation normale (environ 60 décibels) pendant 5 minutes consécutives, sans montrer de signes de stress (halètement, tremblements, fuite, aboiements excessifs) et accepte des friandises ou des interactions calmes de la part du maître, 3 fois sur 3 tentatives consécutives.', 'Soyez extrêmement attentif au moindre signe de stress de votre chien. Le but est de créer une association positive, pas d''augmenter sa peur.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-sons-enregistres.png'),
('desens-tondeuse', 'Cet exercice aide votre chien à mieux supporter le bruit de la tondeuse. En l''habituant progressivement et en douceur, il apprendra à rester calme au lieu d''avoir peur ou de réagir. C''est utile pour les tontes chez le toiletteur ou à la maison.', 'Habituez votre chien au bruit de la tondeuse en douceur et progressivement.', 'Approchez la tondeuse éteinte, puis allumée de plus en plus près de votre chien, en le récompensant à chaque étape.', 'Désensibilisation tondeuse', 'Aider votre chien à se sentir à l''aise et détendu en présence d''une tondeuse, même quand elle fait du bruit.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme, détendu et peut prendre des friandises lorsque la tondeuse est allumée et qu''elle le touche.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement, bâillements répétés, oreilles en arrière, queue entre les pattes, tentative de fuite) ou de fatigue.', 'L''exercice est validé quand le chien reste détendu (sans halètement excessif, sans tremblements, sans tentative de fuite) pendant 30 secondes consécutives avec la tondeuse allumée et vibrante en contact léger sur au moins 3 zones différentes de son corps (par exemple, le dos, une patte, le cou) lors de 3 sessions sur 5 tentatives consécutives, sans nécessiter de friandise continue.', 'Soyez attentif à tout signe de stress, même subtil, de votre chien et adaptez la distance ou l''intensité du bruit en conséquence.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-tondeuse.png'),
('desens-clippers', 'Cet exercice aide votre chien à se sentir plus à l''aise avec le bruit et les vibrations d''une tondeuse. C''est important pour les séances de toilettage afin qu''elles se passent sans stress, pour le chien comme pour vous. On va y aller progressivement pour qu''il s''habitue en douceur.', 'Habituez votre chien à la tondeuse en douceur !', 'Présentez la tondeuse éteinte, puis allumée de loin, en récompensant le calme.', 'Désensibilisation tondeuse toi', 'Aider votre chien à tolérer le bruit et les vibrations de la tondeuse, rendant les séances de toilettage plus sereines pour tout le monde.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calme, détendu et accepte la présence de la tondeuse allumée près de lui, et le contact bref avec la tondeuse allumée sans montrer de peur ou de stress.', 'Arrêtez immédiatement si votre chien montre des signes de stress (halètement, bâillements, léchage de babines, queue basse, tentative de fuite) ou de fatigue, ou s''il perd tout intérêt pour les friandises ou le jeu.', 'L''exercice est validé quand le chien reste calme (pas de halètement excessif, pas de tentative de fuite, pas de léchage de babines, accepte les friandises) pendant que la tondeuse allumée touche légèrement différentes zones de son corps (pattes, dos, cou) pendant 5 secondes consécutives, 5 fois de suite, sur au moins 3 séances distinctes.', 'Soyez attentif à la température de la lame de la tondeuse si vous commencez à tondre, pour ne pas brûler votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/desens-clippers.png'),
('detachement-piece', 'Cet exercice aide votre chien à se sentir bien, même quand vous n''êtes pas juste à côté de lui. En pratiquant régulièrement, il apprendra à être calme et confiant quand il est seul à la maison, évitant ainsi le stress de la séparation.', 'Apprenez à votre chien à être calme et indépendant chez vous.', 'Demandez à votre chien de rester dans une pièce pendant que vous allez dans une autre, puis revenez rapidement.', 'Détachement dans la maison', 'Apprendre à votre chien à rester serein et détendu dans une pièce séparée, en toute autonomie et confiance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien reste calmement dans la pièce, sans pleurer ni chercher à vous suivre, même quand vous n''êtes pas visible. Il peut être occupé avec son jouet ou simplement se reposer.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halète beaucoup, tremble, jappe sans arrêt), s''il ne veut plus de son jouet, ou s''il est trop agité pour se concentrer. Revenez à l''étape précédente ou faites une pause.', 'L''exercice est validé quand le chien reste calmement (sans grogner, japper, pleurer ou tenter de vous suivre) dans une pièce séparée pendant 5 minutes, 3 fois sur 5 tentatives consécutives, sans aide ni friandise présente pendant l''absence.', 'Soyez attentif aux moindres signes de stress ou d''inconfort. Le but est de créer une expérience positive, pas de le forcer.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detachement-piece.png'),
('detection-distractions', 'Cet exercice apprend à votre chien à trouver une odeur spécifique, même s''il y a d''autres odeurs ou des choses qui le distraient. C''est utile pour renforcer son focus et son obéissance dans des situations variées, comme une promenade au parc où il y a beaucoup de stimuli.', 'Votre chien apprend à ignorer les distractions pour trouver une odeur !', 'Placez l''objet avec l''odeur cible et aidez votre chien à l''identifier malgré les distractions ajoutées progressivement.', 'Détection avec distractions', 'Apprendre à votre chien à se concentrer sur une odeur cible et à l''identifier, malgré les distractions environnantes.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien trouve l''objet avec l''odeur cible parmi des leurres et des distractions, en répondant à votre commande ''Cherche''. Il marque l''objet (en le touchant du nez, en s''asseyant devant, etc.) sans être perturbé.', 'Arrêtez l''exercice si votre chien montre des signes de fatigue (bâillements, se gratte souvent, se détourne), de stress (lèvres tirées, oreilles en arrière) ou s''il perd tout intérêt (il ne renifle plus, ne cherche plus).', 'L''exercice est validé quand le chien identifie l''odeur cible dans une zone de 3x3 mètres avec 3 distractions faibles (ex: jouets neutres, feuilles mortes) en moins de 30 secondes, et ce, 4 fois sur 5 tentatives consécutives, sans interagir avec les distractions.', 'Surveillez toujours les signes de frustration ou de confusion chez votre chien. Si la difficulté est trop grande, diminuez-la immédiatement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-distractions.png'),
('detection-bagage', 'La détection de bagages est un excellent exercice pour stimuler mentalement et physiquement votre chien. Il s''agit d''apprendre à votre chien à identifier et signaler la présence d''objets spécifiques (vos bagages) dans un environnement donné. Cet exercice renforce le lien entre vous et votre chien tout en développant son instinct de recherche.', 'Transformez votre chien en détective privé de bagages !', 'Cachez une friandise ou un jouet dans un bagage et laissez votre chien le trouver parmi d''autres.', 'Détection bagages', 'Apprendre à votre chien à utiliser son flair pour trouver un objet spécifique dans une série de bagages et vous le signaler, comme un chien renifleur professionnel !', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement le bagage sur commande vocale et le signale de manière fiable et répétée dans différents environnements sans hésitation.', 'Le chien montre des signes de stress, de fatigue excessive, de frustration, ou s''il refuse catégoriquement de participer à l''exercice malgré des tentatives de simplification et de motivation.', 'Le chien doit montrer un intérêt clair et durable pour le bagage désigné et le signaler de manière intentionnelle (assis, couché, grattage léger) de façon répétée avant de changer d''objet.', 'Surveillez toujours les signes de stress ou de frustration de votre chien. Si l''exercice devient un jeu amusant, il ne doit jamais être une source d''anxiété.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-bagage.png'),
('detection-conditions-meteo', 'Cet exercice ludique permet à votre chien de reconnaître et d''identifier différentes conditions météorologiques. Il est idéal pour stimuler son odorat et son intelligence, tout en renforçant votre lien. Une excellente activité pour les jours où les sorties prolongées sont limitées.', 'Restez zen sous toutes les météos avec votre chien !', 'Pratiquez les ordres connus de votre chien dans différentes conditions météo, en commençant par de courtes sessions.', 'Détection conditions météo', 'Apprendre à votre chien à exécuter les commandes de base (assis, couché, reste) même quand il pleut, qu''il y a du vent ou qu''il fait chaud.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie la condition demandée dans 80% des essais sur 5 conditions différentes, sans aide excessive du propriétaire.', 'Le chien montre des signes de stress, de fatigue excessive, ou perd tout intérêt pour l''exercice pendant plus de deux séances consécutives.', 'L''exercice est validé lorsque le chien, sur commande vocale, identifie correctement une condition météorologique spécifique parmi plusieurs autres, que ce soit à travers un objet associé ou dans son environnement réel.', 'Attention aux orages et aux fortes pluies, qui peuvent effrayer certains chiens et rendre l''exercice contre-productif.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-conditions-meteo.png'),
('detection-explosifs-intro', 'Apprenez à votre chien à identifier l''odeur spécifique d''explosifs de manière ludique et sécuritaire. Cette introduction prépare votre chien à des recherches plus complexes et renforce son instinct naturel de pistage. L''objectif est de créer une association positive entre l''odeur cible et une récompense motivante.', 'Apprenez à votre chien à devenir un as de la détection avec son super flair !', 'Présentez l''odeur cible à votre chien et récompensez-le généreusement dès qu''il y porte attention.', 'Détection d''explosifs (intro)', 'Apprendre à votre chien à associer positivement une odeur spécifique et à l''indiquer, développant ainsi ses capacités olfactives et sa concentration.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement l''odeur et la découvre de manière fiable, en montrant un intérêt clair pour le contenant odorant dans des situations simples. Il associe l''odeur à une récompense positive.', 'Le chien montre des signes de stress, de fatigue excessive, une perte d''intérêt marquée, ou développe des comportements indésirables (agressivité, destruction non ciblée) pendant l''exercice.', 'Après plusieurs séances réussies, introduisez une nouvelle odeur d''explosif (légalement et en toute sécurité) pour vérifier la spécificité. Observez si le chien montre un intérêt similaire ou s''il ignore les autres odeurs.', 'Soyez vigilant à la motivation de votre chien. S''il ne semble pas intéressé, faites une pause et réessayez plus tard en rendant l''exercice plus facile ou avec des récompenses plus attractives.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-explosifs-intro.png'),
('detection-intrusion', 'La détection d''intrusion est un jeu d''odorat où le chien doit localiser un objet spécifique dissimulé dans un environnement. Cet exercice développe le flair naturel du chien et son indépendance dans la recherche. Il renforce également votre complicité en travaillant sur la communication et la confiance mutuelle.', 'Transformez votre chien en un gardien attentif qui vous alerte avec confiance !', 'Apprenez à votre chien à aboyer sur commande en présence d''un inconnu simulé, puis à se calmer sur votre signal.', 'Détection d''intrusion', 'Apprendre à votre chien à signaler vocalement la présence d''un inconnu près de chez vous, pour vous alerter.', 'La constance est la clé du succès', 'variable', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement, ignore les leurres, et se dirige vers l''objet pour le trouver avec une indication claire (par exemple, le rapporter ou s''asseoir à côté s''il s''agit d''une friandise).', 'Le chien ne montre aucun intérêt pour la recherche après plusieurs tentatives, est visiblement stressé ou frustré, ou si vous avez atteint la durée de séance recommandée sans progrès significatifs.', 'Observer si le chien localise l''objet caché dans l''environnement désigné en utilisant son flair, et s''il le signale ou le rapporte comme demandé.', 'Soyez vigilant à ne pas créer un chien trop réactif ou anxieux envers les inconnus. L''objectif est un signal d''alerte contrôlé, pas une agression ou une panique.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-intrusion.png'),
('detection-piece', 'Cet exercice consiste à entraîner votre chien à retrouver un objet spécifique caché dans une pièce, en utilisant son flair. Il permet de stimuler mentalement le chien et de renforcer votre lien. C''est une excellente activité pour les journées pluvieuses ou lorsque vous avez peu d''espace extérieur.', 'Votre chien devient un détective renifleur !', 'Cachez l''odeur et laissez votre chien la trouver en explorant la pièce.', 'Détection dans une pièce', 'Apprendre à votre chien à scanner méthodiquement une pièce pour trouver une odeur spécifique. Le but est qu''il utilise son flair de manière autonome.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien identifie l''objet caché et le signale par une attitude claire (assis, couché, ou focus intense) dans un délai raisonnable (adapté à sa progression) et sans aide externe.', 'Le chien montre des signes de frustration, de stress, de fatigue excessive, ou une désaffection totale pour l''exercice. Si le chien n''a pas progressé après plusieurs séances d''une même difficulté.', 'Observer si le chien recherche activement l''odeur cible dans la pièce et manifeste un intérêt (agitation, reniflements intenses, comportement de ''stop'' ou de marquage) près de l''emplacement de l''objet.', 'Faites attention aux signes de surchauffe si la pièce est chaude ou si votre chien s''active beaucoup pendant l''exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-piece.png'),
('detection-stupefiants', 'Cet exercice apprend à votre chien à chercher une odeur spécifique. C''est utile pour stimuler son intelligence et renforcer votre lien. Il apprendra à se concentrer et à utiliser son flair de manière ciblée.', 'Apprenez à votre chien à devenir un détective des odeurs !', 'Cachez l''odeur cible et apprenez à votre chien à la trouver et à vous la signaler.', 'Détection de stupéfiants', 'Apprendre à votre chien à identifier et signaler une odeur ciblée, comme s''il travaillait pour la police ou les douanes.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien cherche activement l''odeur, la trouve sans aide et la signale clairement (par exemple, il s''assoit ou fixe l''endroit) même si l''odeur est bien cachée et qu''il y a des distractions.', 'Arrêtez l''exercice si votre chien bâille, se lèche les babines, détourne le regard, se gratte souvent, ou s''éloigne de la zone de recherche. Ces signes indiquent qu''il est stressé ou fatigué et qu''il a besoin d''une pause.', 'L''exercice est validé quand le chien identifie et signale correctement l''objet porteur de l''odeur cible dans 3 environnements différents, avec au moins 3 sources de distraction mineures, à 3 reprises sur 5 tentatives consécutives, sans aide verbale ou gestuelle du maître pendant la phase de recherche.', 'Faites attention à ce que votre chien ne mange pas les objets qui contiennent l''odeur. S''il a tendance à mordiller, utilisez un support qu''il ne peut pas abîmer.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-stupefiants.png'),
('detection-boites', 'Votre chien va apprendre à trouver une odeur spécifique cachée dans une série de boîtes. C''est un peu comme un jeu de détective pour votre chien ! Cet exercice stimule son intelligence et son sens de l''odorat, renforçant ainsi votre lien et sa confiance en lui.', 'Transformez votre chien en détective d''odeurs avec cet exercice stimulant !', 'Apprenez à votre chien à trouver une odeur spécifique cachée dans une boîte parmi d''autres.', 'Détection en boîtes alignées', 'Apprendre à votre chien à utiliser son flair pour localiser une odeur cible parmi plusieurs distractions, améliorant sa concentration et son acuité olfactive.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien renifle méthodiquement les boîtes et s''arrête clairement devant la boîte contenant l''odeur cible, sans votre aide. Il semble confiant et motivé par la recherche.', 'Si votre chien bâille, se lèche les babines de façon répétée, tourne le dos aux boîtes ou montre des signes de frustration (grognement léger, pattes levées sans raison), c''est qu''il est temps d''arrêter l''exercice. Il est fatigué ou ne comprend plus.', 'L''exercice est validé quand le chien localise et marque l''odeur cible en positionnant son museau sur la boîte appropriée pendant au moins 3 secondes, 4 fois sur 5 tentatives consécutives, avec un minimum de 3 boîtes alignées et une seule cible.', 'Vérifiez que votre chien ne mange pas la boîte en essayant d''atteindre la friandise. Si c''est le cas, utilisez des boîtes plus résistantes ou un support de friandise.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-boites.png'),
('detection-en-hauteur', 'Votre chien sait déjà trouver des odeurs au sol ? Super ! Maintenant, nous allons lui apprendre à les chercher plus en hauteur. C''est utile pour explorer de nouveaux endroits ou pour des jeux plus stimulants. Il apprendra à lever la tête et à utiliser son flair dans toutes les directions.', 'Apprenez à votre chien à chercher des odeurs cachées en hauteur !', 'Cachez une friandise odorante en hauteur et encouragez votre chien à la trouver en utilisant son flair.', 'Détection en hauteur', 'Apprendre à votre chien à trouver une odeur cible, même si elle est placée en hauteur, en utilisant son flair et en explorant différents niveaux.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien trouve la friandise cachée en hauteur de manière autonome et rapide, sans aide de votre part. Il montre de l''enthousiasme à commencer la recherche.', 'Si votre chien bâille de façon répétée, se lèche la truffe excessivement, tourne la tête, gratte le sol sans chercher l''odeur, ou semble ignorer la friandise, cela indique un stress ou une fatigue. Arrêtez la séance et reprenez plus tard.', 'L''exercice est validé quand le chien trouve la cible placée à une hauteur variée (entre 50cm et 150cm du sol) dans 4 endroits différents de la pièce, 3 fois sur 4 tentatives consécutives, en moins de 30 secondes pour chaque recherche, et sans aide du maître (pointage, indications vocales directes).', 'Soyez vigilant sur les signes de frustration (grognements, aboiements excessifs) pour adapter la difficulté et prévenir le découragement. Si votre chien commence à détruire les supports, c''est un signe qu''il est frustré ou que l''exercice est trop difficile.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-en-hauteur.png'),
('detection-enterree', 'La détection enterrée est un exercice super stimulant pour le flair de votre chien ! Il va apprendre à localiser une odeur spécifique qui est cachée sous terre. Cela renforce sa concentration et son incroyable capacité olfactive. C''est un peu comme une chasse au trésor pour votre chien, guidée par son nez !', 'Un exercice de flair avancé pour que votre chien devienne un vrai détective du nez !', 'Cachez une odeur sous une petite couche de terre et laissez votre chien la trouver en utilisant son nez.', 'Détection enterrée', 'Apprendre à votre chien à utiliser son flair pour trouver une petite source d''odeur cachée sous terre, même quand elle n''est pas visible.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi quand votre chien, après la consigne "Cherche !", se met à fouiller le sol avec son nez et creuse légèrement à l''endroit précis où l''odeur est cachée, sans votre aide.', 'Arrêtez l''exercice si votre chien semble frustré, gratte à d''autres endroits sans conviction, bâille beaucoup (signe de stress), ou ignore l''odeur. Mettez fin à la séance avant qu''il ne soit fatigué ou découragé.', 'L''exercice est validé quand le chien localise et marque clairement la cible d''odeur enfouie (par un reniflement prolongé de 3 secondes, un grattage ou un léchage de la zone) dans un rayon de 10 cm autour de la cible, 4 fois sur 5 tentatives consécutives, avec un temps de recherche de moins de 30 secondes par cible sur une surface de 2m x 2m.', 'Faites attention aux signes d''épuisement de votre chien, surtout s''il creuse. Les exercices de flair sont très intenses pour leur cerveau et leur corps.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-enterree.png'),
('detection-medicale', 'La détection médicale est un exercice incroyable où votre chien apprend à reconnaître et vous signaler des changements subtils dans votre corps, comme un malaise qui approche. C''est un entraînement avancé qui demande de la patience, mais qui peut avoir un impact énorme sur votre sécurité et votre bien-être. Votre chien devient un vrai ange gardien !', 'Apprenez à votre chien à vous protéger en détectant des changements médicaux.', 'Votre chien va apprendre à reconnaître des odeurs spécifiques liées aux changements de votre corps et vous alerter.', 'Détection médicale', 'Apprendre à votre chien à détecter et vous alerter en cas de changements physiologiques, par exemple pour le diabète ou l''épilepsie. Il peut même anticiper certaines crises !', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien renifle une odeur spécifique ou un changement sur vous, puis vous avertit de manière claire (en vous touchant, en aboyant, en vous fixant). Il le fait de plus en plus souvent de manière autonome.', 'Arrêtez l''exercice si votre chien bâille, se lèche excessivement les babines, détourne le regard ou montre des signes de fatigue. C''est le signal qu''il faut faire une pause.', 'L''exercice est validé quand le chien identifie et signale la source d''odeur spécifique (ou le changement physiologique) avec un comportement clair (ex: coup de museau, patte, aboiement ciblé) en moins de 30 secondes, sur 8 tentatives sur 10 consécutives, et ce, dans 3 lieux différents et avec 2 distractions légères présentes.', 'Soyez attentif à votre propre état de santé. Si votre chien vous alerte souvent, consultez votre médecin pour vérifier si tout va bien.  Votre chien est peut-être plus perspicace que vous ne le pensez !', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-medicale.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;UPDATE exercises e SET
  description = COALESCE(NULLIF(v.v_description,''), NULLIF(e.description,'')),
  summary = COALESCE(NULLIF(v.v_summary,''), NULLIF(e.summary,'')),
  short_instruction = COALESCE(NULLIF(v.v_short_instruction,''), NULLIF(e.short_instruction,'')),
  short_title = COALESCE(NULLIF(v.v_short_title,''), NULLIF(e.short_title,'')),
  objective = COALESCE(NULLIF(v.v_objective,''), NULLIF(e.objective,'')),
  dedication = COALESCE(NULLIF(v.v_dedication,''), NULLIF(e.dedication,'')),
  duration = COALESCE(NULLIF(v.v_duration,''), NULLIF(e.duration,'')),
  repetitions = COALESCE(NULLIF(v.v_repetitions,''), NULLIF(e.repetitions,'')),
  frequency = COALESCE(NULLIF(v.v_frequency,''), NULLIF(e.frequency,'')),
  environment = COALESCE(NULLIF(v.v_environment,''), NULLIF(e.environment,'')),
  success_criteria = COALESCE(NULLIF(v.v_success_criteria,''), NULLIF(e.success_criteria,'')),
  stop_criteria = COALESCE(NULLIF(v.v_stop_criteria,''), NULLIF(e.stop_criteria,'')),
  validation_protocol = COALESCE(NULLIF(v.v_validation_protocol,''), NULLIF(e.validation_protocol,'')),
  vigilance = COALESCE(NULLIF(v.v_vigilance,''), NULLIF(e.vigilance,'')),
  progression_next = COALESCE(NULLIF(v.v_progression_next,''), NULLIF(e.progression_next,'')),
  regression_simplified = COALESCE(NULLIF(v.v_regression_simplified,''), NULLIF(e.regression_simplified,'')),
  age_recommendation = COALESCE(NULLIF(v.v_age_recommendation,''), NULLIF(e.age_recommendation,'')),
  cover_image = COALESCE(NULLIF(v.v_cover_image,''), NULLIF(e.cover_image,''))
FROM (VALUES
('detection-personne', 'Cet exercice enseigne à votre chien à identifier une personne spécifique parmi d''autres en se basant sur une odeur. C''est une excellente activité pour développer le flair de votre chien et renforcer votre lien. Il est idéal pour les chiens de tous âges et races, transformant leur instinct naturel en un jeu stimulant.', 'Apprenez à votre chien à détecter une odeur précise sur une personne !', 'Demandez à votre chien de chercher l''odeur sur la personne, puis récompensez-le quand il la trouve.', 'Détection sur personne', 'Apprendre à votre chien à chercher et trouver une odeur cible sur une personne, en la "scannant" du nez.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien doit pouvoir retrouver la personne cible dans 4 sur 5 essais dans un environnement contrôlé et avec diverses distractions légères.', 'Arrêter l''exercice si le chien montre des signes de stress, de frustration excessive, ou s''il refuse catégoriquement de participer malgré des tentatives de simplification.', 'Observer si le chien identifie correctement la personne cible à chaque essai, en ignorant les distracteurs ou les autres odeurs présentes. La récompense intervient uniquement lorsque la personne cible est identifiée.', 'Faites attention à ce que votre chien ne soit pas trop brusque ou excité pendant la recherche, pour ne pas gêner la personne.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-personne.png'),
('detection-vehicule', 'Cet exercice entraîne votre chien à rechercher et indiquer la présence d''une odeur spécifique sur ou autour d''un véhicule. C''est une excellente activité pour stimuler mentalement et physiquement votre chien, renforçant ainsi votre lien. Il simule des situations de travail réel pour les chiens de détection tout en étant un jeu amusant pour les chiens de compagnie.', 'Un super jeu de détective pour le flair de votre chien !', 'Demandez à votre chien de chercher l''odeur cible sur un véhicule et de la signaler.', 'Détection sur véhicule', 'Apprendre à votre chien à identifier et signaler une odeur ciblée sur un véhicule.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien trouve et signale de manière fiable la cache d''odeur sur le véhicule dans divers contextes, avec un minimum de sollicitations duhandler, même en présence de distractions modérées.', 'Le chien montre des signes de stress, de peur, de fatigue excessive, ou une aversion marquée pour l''exercice. Si le chien semble souffrir physiquement ou mentalement.', 'Lors de recherches, le chien doit montrer un intérêt clair et une recherche active autour du véhicule désigné. Une fois l''odeur détectée, le chien doit exécuter son signal (ex: assis, couché) de manière cohérente et intentionnelle en présence de l''odeur.', 'Surveillez toujours les signes de stress ou de frustration. Adaptez la difficulté pour que l''exercice reste un jeu amusant.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/detection-vehicule.png'),
('dire-non', 'L''exercice ''Dire non'' apprend au chien à réprimer une impulsion désirée, développant ainsi son autocontrôle et sa patience. Cela renforce la communication entre le propriétaire et le chien, améliorant la compréhension mutuelle et la gestion des situations où le chien doit se retenir. Cet exercice est fondamental pour établir des limites claires et favoriser un comportement plus calme et obéissant.', 'Apprenez à votre chien un signe de tête amusant et utile !', 'Placez un stick de friandise près de la truffe du chien et guidez-le pour qu''il bouge la tête de gauche à droite.', 'Dire non', 'Apprendre à votre chien à faire un mouvement de ''non'' avec sa tête sur commande, comme un signe de refus ou de désaccord.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien doit être capable de résister à la tentation d''une friandise visible et accessible après avoir entendu le signal ''Non'', et attendre qu''on lui donne la permission (''Oui'') ou une autre récompense.', 'Arrêter immédiatement si le chien montre des signes de stress excessif, de peur ou d''agressivité. Si le chien est constamment frustré ou incapable de comprendre, cela peut indiquer que l''exercice est trop avancé pour lui, et il faut alors revenir à des étapes plus simples ou cesser pour la journée.', 'Les sessions d''entraînement doivent être courtes (5-10 minutes) et répétées plusieurs fois par jour. L''objectif est d''établir une association claire entre le refus de l''action désirée et la récompense immédiate qui suit le bon comportement.', 'Veillez à ce que le mouvement de tête soit toujours doux et que votre chien ne ressente aucune contrainte ou gêne.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/dire-non.png'),
('dire-oui', 'L''exercice "Dire Oui" apprend au chien à associer un signal verbal spécifique à une action agréable ou une récompense. Cela renforce la communication et la confiance entre le chien et son propriétaire. C''est une excellente base pour de nombreux apprentissages ultérieurs.', 'Apprenez à votre chien à dire ''oui'' avec sa tête !', 'Guidez la tête de votre chien de haut en bas en utilisant une friandise.', 'Dire oui', 'Apprenez à votre chien à faire un signe de tête de haut en bas sur commande vocale ou gestuelle.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien répond de manière fiable au signal verbal ''Oui'' en produisant le comportement associé dans 80% des essais, sans avoir besoin d''indices visuels constants de la friandise, et ce, dans différents contextes.', 'Le chien montre des signes de stress, de fatigue, d''incompréhension persistante malgré les ajustements, ou une perte d''intérêt marquée pour la session d''entraînement. Arrêtez également si la relation propriétaire-chien est tendue ou si l''exercice devient frustrant pour l''un ou l''autre.', 'Au cours de 5 séances d''entraînement distinctes, observez si le chien répond au signal verbal "Oui" en initiant le comportement appris (par exemple, s''asseoir) dans les 3 secondes suivant le signal, avec une demande ou une offre spontanée.', 'Observez toujours le langage corporel de votre chien. Il doit rester détendu et intéressé. Toute tension, raideur ou signe de douleur doit vous alerter.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/dire-oui.png'),
('direction-gauche-droite', 'Cet exercice enseigne au chien à tourner à gauche ou à droite sur commande vocale, ce qui est essentiel pour la navigation sur un parcours d''agility. Une bonne compréhension de ces commandes permet au chien de réagir rapidement aux changements de direction et de maintenir sa vitesse. La clarté des signaux et la pratique régulière sont la clé du succès.', 'Guidez votre chien à distance, à gauche ou à droite, pour une meilleure communication.', 'Dites "Gauche" ou "Droite" et pointez la direction pendant que votre chien avance.', 'Direction gauche/droite en agi', 'Apprendre à votre chien à changer de direction (gauche ou droite) sur votre commande vocale et gestuelle, même si vous êtes éloigné de lui.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien tourne de manière fluide et rapide dans la bonne direction sur commande vocale dans au moins 8 sur 10 tentatives, sans hesitation significative.', 'Le chien montre des signes de stress importants, de fatigue, ou d''agression, ou si la confusion persiste malgré les ajustements de l''exercice.', 'Observer la capacité du chien à tourner indépendamment de 90 degrés ou plus à gauche et à droite sur commande vocale, avec ou sans une légère aide corporelle initiale.', 'Faites attention aux surfaces sur lesquelles votre chien évolue. Pour les changements de direction, assurez-vous que le sol n''est pas glissant afin d''éviter les blessures.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/direction-gauche-droite.png'),
('discrimination-menace', 'Cet exercice aide votre chien à faire la différence entre une vraie menace et une personne qui ne représente aucun danger. C''est essentiel pour l''aider à mieux gérer ses émotions et à rester calme dans différentes situations, comme des rencontres inattendues qui pourraient le surprendre ou le stresser. Il apprendra à observer et à évaluer par lui-même. C''est un exercice avancé qui demande de la préparation.', 'Apprenez à votre chien à faire la différence entre un ami et un "faux ennemi" de manière calme.', 'Avec l''aide d''un ami, apprenez à votre chien à ignorer les inconnus neutres et à saluer les personnes amies.', 'Discrimination ami/ennemi', 'Apprendre à votre chien à distinguer une personne amie d''une personne inconnue, pour qu''il ne réagisse pas inutilement et garde son calme.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien reste calme et indifférent en présence d''une personne inconnue qui ne représente pas de menace, et qu''il accepte même les salutations entre cette personne et vous.', 'Arrêtez l''exercice si votre chien montre des signes de stress (halètement, bâillements excessifs, queue basse et agitée, poils hérissés) ou s''il perd tout intérêt. Une séance ne doit pas dépasser 10-15 minutes pour qu''il reste concentré.', 'L''exercice est validé lorsque le chien parvient à rester calme (pas d''aboiements, de grognements, de tirage en laisse excessif) pendant 30 secondes en présence d''une personne inconnue statique à 5 mètres, puis lors de l''approche et du départ de cette personne (mouvement lent), et ce, lors de 4 tentatives consécutives avec deux personnes inconnues différentes.', 'Soyez extrêmement attentif aux signaux de votre chien. Sa sécurité et son bien-être sont primordiaux. Ne le mettez jamais en danger ni lui, ni votre ami.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/discrimination-menace.png'),
('discrimination-odeurs-pistage', 'Cet exercice est un jeu amusant qui apprend à votre chien à trouver une odeur spécifique parmi d''autres. C''est comme un détective canin ! Cela le stimule mentalement et renforce son flair incroyable, essentiel pour son bien-être.', 'Transformez votre chien en détective des odeurs pour le stimuler mentalement.', 'Apprenez à votre chien à trouver et à indiquer une odeur spécifique cachée parmi d''autres.', 'Discrimination d''odeurs', 'Apprendre à votre chien à identifier et à désigner une odeur précise que vous lui avez apprise, même quand d''autres odeurs sont là pour le distraire.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'L''exercice est réussi lorsque votre chien est capable de trouver l''odeur cible parmi au moins 4 ou 5 autres odeurs différentes dans un environnement varié (mais sans trop de distractions) et qu''il vous l''indique clairement (en la touchant du nez, en grattant doucement, ou en s''arrêtant devant).', 'Arrêtez l''exercice si votre chien bâille de manière répétée, détourne le regard, se lèche les babines sans raison apparente, ignore l''odeur ou commence à renifler d''autres choses. Ce sont des signes qu''il est fatigué ou stressé.', 'L''exercice est validé quand le chien identifie et désigne l''odeur cible (par un museau, une patte, un arrêt) parmi 3 contenants différents, dont 2 distracteurs, 8 fois sur 10 tentatives consécutives, sans aide ni indice du maître.', 'Surveillez toujours la queue de votre chien : si elle est basse et qu''il refuse de participer, c''est qu''il n''est pas à l''aise ou qu''il ne comprend pas l''exercice. Prenez note de ses réactions pour adapter le jeu.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/discrimination-odeurs-pistage.png'),
('discrimination-odeurs', 'La discrimination d''odeurs est un exercice stimulant où votre chien apprend à identifier une odeur spécifique parmi d''autres. C''est comme un jeu de détective pour lui ! Cet exercice développe son intelligence et renforce votre complicité, tout en lui offrant une activité mentale enrichissante.', 'Votre chien devient un expert en détection d''odeurs !', 'Cachez une odeur clé et laissez votre chien la trouver parmi d''autres.', 'Discrimination d''odeurs', 'Apprendre à votre chien à trouver et à désigner une odeur cible parmi plusieurs, en utilisant son flair incroyable.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien trouve et signale avec confiance l''odeur cible parmi les autres, même avec des distracteurs odorants ou une difficulté accrue.', 'Arrêtez l''exercice si votre chien baille, se lèche excessivement les babines, détourne le regard, ou ne montre plus d''intérêt. Il est fatigué ou stressé.', 'L''exercice est validé quand le chien identifie et désigne l''odeur cible (par un marquage clair comme le museau sur la cible, assis devant, ou couché) parmi 5 coupes neutres, sur 8 tentatives consécutives, sans aucune aide du maître, dans un environnement peu distrayant.', 'Soyez très attentif au langage corporel de votre chien pour garantir que l''exercice reste positif et amusant.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/discrimination-odeurs.png'),
('discrimination-cible', 'Cet exercice apprend à votre chien à reconnaître et désigner une personne spécifique, même au milieu d''un groupe. C''est très utile par exemple si votre chien doit retrouver un membre de votre famille dans un parc bondé ou pour des jeux de cache-cache améliorés !', 'Votre chien devient un expert pour retrouver la bonne personne !', 'Apprenez à votre chien à retrouver la bonne personne dans n''importe quel groupe.', 'Discrimination de cible', 'Apprendre à votre chien à identifier et à aller vers une personne spécifique que vous lui désignez par son nom ou un signe, quand elle est parmi d''autres personnes.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien doit pouvoir identifier la bonne personne parmi 3 ou 4 sans hésitation, même si les personnes changent de place ou de tenue. Il y va rapidement et avec enthousiasme.', 'Arrêtez l''exercice si votre chien bâille de façon répétée, se lèche les babines, détourne le regard, se gratte souvent ou refuse de participer. Ce sont des signes de fatigue ou de stress. Mieux vaut faire des sessions courtes et positives.', 'L''exercice est validé quand le chien identifie et touche physiquement la personne cible (parmi 3 à 5 personnes immobiles) 8 fois sur 10 tentatives consécutives, à une distance de 5 mètres, sur 3 sessions différentes.', 'Soyez attentif à la réaction de votre chien vis-à-vis des personnes. S''il hésite ou semble mal à l''aise, revenez à une étape plus simple ou réduisez le nombre de participants.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/discrimination-cible.png'),
('discrimination-formes', 'La discrimination de formes est un exercice mental stimulant pour votre chien. Il va apprendre à différencier des objets de formes différentes et à vous les rapporter sur commande. C''est un excellent moyen de développer ses capacités cognitives et de renforcer votre lien sans qu''il ait à beaucoup bouger. Utile pour les chiens qui ont besoin de dépenser de l''énergie mentale et pour impressionner vos amis !', 'Un jeu amusant pour rendre votre chien plus intelligent et renforcer votre complicité !', 'Apprenez à votre chien à choisir la bonne forme parmi plusieurs.', 'Discrimination de formes', 'Apprendre à votre chien à identifier et à rapporter un objet spécifique parmi d''autres, basé sur sa forme.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien apporte la bonne forme que vous avez nommée, même si d''autres formes sont présentes, et cela de manière constante.', 'Arrêtez l''exercice si votre chien bâille de manière répétée, se lèche la truffe, tourne la tête, ou s''éloigne. Ce sont des signes qu''il est fatigué ou stressé et qu''il a besoin d''une pause.', 'L''exercice est validé quand le chien identifie et rapporte l''objet spécifié parmi 5 objets de formes différentes, 4 fois sur 5 tentatives consécutives, sans aucune aide visuelle du maître.', 'Ne laissez jamais votre chien sans surveillance avec les formes, surtout s''il a tendance à mordiller les objets.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/discrimination-formes.png'),
('distributeur-repas', 'Le distributeur de repas interactif est un jouet conçu pour stimuler mentalement votre chien tout en lui faisant manger sa nourriture. Il encourage la patience et la réflexion, transformant le simple acte de manger en une activité enrichissante et ludique. Cet exercice est idéal pour les chiens d''intelligence vive ou ceux qui ont tendance à manger trop rapidement.', 'Transformez les repas en jeu pour un chien plus épanoui !', 'Placez la nourriture de votre chien dans une gamelle interactive plutôt que dans sa gamelle habituelle.', 'Distributeur de repas interact', 'Apprendre à votre chien à utiliser une gamelle interactive pour manger plus lentement et se stimuler mentalement.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien interagit de manière autonome avec le distributeur, cherche activement à en faire sortir la nourriture et y parvient avec peu ou pas de frustration. La nourriture est consommée entièrement par l''intermédiaire du jouet.', 'Le chien montre des signes de frustration extrême, d''agressivité envers le jouet ou son propriétaire, ou s''il refuse catégoriquement d''interagir après plusieurs tentatives. Arrêter également si le chien ne mange pas sa ration complète dans un temps raisonnable (ex: 30 minutes), indiquant un désintérêt ou une difficulté excessive.', 'Observer si le chien manifeste de l''intérêt pour le jouet, s''il tente activement de le manipuler pour faire sortir la nourriture, et s''il y parvient avec succès, même avec une aide initiale.', 'Vérifiez régulièrement l''état de la gamelle interactive. Elle ne doit pas avoir de morceaux cassés ou de bords tranchants qui pourraient blesser votre chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/distributeur-repas.png'),
('dog-dancing', 'Le Dog Dancing, aussi appelé Obé-Rythmée, est une discipline canine qui allie l''obéissance à des mouvements chorégraphiés et rythmés sur une musique. Il s''agit de créer une routine où le chien et son maître exécutent ensemble une série d''exercices ludiques et esthétiques. C''est une excellente façon de renforcer votre lien, d''améliorer la communication et de stimuler mentalement et physiquement votre chien.', 'Créez une chorégraphie unique avec votre chien en dansant ensemble !', 'Enchaînez plusieurs figures connues au rythme de la musique en guidant votre chien avec fluidité.', 'Dog dancing (obé-rythmée)', 'Apprendre une chorégraphie de dog dancing avec votre chien en utilisant des mouvements avancés pour les exécuter en rythme avec la musique.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute la chorégraphie demandée à 80% de manière fluide et rythmée, démontrant un engagement positif et une compréhension des ordres et des mouvements.', 'Le chien montre des signes de fatigue excessive, de stress, de peur ou de frustration. L''exercice devient une corvée ou une punition pour le chien.', 'Observer la fluidité de l''exécution, la précision des mouvements, la synchronisation avec la musique et la joie manifeste du chien.', 'Soyez attentif à la condition physique de votre chien ; n''exécutez pas de mouvements qui pourraient être douloureux pour lui.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/dog-dancing.png'),
('yoga-canin', 'Le Doga, ou yoga canin, est une pratique qui combine le yoga traditionnel avec des exercices doux pour chiens. Il vise à renforcer le lien entre le propriétaire et son animal, tout en améliorant la flexibilité, la mobilité et la relaxation du chien. C''est une activité sécuritaire et bénéfique pour les chiens de tous âges et de différentes conditions physiques.', 'Détendez-vous et connectez-vous avec votre chien grâce au Doga.', 'Guidez délicatement votre chien dans des postures douces en utilisant le toucher et la voix.', 'Doga (yoga canin)', 'Apprendre à faire des postures de yoga simples avec votre chien pour renforcer votre lien et favoriser sa détente.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et détendu pendant la séance, participe volontairement aux exercices, et montre des signes de relaxation à la fin. Une amélioration notable de la flexibilité et de la mobilité après plusieurs séances est également un indicateur de succès.', 'Le chien montre des signes de stress, de peur ou de douleur. Le chien essaie de s''éloigner ou de fuir. Le chien refuse catégoriquement de coopérer, même après plusieurs tentatives douces. En cas de blessure suspectée ou de problème de santé détecté.', 'Observer attentivement le langage corporel du chien. Vérifier l''absence de signes de stress (bâillements excessifs, léchage des babines, queue basse, détournement du regard). S''assurer que le chien accepte les manipulations douces sans résistance.', 'Faites particulièrement attention à ne pas créer de tension ou de douleur lors des flexions ou étirements.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/yoga-canin.png'),
('donne-objet', 'L''exercice ''Donne'' apprend à votre chien à lâcher volontairement un objet qu''il tient en gueule. Cet exercice est crucial pour la sécurité, notamment pour éviter qu''il n''ingère quelque chose de dangereux. Il renforce également la communication et la confiance entre vous et votre chien.', 'Apprenez à votre chien à donner facilement ses jouets !', 'Tendez la main et dites "Donne" pendant que votre chien tient un objet, puis récompensez-le quand il lâche.', 'Donne', 'Apprendre à votre chien à lâcher un objet sur commande, en douceur et volontairement, pour votre sécurité et la sienne. ', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien lâche systématiquement et volontairement l''objet dès l''ordre verbal ''Donne'', sans stress ni résistance. Le chien retourne au jeu ou à une posture attentive après avoir reçu sa récompense.', 'Le chien montre des signes de peur, d''anxiété ou de stress lors de l''exercice. Le chien refuse catégoriquement de lâcher l''objet malgré des séances répétées et des récompenses de haute valeur. L''exercice devient une source de frustration pour le chien ou le maître.', 'Observer si le chien relâche l''objet immédiatement après l''ordre ''Donne'' et sans hésitation, en échange de la friandise. Vérifier que le chien revient volontiers au jeu après avoir mangé la récompense.', 'Soyez attentif à ne jamais créer de conflit autour de l''objet. L''échange doit toujours être une expérience positive pour le chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/donne-objet.png'),
('donne-patte', 'Le ''Donne la patte'' est un excellent exercice pour renforcer le lien avec votre chien et lui apprendre une nouvelle commande amusante. Cet exercice établit une base solide pour des tours plus complexes par la suite. Il permet également de travailler la proprioception et la confiance de votre chien.', 'Un tour amusant pour renforcer votre lien !', 'Demandez à votre chien de ', 'Donne la patte', 'Votre chien apprend à donner sa patte. Cet exercice renforce votre complicité et stimule votre chien mentalement.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien offre sa patte de manière fiable et rapide sur commande verbale et visuelle, indépendamment des distractions mineures. La durée de contact de la patte avec la main peut être prolongée par étapes.', 'Le chien montre des signes de stress, de fatigue, d''ennui ou d''agitation. Le chien refuse catégoriquement de participer ou devient réactif. Le maître n''est plus patient ou est frustré.', 'Observer si le chien lève spontanément sa patte pour toucher la main tendue du maître après entend le signal verbal et visuel.', 'Restez attentif aux signes de fatigue ou de stress de votre chien. Assurez-vous qu''il apprécie l''exercice et qu''il est motivé.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/donne-patte.png'),
('choix-direction', 'Cet exercice apprend à votre chien qu''il peut choisir le chemin lors d''une promenade. Offrir des choix renforce la confiance de votre chien et améliore votre relation. C''est une base essentielle pour un chien bien dans ses pattes.', 'Offrez le choix à votre chien pour des promenades plus heureuses !', 'À une intersection, arrêtez-vous et laissez votre chien montrer la voie.', 'Donner le choix de direction', 'Apprendre au chien à indiquer la direction qu''il souhaite prendre en promenade, ce qui renforce son autonomie et votre complicité.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien se dirige naturellement et sans hésitation vers un chemin, et vous le suivez dans son choix.', 'Si votre chien montre des signes de stress (halètement excessif, refus de bouger, queue basse, oreilles en arrière) ou de fatigue, arrêtez l''exercice. Une promenade doit rester un plaisir. Reprenez plus tard.', 'L''exercice est validé quand le chien initie activement un mouvement dans une direction à une intersection ou un point de choix, 3 fois sur 5 tentatives consécutives, et que vous le suivez sans aucune tension de la laisse pendant au moins 10 secondes après son choix.', 'Surveillez les signes de stress ou de confusion de votre chien. S''il semble perdu ou angoissé par le choix, simplifiez l''exercice ou faites une pause. Adaptez-vous toujours à son état émotionnel.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/choix-direction.png'),
('donner-medicament', 'Apprenez à votre chien à prendre un médicament sans stress. Cet exercice est essentiel pour sa santé et votre tranquillité d''esprit, en particulier lors de soins vétérinaires. Il renforce également votre lien de confiance.', 'Facilitez la prise de médicaments pour le bien-être de votre chien !', 'Apprenez à votre chien à associer la prise de médicaments à une expérience positive et récompensante.', 'Donner un médicament', 'Apprendre à votre chien à accepter un médicament (comprimé ou sirop) facilement et calmement.', 'La constance est la clé du succès', '3 min', '5 fois', '1x/jour', 'tous', 'Le chien prend le médicament volontairement ou avec une légère aide, sans signe de stress (bâillements, léchage de babines, détournement du regard, tremblements).', 'Le chien présente des signes clairs de stress (halètement excessif, tremblements, tentatives de fuite, grognements, morsures). Le chien refuse de prendre le médicament après plusieurs tentatives douces. Le chien semble épuisé ou frustré.', 'L''exercice est validé quand le chien accepte de prendre le médicament (comprimé ou liquide) et l''ingère calmement, sans résistance visible, dans 4 cas sur 5 tentatives consécutives, en moins de 10 secondes après présentation, et montre un comportement détendu après l''ingestion.', 'Faites attention à tout signe de stress (léchage de babines, bâillements, détournement du regard, queue basse). Observez si le chien a bien avalé le médicament. Restez calme et patient. Si vous êtes stressé, votre chien le ressentira.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/donner-medicament.png'),
('drive', 'Le "drive" est un exercice où votre chien apprend à pousser un objet, comme une balle ou un jouet, devant lui. Cela l''aide à mieux contrôler ses mouvements et à renforcer votre lien. C''est un exercice avancé qui demande de la patience et de la persévérance.', 'Apprenez à votre chien à pousser des objets avec motivation et précision !', 'Apprenez à votre chien à pousser un objet devant lui en suivant vos indications.', 'Drive (pousser)', 'Votre chien apprend à utiliser son corps pour pousser des objets dans la direction que vous lui indiquez. Il développe sa concentration et sa coordination.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Votre chien est capable de pousser l''objet désiré sur une courte distance à l''aide de votre signal verbal "Pousse" et de votre geste. Il semble prendre plaisir à l''exercice.', 'Si votre chien montre des signes de fatigue (halètement excessif, baisse d''attention), de stress (lèchement de babines, bâillements répétitifs, tête basse) ou de désintérêt (il ne réagit plus aux ordres, s''éloigne).', 'L''exercice est validé quand le chien pousse volontairement l''objet sur une distance d''au moins 1 mètre, 5 fois sur 7 tentatives consécutives, sans aide physique du maître, et sans prendre l''objet en gueule plus d''une fois par tentative.', 'Surveillez toujours le niveau d''intérêt et d''énergie de votre chien. Assurez-vous qu''il ne se blesse pas en poussant l''objet, en particulier s''il doit forcer sur ses pattes ou son dos. Stoppez l''exercice immédiatement au moindre signe d''inconfort ou de douleur, ou s''il commence à mâchouiller l''objet au lieu de le pousser.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/drive.png'),
('echauffement-sportif', 'L''échauffement sportif prépare les muscles de votre chien avant l''effort. C''est essentiel pour éviter les blessures et augmenter ses performances. En quelques minutes, votre chien sera prêt pour toute activité physique. C''est une routine simple qui aura un grand impact sur sa santé et son bien-être.', 'Un corps chaud est un corps en sécurité ! Préparez votre chien à l''action.', 'Proposez une série de mouvements doux pour éveiller les muscles de votre chien.', 'Échauffement sportif', 'Préparer le corps de votre chien à l''exercice physique pour prévenir les blessures.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien trotte de manière fluide, ses mouvements sont amples et ses muscles sont souples. Il semble motivé et prêt pour l''activité sans signes de douleur ou de raideur.', 'Si votre chien montre des signes de douleur, de boiterie, de raideur anormale, ou qu''il refuse de bouger, arrêtez l''échauffement. Si vous observez un halètement excessif ou une forte fatigue, arrêtez et laissez-le se reposer. L''échauffement ne doit jamais être une source d''épuisement.', 'L''échauffement est validé quand le chien effectue 3 à 5 répétitions de chaque mouvement (rotations du cou, inclinaisons latérales, révérences, flexions du dos) de manière fluide et sans résistance, sur les deux côtés du corps pour les mouvements latéraux, et ce, sur 3 séances consécutives.', 'Soyez attentif à la posture de votre chien : est-il raide ou souple ? Surveillez sa respiration : est-elle calme et régulière ou halète-t-il excessivement ? Observez son regard et ses oreilles : exprime-t-il du plaisir ou de l''inconfort ? Ces signes sont cruciaux pour adapter l''intensité et la durée de l''échauffement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/echauffement-sportif.png'),
('embarquer-vehicule', 'Apprends à ton chien à monter et descendre calmement et en sécurité de n''importe quel véhicule. Cet exercice renforce sa confiance et prévient les accidents, rendant les trajets plus agréables pour vous deux.', 'Des trajets sereins et sécurisés, ça commence ici !', 'Apprends à ton chien à monter et descendre du véhicule calmement et en sécurité.', 'Embarquer/débarquer d''un véhic', 'Ton chien doit monter et descendre du véhicule de manière autonome et sereine, sans peur ni précipitation, en attendant ton signal.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et descend du véhicule sur commande, calmement, sans hésitation ni précipitation, et reste à l''intérieur jusqu''à une nouvelle commande de descente.', 'Si le chien refuse de monter après plusieurs tentatives, s''il montre des signes de peur ou d''anxiété (queue basse, oreilles en arrière, léchage de babines, halètement excessif), s''il est fatigué ou s''il commence à être distrait. Arrête et reprends plus tard dans la journée ou le lendemain.', 'L''exercice est validé quand le chien monte et descend du véhicule sur commande, sans poser de patte au sol avant le signal de descente, et sans précipitation, 5 fois sur 5 tentatives consécutives, sur au moins 2 types de véhicules différents (ex: voiture et SUV/break).', 'Regarde si les mouvements de ton chien sont fluides et qu''il n''y a pas de boiterie ou de signe de douleur. Sois attentif à son attitude générale : est-il détendu ou stressé ? Le contexte est-il sécuritaire (pas de danger extérieur) ?', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/embarquer-vehicule.png'),
('enchainement-positions', 'L''enchaînement de positions est un exercice essentiel pour enseigner la discipline à votre chien et améliorer sa compréhension des commandes. Il consiste à faire passer le chien d''une position à une autre (assis, couché, debout) sur commande vocale ou gestuelle. La régularité et la patience sont les clés pour que votre chien réussisse cet exercice complexe.', 'Apprenez à votre chien à enchaîner les positions comme un pro !', 'Guidez votre chien pour qu''il alterne les positions assis, couché et debout, en le récompensant à chaque succès.', 'Enchaînement de positions', 'Votre chien apprend à changer de position (assis, couché, debout) rapidement et facilement sur votre signal.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute correctement l''enchaînement de trois positions (ou plus) sur commande vocale avec moins de 10% d''erreurs, et ce, dans au moins trois environnements différents. Les transitions sont fluides et le chien montre de l''enthousiasme pour l''exercice.', 'Le chien montre des signes d''épuisement physique ou mental, d''anxiété, de peur ou de frustration persistante. Si le chien refuse catégoriquement d''exécuter une position malgré des tentatives répétées et adaptées. Si le chien est distrait au point de ne plus répondre aux commandes.', 'Observer la rapidité, la fluidité et la précision des transitions entre les trois positions demandées, ainsi que la compréhension sans hésitation des commandes vocales et gestuelles. Vérifier si le chien reste dans la position demandée jusqu''à la commande suivante.', 'Observez toujours le langage corporel de votre chien. Il doit rester détendu et intéressé. Si la queue est basse, les oreilles en arrière, ou s''il détourne le regard, c''est un signe qu''il n''est pas à l''aise. N''oubliez pas que l''éducation doit être un plaisir pour vous deux.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/enchainement-positions.png'),
('enchainement-rapide', 'L''Enchaînement Rapide est un exercice dynamique qui vise à améliorer la vitesse d''exécution et la fluidité des changements de position de votre chien. Il est idéal pour les chiens sportifs ou pour ceux qui manquent d''entrain lors des exercices de base. Cet exercice demande une bonne coordination entre le maître et le chien, ainsi qu''une compréhension claire des commandes.', 'Transformez les ordres connus en une chorégraphie canine impressionnante !', 'Demandez à votre chien d''exécuter 3 à 5 ordres différents à la suite, comme "Assis", "Donne la patte", "Couché", "Debout", "Viens".', 'Enchaînement rapide', 'Apprendre à votre chien à exécuter une série de 3 à 5 ordres connus, les uns après les autres, sans pause prolongée entre eux. L''objectif est d''obtenir un enchaînement fluide et rapide.', 'La constance est la clé du succès', '8 min', '5 fois', '1x/jour', 'tous', 'Le chien exécute rapidement et sans hésitation les changements de position (assis, debout, couché) en suivant le rythme et la direction indiqués par le maître, même à une vitesse accrue.', 'Le chien montre des signes de fatigue excessive, de stress, ou devient distrait et ne répond plus aux commandes. L''exercice est également arrêté si le maître ou le chien manque de coordination sur une période prolongée.', 'Observer la rapidité et la précision des changements de position du chien suite aux commandes et aux mouvements du maître. Le chien doit passer d''une position à l''autre sans hésitation.', 'Soyez attentif à la rapidité d''exécution de votre chien et à sa joie de participer. S''il est lent ou hésitant, simplifiez la séquence. Si votre chien refuse systématiquement un ordre en particulier, revoyez cet ordre seul.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/enchainement-rapide.png'),
('endurance-patrouille', 'L''endurance de patrouille est un exercice avancé conçu pour améliorer la concentration et la persévérance de votre chien dans des environnements distrayants. Il simule des situations de travail où le chien doit rester alerte et obéissant malgré le chaos potentiel. Cet exercice renforce le lien entre le chien et son maître tout en développant une autonomie contrôlée chez le chien.', 'Marchez longtemps avec votre chien, il apprendra l''endurance et restera calme à vos côtés !', 'Marchez à un rythme régulier pendant 60 minutes avec votre chien à vos côtés, en maintenant son attention.', 'Endurance de patrouille', 'Apprendre à votre chien à maintenir un effort régulier et une bonne concentration pendant une longue marche à vos côtés.', 'La constance est la clé du succès', '60 min', '5 fois', '1x/jour', 'tous', 'Le chien peut maintenir une position pendant au moins 5 minutes dans un environnement modérément distrayant, en ignorant les stimuli sans anxiété ni agitation, et répond au rappel.', 'Le chien montre des signes de stress excessif, de fatigue, ou d''agressivité. L''exercice doit être arrêté si le chien ne parvient pas à se calmer malgré les ajustements.', 'Chaque étape doit être maîtrisée avec succès avant de passer à la suivante. Le chien doit montrer une diminution des réactions aux distractions et une augmentation du temps de maintien.', 'Surveillez les signes de chaleur (halètements forts et rapides, langue très rouge), les signes de douleur (boiterie, gémissements), et l''état général de votre chien. Soyez attentif à son environnement pour éviter les dangers.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/endurance-patrouille.png'),
('endurance-recherche', 'Cet exercice vise à développer l''endurance et la persévérance de votre chien dans des recherches prolongées. Il est idéal pour les chiens avec un fort instinct de prédation ou de poursuite, et peut être adapté à différentes disciplines comme le pistage ou la recherche utilitaire. L''objectif est de maintenir la concentration et la motivation du chien sur une longue durée, en simulant des scénarios réalistes et stimulants.', 'Faites de votre chien un champion de la recherche longue durée !', 'Apprenez à votre chien à chercher patiemment et longtemps des objets cachés.', 'Endurance de recherche (2h+)', 'Que votre chien maintienne un effort de recherche concentré et motivé pendant une très longue période, sans se lasser.', 'La constance est la clé du succès', '120 min', '5 fois', '1x/jour', 'tous', 'Le chien recherche activement, utilise ses sens de manière efficace, ignore les distractions non pertinentes, signale les découvertes et maintient une attitude positive pendant toute la durée de la recherche prolongée.', 'Le chien montre des signes évidents de stress, de blessure, de détresse physique ou mentale, ou d''une perte totale de motivation et d''intérêts. Il est impératif d''arrêter immédiatement l''exercice dans ces cas.', 'L''exercice est validé si le chien maintient un engagement et une concentration constants sur la durée cible, démontrant résilience et motivation malgré les difficultés.', 'Surveillez l''environnement pour les dangers potentiels (autres animaux, personnes), l''état physique de votre chien (déshydratation, surchauffe) et son niveau d''engagement dans l''exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/endurance-recherche.png'),
('engage-disengage', 'L''exercice ''Engage/Disengage'' vise à aider votre chien à gérer son excitation et à rester calme en présence de déclencheurs. Il apprend à détourner son attention de la source de stress ou d''excitation pour se concentrer sur vous. Cet exercice est crucial pour les chiens ayant des réactions anxieuses ou agressives envers certains stimuli extérieurs.', 'Apprenez à votre chien à ignorer les distractions en toute sérénité !', 'Apprenez à votre chien à regarder une distraction, puis à reporter son attention sur vous.', 'Engage/Disengage', 'Apprendre à votre chien à observer une distraction et à s''en détourner pour se concentrer sur vous. Il développe sa capacité à gérer les stimuli environnants.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien regarde le déclencheur sans tension physique apparente, puis, sur un signal verbal ou visuel, détourne son regard vers le maître, faisant preuve de concentration sur ce dernier. La réaction de stress ou d''excitation est significativement réduite ou absente.', 'Le chien montre des signes clairs de stress, d''anxiété ou d''agressivité (haleine rapide, queue basse, oreilles en arrière, grognements, tentative de fuite, fixation intense, vocalisations excessives). Si le chien devient physiquement ingérable ou insécure, l''exercice doit être immédiatement interrompu et la distance par rapport au déclencheur augmentée ou le déclencheur retiré.', 'Observer si le chien peut tolérer la présence du déclencheur à une distance rapprochée sans réagir, puis détourner volontairement son attention vers le maître pour obtenir une récompense. L''objectif est qu''il recherche activement le maître et la récompense au lieu de fixer ou d''interagir avec le déclencheur.', 'Durant l''exercice, soyez attentif aux signaux d''apaisement de votre chien pour valider quand il se détourne de la source de distraction et pouvoir le récompenser au bon moment. Soyez également vigilant sur son niveau de stress, en particulier si le chien est réactif. Votre intonation doit rester positive. Il ne doit pas y avoir d''énervement.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/engage-disengage.png'),
('entrer-eau', 'Cet exercice apprend à votre chien à aimer l''eau et à y entrer calmement. En suivant des étapes simples et amusantes, vous construirez sa confiance et transformerez l''appréhension en plaisir. Idéal pour les futures baignades en toute sécurité.', 'Apprenez à votre chien à aimer l''eau en douceur et en toute confiance !', 'Guidez votre chien vers l''eau avec des encouragements et des friandises, en respectant toujours son rythme.', 'Entrer dans l''eau', 'Apprendre à votre chien à entrer dans l''eau de manière positive et sereine, en renforçant votre lien et sa confiance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien entre calmement dans l''eau jusqu''à avoir les pattes et une partie du corps immergées, sans montrer de signes de peur ou de stress, et en restant attentif à son maître. Il accepte la présence de l''eau positivement.', 'Arrêtez l''exercice si votre chien montre des signes de stress importants (tremblements, queue entre les jambes, tentatives de fuite), s''il halète excessivement, ou s''il semble très fatigué. Une session réussie doit toujours se terminer sur une note positive, avant l''épuisement.', 'L''exercice est validé quand le chien entre dans l''eau jusqu''au niveau de son ventre, de manière volontaire et calme, trois fois sur cinq tentatives consécutives, en affichant une communication corporelle détendue (queue non rentrée, oreilles détendues).', 'Soyez constamment attentif aux réactions de votre chien. Surveillez les signes de stress ou de fatigue. Gardez le contrôle de la laisse près du corps lorsque vous êtes au bord de l''eau pour éviter qu''il ne parte courir sans prévenir. Si votre chien a tendance à boire beaucoup d''eau, proposez-lui des pauses régulières pour éviter la surhydratation. Observez aussi l''environnement: y a-t-il des dangers cachés au fond de l''eau? Des objets flottants dangereux?', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/entrer-eau.png'),
('envoi-en-avant', 'L''exercice "Envoi en avant" apprend à votre chien à se diriger vers un endroit précis que vous lui indiquez. C''est utile pour lui demander d''aller à son panier ou de se rendre à un endroit précis dans le jardin, même s''il y a une distraction.', 'Apprenez à votre chien à se diriger précisément où vous le souhaitez !', 'D’un geste et d’une voix, indiquez à votre chien où aller !', 'Envoi en avant', 'Votre chien apprend à se déplacer vers une cible désignée par votre geste et votre voix, renforçant ainsi votre communication et son obéissance à distance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien se dirige vers l''objet désigné par votre geste et votre voix, même à distance et avec de légères distractions.', 'Si votre chien montre des signes de fatigue (halètement excessif, traîne la patte) ou de stress (léchage de babines, bâillements répétés, évitement du regard), arrêtez immédiatement la séance. Revenez-y plus tard quand il sera disposé.', 'L''exercice est validé quand le chien se dirige vers la cible désignée par le geste et la commande vocale, atteint la cible et y reste au moins 3 secondes, 8 fois sur 10 tentatives consécutives, à une distance de 5 mètres, sans aide physique.', 'Soyez attentif aux signes de frustration ou de confusion chez votre chien. Si tel est le cas, simplifiez l''exercice en réduisant la distance ou en rendant la cible plus visible.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/envoi-en-avant.png'),
('envoi-en-avant-ring', 'Le but de cet exercice est que votre chien coure en ligne droite sur une longue distance, sur votre ordre, et s''arrête à un endroit précis. C''est un exercice avancé qui demande de la précision et une bonne connexion avec votre chien. Il est souvent utilisé dans les sports canins comme le ring pour développer la vitesse et l''obéissance à distance.', 'Apprenez à votre chien à courir loin et droit devant pour un rappel parfait !', 'Demandez à votre chien de "Suivre" ou "Va" et de courir droit devant vous.', 'Envoi en avant (ring)', 'Apprendre à votre chien à courir droit devant lui sur une longue distance (plus de 30 mètres) et à s''arrêter précisément à la fin du parcours sur votre instruction. Cet exercice renforce l''obéissance à distance.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Votre chien exécute l''ordre "Suivre" ou "Va" et court droit devant vous sur 30 mètres ou plus, puis s''arrête sur "Stop" ou un signal de la main.', 'Arrêtez l''exercice si votre chien ne veut plus courir, s''il est essoufflé, s''il se lèche les babines de manière répétée (signe de stress), ou s''il part dans des directions différentes sans revenir à l''objectif initial. Cela signifie qu''il est fatigué ou qu''il ne comprend plus.', 'L''exercice est validé quand le chien s''élance en ligne droite sur 30 mètres, s''arrête dans un rayon de 1 mètre autour du point désigné au signal ''STOP!'', et maintient la position au moins 3 secondes en regardant le maître, sur 4 tentatives consécutives.', 'Surveillez attentivement l''environnement pour éviter tout danger (autres chiens, cyclistes, enfants). Assurez-vous que votre chien ne montre pas de signes de stress ou de fatigue. Si c''est le cas, arrêtez immédiatement l''exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/6b61b2dd-7423-40cc-8994-8753c53f8718.png'),
('equilibre-senior', 'Cet exercice aide votre chien âgé à garder un bon équilibre et à renforcer ses muscles en douceur. C''est comme une petite gymnastique pour le maintenir en forme et prévenir les chutes, avec un coussin mou pour plus de confort.', 'Aidez votre chien senior à retrouver un équilibre de champion en douceur !', 'Guidez votre chien à monter et se tenir en équilibre sur un coussin mou pendant quelques secondes.', 'Équilibre senior', 'Améliorer l''équilibre et renforcer les muscles profonds de votre chien senior pour une meilleure mobilité au quotidien.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Votre chien monte sur le coussin et y reste en équilibre pendant 3 à 5 secondes sans aide.', 'Si votre chien halète beaucoup, refuse de monter sur le coussin, tremble, ou semble chercher à s''échapper, arrêtez la séance. C''est peut-être qu''il est fatigué ou qu''il n''apprécie pas l''exercice ce jour-là.', 'L''exercice est validé quand le chien monte seul sur le coussin, maintient une position debout stable pendant 10 secondes, 5 fois sur 7 tentatives consécutives, sans aide physique du maître.', 'Faites attention aux signes de fatigue ou de douleur, surtout chez les chiens âgés : boiterie, difficulté à se lever, agitation, ou manque d''intérêt soudain. Adaptez la durée et l''intensité de l''exercice.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/equilibre-senior.png'),
('balance-coussin', 'Cet exercice apprend à votre chien à se tenir en équilibre sur un coussin instable. Cela renforce ses muscles profonds et améliore sa conscience corporelle. C''est un excellent moyen de dépenser votre chien mentalement et physiquement, tout en s''amusant ensemble.', 'Améliorez la stabilité et la proprioception de votre chien de manière ludique !', 'Demandez à votre chien de monter et de tenir sur le coussin d’équilibre.', 'Équilibre sur coussin', 'Le chien apprend à se stabiliser sur une surface qui bouge. Cela renforce ses muscles et l’aide à mieux contrôler son corps.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte sur le coussin et y maintient les quatre pattes pendant au moins 5 secondes sans aide.', 'Le chien montre des signes d''épuisement, halète beaucoup, refuse de monter, ou semble stressé (bâillements répétés, léchage de truffe, regard détourné).', 'L''exercice est validé quand le chien maintient ses quatre pattes sur le coussin pendant au moins 5 secondes, sans aide manuelle ni guidage constant (laisse lâche), sur 3 tentatives consécutives.', 'Faites attention à ce que le chien ne glisse pas du coussin, surtout au début. Gardez l''exercice amusant et positif pour éviter toute anxiété.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/balance-coussin.png'),
('escaliers-mecaniques', 'L''exercice des escaliers mécaniques permet à votre chien de s''habituer à différents types de surfaces mobiles et de bruits, tout en renforçant sa confiance. Il est important de commencer lentement et de manière positive pour que l''expérience soit agréable pour le chien. Cet exercice est idéal pour les chiens urbains ou ceux qui doivent s''adapter à des environnements nouveaux et potentiellement stressants.', 'Apprenez à votre chien à prendre les escaliers mécaniques sans stress !', 'Guidez calmement votre chien sur et hors des escaliers mécaniques, en le rassurant.', 'Escaliers mécaniques', 'Votre chien apprend à utiliser les escaliers mécaniques en toute sécurité et avec sérénité.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien monte et descend les escaliers mécaniques avec confiance et calme, sans tremblements ni signes de peur excessifs, et recherche activement les friandises et les félicitations de son handler.', 'Le chien montre des signes de peur, d''anxiété ou de panique (queue entre les pattes, oreilles aplaties, refus catégorique de bouger, tentative de fuite). Si le chien est trop fatigué ou si le handler ne parvient pas à maintenir une attitude positive et rassurante.', 'Observer attentivement le langage corporel du chien (queue basse, oreilles en arrière, bâillements, halètement excessif, tremblements). S''il montre des signes de stress ou de peur, l''exercice doit être ralenti ou arrêté. Récompenser la confiance et le calme est essentiel.', 'Surveillez constamment les pattes de votre chien pour éviter qu''il ne se coince entre les marches ou sur les côtés de l''escalator. Gardez un œil sur les autres usagers et votre environnement pour éviter les bousculades.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/escaliers-mecaniques.png'),
('escorte-personne', 'L''exercice ''Escorte de personne'' enseigne à votre chien à marcher calmement à vos côtés, en ignorant les distractions, lorsqu''une autre personne passe près de vous. Cet exercice renforce le lien et la confiance entre vous et votre chien, tout en améliorant son auto-contrôle. Il est essentiel pour les promenades en milieu urbain ou fréquenté.', 'Apprenez à votre chien à devenir le garde du corps parfait !', 'Faites suivre une personne à votre chien, en restant toujours à ses côtés.', 'Escorte de personne', 'Votre chien apprend à suivre une personne de très près, à garder une bonne distance et à ne pas la dépasser. Il reste aussi attentif à ce que vous lui demandez.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien marche à vos côtés calmement, sans tirer sur la laisse, ni aboyer ou grogner, lorsqu''une personne passe à proximité. Il maintient son attention sur vous la majorité du temps, ou répond rapidement aux commandes lorsqu''il est distrait. La distance à laquelle la personne peut passer sans que le chien ne réagisse sera progressivement augmentée.', 'Le chien montre des signes de stress excessif, de peur, d''agressivité (grognements, morsures), ou de réactivité incontrôlable (hurlements, tentatives d''attaque). Si ces comportements surviennent, arrêtez immédiatement la séance, éloignez-vous de la source de stress et réévaluez la situation, peut-être avec l''aide d''un professionnel.', 'Commencez dans un environnement familier et peu fréquenté. Augmentez progressivement la difficulté en introduisant des distractions plus importantes (plus de personnes, bruit, nourriture au sol) et des environnements plus dynamiques (rue commerçante, parc). Le chien doit systématiquement rester calme et attentif à vous lors du passage d''une personne.', 'Faites attention à l''environnement. Évitez les lieux trop bruyants ou avec beaucoup de stimulations au début. Surveillez toujours la posture et le comportement de votre chien pour détecter tout signe de malaise ou de stress. Soyez aussi vigilant à ne pas laisser le VIP se mettre en danger à cause d''un mouvement inattendu du chien.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/escorte-personne.png'),
('eteindre-lumiere', 'Cette séance d''entraînement enseigne à votre chien à éteindre une lumière en appuyant sur un interrupteur. C''est un excellent exercice de résolution de problèmes et de manipulation d''objets qui renforce votre lien. Il nécessite de la patience et une approche étape par étape.', 'Apprenez à votre chien à éteindre la lumière, un tour amusant et utile !', 'Apprenez à votre chien à éteindre la lumière sur commande.', 'Éteindre la lumière', 'Le chien apprend à toucher l''interrupteur de la lumière sur commande pour l''éteindre, avec son museau ou sa patte.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien éteint la lumière de manière fiable à au moins 4 reprises sur 5 tentatives, sans hésitation ni besoin d''indices multiples.', 'Le chien montre des signes de stress, de frustration, de fatigue ou de démotivation (bâillements excessifs, léchage des lèvres, évitement, grognements). L''exercice devient répétitif.', 'Observer si le chien peut volontairement appuyer sur l''interrupteur pour éteindre la lumière sur commande vocale ou par simple exposition à la lumière allumée, sans aide extérieure.', 'Soyez attentif à tout signe de stress ou d''inconfort chez votre chien. Si l''interrupteur est haut, assurez-vous qu''il n''y ait pas de risque de déséquilibre.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/eteindre-lumiere.png'),
('eternuer', 'Apprenez à votre chien à éternuer sur commande, un tour amusant et fascinant qui montre un bon contrôle et une bonne compréhension de la part de votre chien. Cet exercice utilise des leurres et des renforcements positifs pour encourager le comportement souhaité. Une fois maîtrisé, il peut être un excellent moyen d''impressionner vos amis ou simplement de renforcer votre lien avec votre compagnon canin.', 'Un tour amusant pour renforcer votre complicité !', 'Apprenez à votre chien à éternuer sur commande avec un déclencheur doux.', 'Éternuer sur commande', 'Apprendre à votre chien à réaliser un faux éternuement sur commande, améliorant ainsi votre complicité et l''enrichissement mutuel par le jeu.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien éternue de manière fiable dans les 3 secondes suivant la commande vocale, dans des environnements variés et avec un minimum de distractions, sans besoin de leurre physique.', 'Le chien montre des signes de stress, de frustration ou d''inconfort. L''exercice n''est pas amusant pour le chien. Le chien ne progresse pas malgré des efforts constants et adaptés.', 'Observer si le chien éternue de manière intentionnelle suite à la commande vocale, sans aide physique ou leurre actif. Le comportement doit être reproductible sur demande.', 'Évitez à tout prix de rendre l''expérience désagréable pour le chien. Ne le touchez jamais brusquement, ne le réprimandez pas s''il ne réussit pas et assurez-vous qu''il ne se blesse pas avec le coton-tige. La gentillesse et la patience sont essentielles.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/eternuer.png'),
('etirements-guides', 'Les étirements guidés aident à améliorer la flexibilité de votre chien, à prévenir les blessures et à favoriser la relaxation musculaire. Cet exercice est excellent pour les chiens plus âgés, les athlètes canins ou tout chien ayant des raideurs. Il est important de pratiquer ces étirements en douceur et de toujours respecter les limites de votre animal.', 'Détendez les muscles de votre chien pour améliorer sa souplesse !', 'Guidez délicatement votre chien avec une friandise pour l''inciter à s''étirer en douceur.', 'Étirements guidés', 'L''objectif est d''étirer en douceur les muscles de votre chien pour améliorer sa souplesse et sa récupération après l''effort.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien reste calme et coopératif pendant la majorité des étirements, sans montrer de signes de stress ou de douleur. Une légère mobilité et une relaxation visible après la séance.', 'Tout signe de douleur ou d''inconfort chez le chien (gémissements, tentative de morsure, tension musculaire évidente), refus catégorique de coopérer, ou si l''exercice est devenu une source de stress pour le chien.', 'Observer attentivement les réactions du chien (langage corporel, vocalisation). Valider la pression et l''amplitude de chaque mouvement en fonction de la réaction du chien.', 'Soyez attentif aux signaux de votre chien : bâillements, léchage de babines, détournement du regard, ou tentatives de se lever sont des signes qu''il n''est pas à l''aise ou que l''étirement est trop intense. Arrêtez ou réduisez l''intensité.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/etirements-guides.png'),
('etirements-senior', 'Cet exercice de stretching doux est conçu pour les chiens seniors afin d''améliorer leur souplesse, de réduire les raideurs articulaires et de maintenir une bonne mobilité. Il se concentre sur des mouvements lents et contrôlés pour ne pas fatiguer le chien, tout en favorisant son bien-être physique et mental. Une routine régulière aide à prévenir les blessures et à améliorer la qualité de vie de votre compagnon âgé.', 'Assouplissez votre chien senior en douceur pour plus de confort au quotidien !', 'Réalisez des étirements lents et progessifs sur le corps de votre chien pendant qu''il est détendu.', 'Étirements seniors', 'Améliorer la souplesse des articulations de votre chien senior et favoriser sa relaxation grâce à des étirements doux et contrôlés.', 'La constance est la clé du succès', '5 min', '5 fois', '1x/jour', 'tous', 'Le chien est capable d''effectuer tous les étirements demandés sans résistance, en maintenant une posture détendue et en montrant des signes de bien-être post-exercice (par exemple, un léger bâillement, un soupir de contentement).', 'Le chien montre des signes clairs de douleur, de peur, d''épuisement ou de refus prononcé d''obéir. Tout mouvement qui semble causer une gêne articulaire ou musculaire.', 'Observer la réaction du chien à chaque mouvement. Le chien doit rester calme et coopératif. Aucun signe de douleur ou de gêne ne doit être visible. La respiration doit rester régulière.', 'Soyez attentif aux moindres signes de douleur ou d''inconfort. Si votre chien réagit mal, arrêtez l''étirement ou l''exercice COMPLETEMENT et consultez votre vétérinaire. Un étirement n''est pas un combat.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/etirements-senior.png'),
('excitation-controlée', 'Cet exercice vise à apprendre au chien à gérer son excitation lors de situations potentiellement stimulantes. L''objectif est de lui permettre de rester calme et attentif malgré la présence de distractions. Cela renforce le lien de confiance et la capacité de concentration du chien.', 'Apprenez à votre chien à gérer son excitation pour qu''il reste serein en toutes circonstances !', 'Provoquez une courte période d''excitation intense, puis demandez immédiatement le calme à votre chien.', 'Excitation contrôlée', 'Apprendre à votre chien à passer d''un état d''excitation intense à un état de calme, et vice-versa, pour qu''il puisse mieux gérer ses émotions.', 'La constance est la clé du succès', '10 min', '5 fois', '1x/jour', 'tous', 'Le chien peut rester assis calmement pendant plus d''une minute face à des distractions modérées (personnes qui passent, autres chiens à distance raisonnable) sans tenter de poursuivre ou d''aboyer.', 'Le chien montre des signes de stress excessif (halètement important, bâillements répétés, queue basse, évitement du regard) ou devient incontrôlable malgré les corrections.', 'Observer la capacité du chien à répondre au ''assis'' et à maintenir la position pendant au moins 30 secondes en présence de distractions graduelles et d''une personne ou d''un objet en mouvement.', 'Soyez attentif à l''énergie de votre chien. S''il est très excité, attendez quelques secondes qu''il se pose un peu avant de lui demander le calme. Ne le sur-stimulez pas au point qu''il perde totalement le contrôle.', NULL, NULL, 'tous', NULL),
('certification-detection', 'L''exercice de certification est une évaluation complète des compétences d''obéissance et de contrôle du chien dans diverses situations. Il vise à confirmer que le chien répond de manière fiable aux commandes dans des environnements distrayants pour assurer sa sécurité et celle des autres. Cet exercice est souvent requis pour les chiens de thérapie, d''assistance ou pour des programmes de reconnaissance avancés.', 'Préparez-vous et votre chien à réussir n''importe quel examen !', 'Réalisez une série d''exercices de base comme si vous passiez une certification.', 'Exercice de certification', 'L''objectif est de vous entraîner et de montrer que votre chien peut rester calme et obéissant dans différentes situations, comme le ferait un chien certifié.', 'La constance est la clé du succès', '30 min', '5 fois', '1x/jour', 'tous', 'Le chien démontre une obéissance fiable, un bon contrôle de soi et une complicité avec son propriétaire dans toutes les épreuves de l''exercice, prouvant sa capacité à réagir correctement aux commandes dans des situations variées.', 'Le chien manifeste de l''agressivité envers le juge, le propriétaire ou un autre chien, ou s''il refuse catégoriquement d''exécuter une commande essentielle après plusieurs tentatives assistées, le test est considéré comme échoué.', 'Le chien doit exécuter chaque commande demandée par le juge avec précision et dans le temps imparti, sans démonstration de stress ou d''agressivité. Les aides (friandises, jouets, encouragements verbaux excessifs) sont interdites dans la plupart des cas sauf indication contraire spécifique.', 'Surveillez toujours l''environnement pour assurer la sécurité de votre chien (pas de dangers, pas d''objets qu''il pourrait manger). Observez aussi les réactions de votre chien : est-il content ? A-t-il peur ? Est-il fatigué ? Adaptez l''exercice à son état du moment.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/certification-detection.png'),
('exploration-securisee', 'L''exploration sécurisée est un exercice essentiel pour développer l''indépendance et la confiance de votre chien tout en explorant de nouveaux environnements. Cet exercice permet à votre chien de découvrir son environnement à son rythme, renforçant ainsi son bien-être mental et réduisant les comportements d''anxiété. Il est crucial de guider subtilement votre chien, en lui laissant l''initiative tout en assurant sa sécurité.', 'Découvrez le monde avec votre chien en toute confiance et renforcez votre lien !', 'Explorez de nouveaux lieux ensemble, en toute sécurité, en laissant votre chien prendre l''initiative.', 'Exploration sécurisée', 'Votre chien apprend à explorer sereinement de nouveaux environnements, ce qui renforce sa confiance et votre lien.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien explore activement et sereinement l''environnement, se tourne volontairement vers le propriétaire pour obtenir des informations ou des récompenses, et répond positivement aux encouragements verbaux.', 'Le chien montre des signes de peur extrême (tremblements, tentatives de fuite désespérées), d''agression, ou un inconfort prolongé malgré les tentatives de réconfort et de sécurisation de la part du propriétaire.', 'Observer la capacité du chien à rester calme et attentif à son environnement tout en maintenant un lien de confiance avec le propriétaire. Vérifier l''absence de signes de stress excessif ou d''excitation incontrôlée.', 'Soyez attentif à votre chien : son langage corporel (oreilles, queue, posture), ses réactions face à de nouvelles choses, et son intérêt pour l''exploration. Soyez aussi vigilant à l''environnement : dangers potentiels, autres animaux ou personnes.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/exploration-securisee.png'),
('foule', 'Cet exercice vise à exposer progressivement votre chien aux environnements animés et aux foules de manière contrôlée et positive. L''objectif est de renforcer sa confiance et de lui apprendre à rester calme malgré la présence de nombreuses personnes. Commencez dans des zones peu fréquentées et progressez vers des environnements plus stimulants.', 'Apprenez à votre chien à être zen en foule !', 'Promenez-vous calmement avec votre chien dans des lieux animés, en le récompensant pour son calme.', 'Exposition à la foule', 'Apprendre à votre chien à rester serein et attentif en votre présence, même dans des lieux très fréquentés.', 'La constance est la clé du succès', '15 min', '5 fois', '1x/jour', 'tous', 'Le chien est à l''aise dans un environnement modérément fréquenté pendant au moins 15-20 minutes, en restant calme et réactif aux ordres du maître, avec peu ou pas de signes de stress.', 'Le chien montre des signes persistants de peur extrême, d''anxiété ou d''agressivité. Si le maître se sent dépassé ou incapable de gérer le comportement du chien en sécurité.', 'Observe the dog''s body language throughout the exercise. The dog should exhibit relaxed body posture, be responsive to handler cues, and show a decrease in stress-related behaviors as exposure increases.', 'Soyez très attentif au langage corporel de votre chien. Soyez vigilant aux interactions avec les autres personnes (enfants qui courent, personnes qui veulent le toucher) et les autres chiens. Anticipez et protégez votre chien d''éventuels désagréments. Gardez toujours votre chien en laisse et tenez-la fermement mais sans tension. Gardez un plan de sortie facile de la foule.', NULL, NULL, 'tous', 'https://dcwbqsfeouvghcnvhrpj.supabase.co/storage/v1/object/public/exercise-images/covers/foule.png')
) AS v(v_slug, v_description, v_summary, v_short_instruction, v_short_title, v_objective, v_dedication, v_duration, v_repetitions, v_frequency, v_environment, v_success_criteria, v_stop_criteria, v_validation_protocol, v_vigilance, v_progression_next, v_regression_simplified, v_age_recommendation, v_cover_image)
WHERE e.slug = v.v_slug;